-- [OK] [AUTO] aion_GetUserInstance

CREATE OR REPLACE FUNCTION aion_getuserinstance(
    p_char_id integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT ui.server_id, ui.world_id, ui.instance_id, ui.reentrance_time, ui.count_variate, i.validity_time FROM user_instance as ui LEFT OUTER JOIN instance as i ON ui.instance_id = i.instance_id WHERE ui.char_id = p_char_id::integer;
END;
$$;

