-- [OK] [AUTO] aion_GetEquipmentItemList_20111227

CREATE OR REPLACE FUNCTION aion_getequipmentitemlist_20111227(
    p_char_id integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT a.slot, a.name_id, COALESCE(b.skin_name_id,0),COALESCE(b.proc_tool_nameid, 0),COALESCE(b.dye_info,0) FROM user_item a  left join user_item_option b  on a.id = b.id WHERE a.char_id = p_char_id::integer AND a.warehouse = 0 AND slot between 1 and 2;
END;
$$;

