-- [OK] [AUTO] aion_SetGloryPointInfo

CREATE OR REPLACE FUNCTION aion_setglorypointinfo(
    p_nCharId integer,
    p_nGloryPoint integer,
    p_nTodayGloryPoint integer,
    p_nThisWeekGloryPoint integer,
    p_nLastWeekGloryPoint integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT glory_point FROM user_gp_data WHERE char_id = p_nCharId::integer) THEN
    UPDATE user_gp_data SET glory_point = p_nGloryPoint WHERE char_id = p_nCharId::integer;
    ELSE
    IF (p_nGloryPoint > 0) THEN
    INSERT INTO user_gp_data (char_id, glory_point, ownership_bonus_gp) VALUES (p_nCharId, p_nGloryPoint, 0);
    END IF;
    END IF;
    UPDATE user_data SET today_glory_point=p_nTodayGloryPoint, this_week_glory_point=p_nThisWeekGloryPoint, last_week_glory_point=p_nLastWeekGloryPoint WHERE char_id = p_nCharId::integer;
END;
$$;

