-- [OK] [AUTO] aion_PutItem

CREATE OR REPLACE FUNCTION aion_putitem(
    p_nCharId integer,
    p_nNameId integer,
    p_nSlotId smallint,
    p_nAmount bigint,
    p_nTid bigint,
    p_nSlotNum smallint,
    p_nWarehouse integer,
    p_soulBound smallint,
    p_enchantCount smallint,
    p_skinNameId integer,
    p_statEnchantName0 integer,
    p_statEnchantName1 integer,
    p_statEnchantName2 integer,
    p_statEnchantName3 integer,
    p_statEnchantName4 integer,
    p_statEnchantName5 integer,
    p_optionCount smallint,
    p_dye_info integer,
    p_nProcToolNameId integer,
    p_nExpiredTime integer,
    p_producer varchar(20),
    p_buyamount smallint,
    p_buyduration smallint,
    p_obtainSkinType smallint,
    p_expireSkinTime integer,
    p_dynamicProperty integer,
    p_serverOfOrigin smallint,
    p_expireDyeTime integer,
    p_random_option smallint,
    p_limit_enchant_count smallint,
    p_reidentify_count smallint,
    p_authorizeCount smallint,
    p_vanishPoint integer,
    p_enchantProbAddition integer,
    p_optionProbAddition integer,
    p_keyNameId integer,
    p_exceedState smallint,
    p_exceedSkillId1 integer,
    p_exceedSkillId2 integer,
    p_exceedSkillId3 integer,
    p_baseSkillId integer,
    OUT p_dbId bigint
) RETURNS bigint
LANGUAGE plpgsql
AS $$
BEGIN
    INSERT INTO user_item (char_id, name_id, slot_id, amount,tid,slot,warehouse, producer, expired_time,buy_amount, buy_duration, dynamic_property, server_of_origin) VALUES (p_nCharId, p_nNameId, p_nSlotId, p_nAmount, p_nTid, p_nSlotNum, p_nWarehouse, p_producer, p_nExpiredTime, p_buyamount, p_buyduration, p_dynamicProperty, p_serverOfOrigin);
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN;
    END IF;
    p_dbId := LASTVAL();
    IF ( (p_random_option > 0) or (p_skinNameId > 0) or (p_statEnchantName0 > 0) or (p_statEnchantName1 > 0) or (p_statEnchantName2 > 0) or (p_statEnchantName3 > 0) or (p_statEnchantName4 > 0) or (p_statEnchantName5 > 0) or (p_nProcToolNameId > 0) or (p_enchantCount > 0) or (p_soulBound > 0) or (p_optionCount > 0) or (p_dye_info != 0) or (p_limit_enchant_count > 0) or (p_authorizeCount > 0) or (p_vanishPoint > 0) or (p_enchantProbAddition > 0) or (p_optionProbAddition > 0) or (p_keyNameId > 0) ) THEN
    INSERT INTO user_item_option (id, char_id, soul_bound, enchant_count, skin_name_id, stat_enchant_name0, stat_enchant_name1, stat_enchant_name2, stat_enchant_name3, stat_enchant_name4, stat_enchant_name5, option_count, dye_info, proc_tool_nameid, obtain_skin_type, expire_skin_time, expire_dye_time, random_option, limit_enchant_count, reidentify_count, authorize_count, vanish_point, enchant_prob_addition, option_prob_addition, KeyNameId, exceedState, ExceedSkillId1, ExceedSkillId2, ExceedSkillId3, BaseSkillId ) values (p_dbId, p_nCharId,p_soulBound,p_enchantCount,p_skinNameId, p_statEnchantName0, p_statEnchantName1, p_statEnchantName2, p_statEnchantName3, p_statEnchantName4, p_statEnchantName5, p_optionCount, p_dye_info, p_nProcToolNameId,p_obtainSkinType, p_expireSkinTime, p_expireDyeTime, p_random_option,p_limit_enchant_count, p_reidentify_count, p_authorizeCount, p_vanishPoint, p_enchantProbAddition, p_optionProbAddition, p_keyNameId, p_exceedState, p_exceedSkillId1, p_exceedSkillId2, p_exceedSkillId3, p_baseSkillId );
    END IF;
    RETURN;
END;
$$;

