-- [OK] [AUTO] aion_UpdateBuilderCommandLog

CREATE OR REPLACE FUNCTION aion_updatebuildercommandlog(
    p_strUserId varchar(20),
    p_resultMessage varchar(1024) DEFAULT ''
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT BUILDER_LOG_ID FROM builder_log WHERE CHAR_NM = p_strUserId) THEN
    UPDATE builder_log SET result_message = result_message + p_resultMessage where CHAR_NM = p_strUserId;
    ELSE
    INSERT INTO builder_log ( world_id, char_nm, build_nm, build_parameter, builder_type, builder_lv, regdate) VALUES ( 0, p_strUserId, '', '', 0, 0, CURRENT_TIMESTAMP);
    END IF;
END;
$$;

