    p_char_id integer,
    p_emotion_type smallint,
    p_expire_date integer
) RETURNS bigint
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    IF NOT EXISTS (SELECT  char_id FROM user_emotion  WHERE char_id = p_char_id::integer AND emotion_type = p_emotion_type LIMIT 1) THEN
    INSERT INTO user_emotion ( char_id, emotion_type, expire_date ) VALUES ( p_char_id, p_emotion_type, p_expire_date );
    ELSE
    UPDATE	user_emotion SET		expire_date = p_expire_date WHERE	char_id = p_char_id::integer AND		emotion_type = p_emotion_type;
    END IF;
    RETURN v_rowcount;
END;
$$;

