-- [OK] [AUTO] GM_UserRateDA_SrchUserList_del

CREATE OR REPLACE FUNCTION gm_userrateda_srchuserlist_del(
    p_rate_id integer,
    p_cvs_class varchar(100),
    p_rank_from integer,
    p_rank_to integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_xml xml;
BEGIN
    v_xml := CAST('<c>' || REPLACE(p_cvs_class, ',', '</c><c>') || '</c>' AS xml);
    PERFORM  r.id, r.mu, r.sigma, u.char_id, u.user_id, u.account_id, u.account_name, u.race, u.class, u.guild_id, g.id AS guild_id, g.name AS guild_name FROM	user_rate r JOIN	user_data u	ON u.char_id = r.char_id LEFT JOIN	guild g	ON g.id = u.guild_id WHERE	r.rate_id = p_rate_id::integer AND		u.class IN (SELECT n.value('.', 'tinyint') as class from v_xml.nodes('c') as c(n)) AND		r.id NOT IN (SELECT  r2.id FROM	user_rate r2 JOIN	user_data u2 ON u2.char_id = r2.char_id WHERE	r2.rate_id = p_rate_id::integer AND		u2.class IN (SELECT n.value('.', 'tinyint') as class from v_xml.nodes('c') as c(n)) ORDER BY mu DESC, sigma  LIMIT p_rank_from - 1) ORDER BY mu DESC, sigma DESC LIMIT p_rank_to - p_rank_from + 1;
END;
$$;

