-- [OK] [AUTO] aion_GetUserIsBlock

CREATE OR REPLACE FUNCTION aion_getuserisblock(
    p_charId integer,
    p_targetname varchar(50),
    OUT p_targetId integer,
    OUT p_isblock integer,
    OUT p_optionflag integer
) RETURNS record
LANGUAGE plpgsql
AS $$
BEGIN
    p_targetId := 0;
    SELECT COALESCE(char_id,0) INTO p_targetId FROM user_data where user_id = p_targetname::integer and delete_complete_date=0 and race = (select race from user_data where char_id = p_charId::integer);
    p_isblock := 0;
    p_optionflag := 0;
    IF p_targetId is not null and p_targetId != 0 THEN
    IF EXISTS (SELECT block_id from user_block where char_id = p_targetId::integer and block_id = p_charId::integer) THEN
    p_isblock := 1;
    ELSE
    p_isblock := 0;
    END IF;
    SELECT COALESCE(optionflags,0) INTO p_optionflag FROM user_data  where char_id = p_targetId::integer;
    END IF;
    RETURN;
END;
$$;

