-- [OK] [AUTO] aion_UpdateDisassemblyRetry

CREATE OR REPLACE FUNCTION aion_updatedisassemblyretry(
    p_charId integer,
    p_itemId bigint,
    p_retryCount integer,
    p_isDelete smallint,
    p_name1 integer,
    p_count1 integer,
    p_name2 integer,
    p_count2 integer,
    p_name3 integer,
    p_count3 integer,
    p_name4 integer,
    p_count4 integer,
    p_name5 integer,
    p_count5 integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    -- Transaction managed by PG function context
    update user_disassembly_retry set retryCount = p_retryCount, isDelete = p_isDelete, nameId1 = p_name1, ItemCount1 = p_count1, nameId2 = p_name2, ItemCount2 = p_count2, nameId3 = p_name3, ItemCount3 = p_count3, nameId4 = p_name4, ItemCount4 = p_count4, nameId5 = p_name5, ItemCount5 = p_count5, UpdateDate = CURRENT_TIMESTAMP where charId = p_charId and ItemId = p_itemId;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    insert into user_disassembly_retry values(p_charId, p_itemId, p_retryCount, p_isDelete, p_name1, p_count1, p_name2, p_count2, p_name3, p_count3, p_name4, p_count4, p_name5, p_count5, CURRENT_TIMESTAMP);
    END IF;
    -- COMMIT (implicit in PG function)
END;
$$;

