-- [OK] [AUTO] aion_DeleteEventItem

CREATE OR REPLACE FUNCTION aion_deleteeventitem(
    p_itemid bigint
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_currTime timestamp;
BEGIN
    IF NOT EXISTS (SELECT object_id FROM information_schema.tables WHERE name = 'aionDeletedEventItemCount') THEN
    CREATE TABLE aionDeletedEventItemCount( delete_id int NOT NULL, char_id int NOT NULL, item_count bigint NOT NULL, apply_date datetime NOT NULL, event_item bigint NOT NULL );
    END IF;
    v_currTime := CURRENT_TIMESTAMP;
    insert into aionDeletedEventItemCount (char_id, item_count, apply_date, event_item) select user_item.char_id, sum(amount) as item_count, v_currTime, p_itemid from user_item where user_item.name_id = p_itemid and (warehouse = 0 or warehouse = 1 OR (warehouse >= 30 AND warehouse < 50)) group by user_item.char_id;
    UPDATE user_item SET warehouse=10, update_date=v_currTime WHERE name_id=p_itemid;
    RETURN QUERY SELECT * from aionDeletedEventItemCount where apply_date = v_currTime;
END;
$$;

