-- [OK] [AUTO] GM_UserRateDA_SrchUserListByRank

CREATE OR REPLACE FUNCTION gm_userrateda_srchuserlistbyrank(
    p_rate_id integer,
    p_cvs_class varchar(100),
    p_rank_from integer,
    p_rank_to integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
BEGIN
    v_sql := ';
    RETURN QUERY SELECT	x.*, g.name as ''guild_nm'' FROM	( SELECT	RANK() OVER (ORDER BY r.mu DESC, r.sigma) AS rate_rank, r.rate_id, r.mu, r.sigma, r.update_cnt, u.char_id, u.user_id, u.account_id, u.account_name, u.race, u.class, u.guild_id, u.gender, u.lev FROM	user_rate r  JOIN	user_data u 	ON u.char_id = r.char_id and u.delete_complete_date = 0 WHERE	r.rate_id = ' || CAST(p_rate_id AS varchar) IF (COALESCE(p_cvs_class, 'null') <> 'null') BEGIN SET	v_sql = v_sql || ' AND		u.class IN (' || p_cvs_class || ') ' END SET		v_sql = v_sql || ' ) x LEFT JOIN	guild g 	ON g.id = x.guild_id WHERE ' || CAST(p_rank_from AS varchar) || '<= rate_rank AND rate_rank <=' || CAST(p_rank_to AS varchar) || ' ORDER BY rate_rank';
    EXECUTE v_sql;
END;
$$;

