-- [OK] [AUTO] aion_UpdateLegionDominionRanking

CREATE OR REPLACE FUNCTION aion_updatelegiondominionranking(
    p_nLegionId integer,
    p_legionName varchar(32),
    p_nDominionId integer,
    p_nScore integer,
    p_nPlayedTime integer,
    p_nGameEndTime bigint,
    p_nServerId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF NOT EXISTS (SELECT p_nDominionId FROM legion_dominion_rankings WHERE legion_id = p_nLegionId::integer and dominion_id=p_nDominionId and take_over_processed_time=0 and server_id = p_nServerId::integer) THEN
    INSERT INTO legion_dominion_rankings (legion_id, dominion_id, score, played_time_in_sec, game_end_time, take_over_processed_time, server_id) VALUES (p_nLegionId, p_nDominionId, p_nScore, p_nPlayedTime, p_nGameEndTime, 0, p_nServerId);
    ELSE
    UPDATE legion_dominion_rankings SET score = p_nScore::integer, played_time_in_sec=p_nPlayedTime, game_end_time=p_nGameEndTime where legion_id = p_nLegionId::integer and dominion_id=p_nDominionId and take_over_processed_time=0 and server_id = p_nServerId::integer;
    END IF;
END;
$$;

