) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    -- Transaction managed by PG function context
    update user_luna_dice_gotcha set open_num = p_open_num, use_special_dice = p_use_special_dice, recv_reward_time = p_recv_reward_time where char_id = p_char_id::integer;
