CREATE OR REPLACE FUNCTION aion_putitembind(
    p_nId bigint,
    p_nActorType integer,
    p_nActorValue integer,
    p_nBindWarehouse integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    -- Transaction managed by PG function context
    UPDATE user_item SET slot_id = -1, warehouse = p_nBindWarehouse::integer, update_date = CURRENT_TIMESTAMP WHERE id = p_nId;
    IF 0 /* @v_ERROR */ = 0 THEN
    INSERT INTO user_item_bind(item_id, actor_type, actor_value) VALUES (p_nId, p_nActorType, p_nActorValue);
    -- COMMIT (implicit in PG function)
    RETURN 0;
    ELSE
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    END IF;
END;
$$;

