-- [OK] [AUTO] GM_UserRecoveryInfoDAO_Insert

CREATE OR REPLACE FUNCTION gm_userrecoveryinfodao_insert(
    p_char_id integer,
    p_recovery_status smallint,
    OUT p_returnValue integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_error integer;
BEGIN
    p_returnValue := 0;
    IF EXISTS (SELECT char_id FROM user_recovery_info  WHERE char_id = p_char_id::integer) THEN
    UPDATE user_recovery_info SET recovery_status = p_recovery_status WHERE char_id = p_char_id::integer;
    ELSE
    INSERT into user_recovery_info(char_id, recovery_status) VALUES (p_char_id, p_recovery_status);
    END IF;
    v_error := 0 /* @v_ERROR */;
    v_rowCount := v_rowcount;
    IF v_error <> 0 OR v_rowCount < 1 THEN
    RETURN;
    END IF;
    p_returnValue := 1;
    RETURN;
END;
$$;

