-- [OK] [AUTO] aion_PutItemCompoundedTwoHand_20121105

CREATE OR REPLACE FUNCTION aion_putitemcompoundedtwohand_20121105(
    p_dbId bigint,
    p_main_item_dbid bigint,
    p_nWarehouse integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_ret integer;
    v_charid integer;
BEGIN
    UPDATE user_item SET warehouse = p_nWarehouse::integer,  main_item_dbid = p_main_item_dbid, update_date=CURRENT_TIMESTAMP where id = p_dbId and warehouse != 17;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    v_ret := v_rowcount;
    IF NOT EXISTS (select id  from user_item_option where id = p_dbId) THEN
    SELECT char_id INTO v_charid WHERE id = p_dbId;
    insert into user_item_option (id, char_id) values (p_dbId, v_charid);
    END IF;
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN v_ret;
    END IF;
    p_dbId := LASTVAL();
    RETURN v_ret;
END;
$$;

