-- [OK] [AUTO] GM_UserResetName_Srch

CREATE OR REPLACE FUNCTION gm_userresetname_srch(
    p_top_count integer,
    p_page_num integer,
    p_user_id varchar(20),
    p_account_id integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    IF (p_account_id != 0) THEN
    RETURN QUERY SELECT  account_id, char_id, char_name_old as user_id from	reset_charname_list  where	account_id = p_account_id::integer order by char_name_old LIMIT p_top_count;
    RETURN QUERY SELECT count(*) as total from reset_charname_list  where	account_id = p_account_id::integer;
    ELSIF (COALESCE(p_user_id, '') <> '') THEN
    RETURN QUERY SELECT  account_id, char_id, char_name_old as user_id from	reset_charname_list  where	char_id not in (SELECT /*INLINE_LIMIT:p_top_count * (p_page_num-1*/) char_id from reset_charname_list  where	char_name_old like p_user_id || '%' order	by char_name_old ) and char_name_old like p_user_id || '%' order by char_name_old LIMIT p_top_count;
    RETURN QUERY SELECT count(*) as total from reset_charname_list  where char_name_old like p_user_id || '%';
    ELSE
    RETURN QUERY SELECT  account_id, char_id, char_name_old as user_id from	reset_charname_list  where	char_id not in (SELECT /*INLINE_LIMIT:p_top_count * (p_page_num-1*/) char_id from	reset_charname_list  order	by char_name_old ) order by char_name_old LIMIT p_top_count;
    RETURN QUERY SELECT count(*) as total from reset_charname_list;
    END IF;
END;
$$;

