-- [WARN] [REVIEW] aion_UpdateOldUserOfLowlevelToDelete
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION aion_updateolduseroflowleveltodelete(
    p_check_days integer,
    p_low_level integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
BEGIN
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name = 'temp_user_id_object_to_del$') THEN
    DROP TABLE temp_user_id_object_to_del$;
    END IF;
    -- Transaction managed by PG function context
    v_sql := 'SELECT char_id INTO temp_user_id_object_to_del$ FROM user_data WHERE delete_date = 0 AND delete_complete_date = 0 AND GetUnixtimeWithUTCAdjust(last_logout_time, 0) || ' || CAST((3600*24*p_check_days) AS varchar(20)) || '< GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) AND lev < ' || CAST(p_low_level AS varchar(20));
    RAISE NOTICE '%', v_sql;
    EXECUTE v_sql;
    UPDATE user_data SET delete_date = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0), delete_complete_date = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) where char_id in (select char_id from temp_user_id_object_to_del$);
    -- COMMIT (implicit in PG function)
END;
$$;

