-- [WARN] [REVIEW] aion_GetVendorAverageDark
--   Warning: CURSOR logic detected - converted to PG cursor syntax

CREATE OR REPLACE FUNCTION aion_getvendoraveragedark(
    p_make_date integer,
    p_get_only_oneweek integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_cursqldate timestamp := CURRENT_TIMESTAMP;
    v_name_id bigint;
    v_avg bigint;
    v_num integer;
    v_last_avg bigint;
    v_last_num integer;
    v_last_date integer;
    cur_log CURSOR FOR (SELECT name_id, AVG(sold_unit_price), COUNT(*) FROM vendor_average_dark WHERE sold_date < p_make_date GROUP BY name_id);
BEGIN
    OPEN cur_log;
    FETCH cur_log INTO v_name_id, v_avg, v_num;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    SELECT average_unit_price, entire_sold_number, create_date INTO v_last_avg, v_last_num, v_last_date FROM vendor_average_dark_last_result WHERE name_id = v_name_id;
    IF v_last_avg IS NULL THEN
    INSERT INTO vendor_average_dark_last_result (name_id, average_unit_price, entire_sold_number, create_date, update_date) VALUES (v_name_id, v_avg, v_num, p_make_date, p_make_date);
    ELSE
    UPDATE vendor_average_dark_last_result SET average_unit_price = v_avg, entire_sold_number = v_num, update_date = p_make_date, update_datetime = v_cursqldate WHERE name_id = v_name_id;
    END IF;
    FETCH cur_log INTO v_name_id, v_avg, v_num;
    v_fetch_found := FOUND;
    END IF;
    CLOSE cur_log;
    DELETE FROM vendor_average_dark WHERE sold_date < p_make_date;
    IF (p_get_only_oneweek > 0) THEN
    RETURN QUERY SELECT name_id, average_unit_price WHERE update_date = p_make_date;
    ELSE
    RETURN QUERY SELECT name_id, average_unit_price FROM vendor_average_dark_last_result;
    END IF;
END;
$$;

