-- [OK] [AUTO] get_constraint_name

CREATE OR REPLACE FUNCTION get_constraint_name(
    p_table varchar(100),
    p_column varchar(100),
    OUT p_oldName varchar(250)
) RETURNS varchar(250)
LANGUAGE plpgsql
AS $$
BEGIN
    SELECT default_constraints.name INTO p_oldName FROM information_schema.columns inner join information_schema.tables on all_columns.object_id = tables.object_id inner join information_schema.schemata on tables.schema_id = schemas.schema_id inner join sys.default_constraints on all_columns.default_object_id = default_constraints.object_id where schemas.name = 'dbo' and tables.name = p_table and all_columns.name = p_column;
END;
$$;

