-- [OK] [AUTO] aion_DeleteItemByDate_20111227

CREATE OR REPLACE FUNCTION aion_deleteitembydate_20111227(
    p_date integer,
    p_warehouse integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_deletedate timestamp;
BEGIN
    v_deletedate := (CURRENT_TIMESTAMP + (-p_date) * INTERVAL '1 day');
    CREATE TEMP TABLE deletedItem ( id int NOT NULL );
    INSERT INTO deletedItem SELECT ID from user_item where warehouse = p_warehouse::integer AND tid = 0 AND update_date < v_deletedate;
    delete from user_item_option where ID in (select * from deletedItem);
    delete from user_item_charge where ID in (select * from deletedItem);
    Delete from user_item_polish where id in (select * from deletedItem);
    delete from user_item_attribute where id in (select * from deleteditem);
    DELETE FROM user_item WHERE ID in (select * from deletedItem);
    DROP TABLE IF EXISTS deletedItem;
END;
$$;

