-- [OK] [AUTO] aion_GetGuildJoinApplicantJoinInfo

CREATE OR REPLACE FUNCTION aion_getguildjoinapplicantjoininfo(
    p_nCharId integer,
    p_nGuildId integer,
    p_type integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_utc_adjust bigint;
BEGIN
    v_utc_adjust := GetUtcAdjustSecWithUTC_Local((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), CURRENT_TIMESTAMP);
    IF EXISTS (SELECT char_id FROM user_guild_join_application WHERE char_id = p_nCharId::integer and guild_id = p_nGuildId::integer) THEN
    IF p_type = 0 THEN
    PERFORM user_id, class, gender, lev, world, GetUnixtimeWithUTCAdjust(last_logout_time, v_utc_adjust) AS last_logout_time, a.race, 0, COALESCE(b.id, -1), COALESCE(permission,0) FROM user_data a left join house_instant b  on a.char_id = b.id and b.state<>6 WHERE a.char_id = p_nCharId::integer and a.guild_id = 0 and a.delete_complete_date = 0;
    ELSIF p_type = 1 THEN
    PERFORM user_id, class, gender, lev, world, GetUnixtimeWithUTCAdjust(last_logout_time, v_utc_adjust) AS last_logout_time, a.race, b.id, b.addr_id, COALESCE(permission, 0) FROM user_data a, house_field b WHERE a.char_id = p_nCharId::integer and a.guild_id = 0 and a.delete_complete_date = 0 and a.char_id = b.owner_id AND b.owner_type = 2;
    END IF;
    END IF;
END;
$$;

