-- [OK] [AUTO] GM_AbyssDA_SrchAbyssDefenderAbnormal

CREATE OR REPLACE FUNCTION gm_abyssda_srchabyssdefenderabnormal(
    p_abyss_id integer,
    p_tick_from integer,
    p_tick_to integer,
    p_valid_siege_point integer,
    p_invalid_char_count integer,
    p_normal_rank_to integer,
    p_normal_count_to integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    PERFORM  r.update_time, r.abyss_id, c.contributer_total, r.defender_share_amount, r.defender_rank, r.defender_siegepoint, r.group_id, u.char_id, u.user_id, u.account_id, u.account_name, u.race, u.class, CAST(u.gender AS char) as gender, COALESCE(u.login_server, u.org_server) login_server, u.org_server, u.cur_server, u.world, u.lev, u.builder, TO_CHAR(u.create_date, 'YYYY-MM-DD HH24:MI:SS') AS create_date, u.delete_type, u.delete_complete_date, u.delete_date, CASE WHEN u.last_login_time = u.last_logout_time THEN 'on' WHEN u.last_login_time != u.last_logout_time THEN 'off' END AS logonoff FROM	abyss_user_defender r JOIN	user_data u ON	r.defender_char_id = u.char_id JOIN( SELECT	abyss_id ,update_time FROM	abyss_user_defender WHERE	abyss_id = p_abyss_id::integer AND p_tick_from <= update_time AND update_time <= p_tick_to AND		defender_rank = 1 AND defender_share_amount <= p_valid_siege_point GROUP BY abyss_id, update_time HAVING	p_invalid_char_count::integer <= count(defender_char_id) UNION SELECT	abyss_id ,update_time FROM	abyss_user_defender WHERE	abyss_id = p_abyss_id::integer AND p_tick_from <= update_time AND update_time <= p_tick_to AND		defender_rank <= p_normal_rank_to GROUP BY abyss_id, update_time HAVING	count(defender_char_id) < p_normal_count_to ) s ON	s.abyss_id = r.abyss_id AND s.update_time = r.update_time JOIN( SELECT	abyss_id, update_time, count(abyss_id) AS contributer_total FROM	abyss_user_defender GROUP BY abyss_id, update_time ) c ON	c.abyss_id = s.abyss_id AND c.update_time = s.update_time ORDER BY u.char_id, r.abyss_id, r.update_time desc LIMIT 100;
END;
$$;

