    p_nWarehouse integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_ret integer;
BEGIN
    IF p_nWarehouse = 17 THEN
    UPDATE user_item SET warehouse = p_nWarehouse::integer WHERE id = p_nId;
    ELSE
    UPDATE user_item SET warehouse = p_nWarehouse::integer, update_date = CURRENT_TIMESTAMP WHERE id = p_nId;
    END IF;
    v_ret := v_rowcount;
    RETURN v_ret;
END;
$$;

