-- [OK] [AUTO] GM_UserUseditemOnTradingDAO_UpdateStatusForBuyRecovery

CREATE OR REPLACE FUNCTION gm_useruseditemontradingdao_updatestatusforbuyrecovery(
    p_char_id integer,
    p_name_id integer,
    p_status smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    update user_useditem_ontrading set status = p_status::integer where used_id=(SELECT  target_item.used_id from ( select ROW_NUMBER() over (PARTITION BY uuo.used_id order by ui.create_date desc) rnk, uuo.used_id from user_item ui join user_useditem_ontrading uuo on ui.name_id=uuo.tradeitemid where ui.char_id=uuo.char_id and ui.char_id = p_char_id::integer and name_id=p_name_id and trade_type=1 and status=0 and EXTRACT(EPOCH FROM (uuo.regdate)::timestamp - (ui.create_date)::timestamp)::integer between -1 and 2 ) target_item where target_item.rnk = 1 order by target_item.used_id desc LIMIT 1);
END;
$$;

