-- [OK] [AUTO] aion_GetGuildList_20150618

CREATE OR REPLACE FUNCTION aion_getguildlist_20150618(
    p_nType smallint,
    p_nRace smallint,
    p_strSearchString varchar(32)
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_nType = 0 THEN
    RETURN QUERY SELECT aa.id, aa.name, bb.user_id, aa.level, aa.memberCount, aa.intro, aa.join_process_type, aa.join_restrict_level FROM ( (SELECT a.id, a.name, a.master_id, a.level, b.memberCount, a.join_process_type, a.join_restrict_level, a.intro, a.rank FROM ( (SELECT  id, name, master_id, level, join_process_type, join_restrict_level, intro, rank  FROM guild WHERE race = p_nRace::integer and 0 < rank ORDER BY rank ASC LIMIT 50) a JOIN (SELECT COUNT(char_id) as memberCount, guild_id FROM user_data WHERE guild_id != 0 and delete_complete_date = 0 GROUP BY guild_id) b ON a.id = b.guild_id ) ) aa JOIN (SELECT char_id, user_id FROM user_data WHERE guild_id != 0 and delete_complete_date = 0) bb ON aa.master_id = bb.char_id ) ORDER BY aa.rank ASC;
    ELSIF p_nType = 1 THEN
    RETURN QUERY SELECT aa.id, aa.name, bb.user_id, aa.level, aa.memberCount, aa.intro, aa.join_process_type, aa.join_restrict_level FROM ( (SELECT a.id, a.name, a.master_id, a.level, b.memberCount, a.join_process_type, a.join_restrict_level, a.intro FROM ( (SELECT  id, name, master_id, level, join_process_type, join_restrict_level, intro  FROM guild WHERE race = p_nRace::integer and name LIKE '%' || p_strSearchString || '%' ORDER BY LENGTH(name) LIMIT 50) a JOIN (SELECT COUNT(char_id) as memberCount, guild_id FROM user_data WHERE guild_id != 0 and delete_complete_date = 0 GROUP BY guild_id) b ON a.id = b.guild_id ) ) aa JOIN (SELECT char_id, user_id FROM user_data WHERE guild_id != 0 and delete_complete_date = 0) bb ON aa.master_id = bb.char_id ) ORDER BY LENGTH(aa.name);
    ELSIF p_nType = 2 THEN
    RETURN QUERY SELECT aa.id, aa.name, bb.user_id, aa.level, aa.memberCount, aa.intro, aa.join_process_type, aa.join_restrict_level FROM ( (SELECT a.id, a.name, a.master_id, a.level, b.memberCount, a.join_process_type, a.join_restrict_level, a.intro FROM ( (SELECT  id, name, master_id, level, join_process_type, join_restrict_level, intro FROM guild WHERE race = p_nRace::integer and intro LIKE '%' || p_strSearchString || '%' LIMIT 50) a JOIN (SELECT COUNT(char_id) as memberCount, guild_id FROM user_data WHERE guild_id != 0 and delete_complete_date = 0 GROUP BY guild_id) b ON a.id = b.guild_id ) ) aa JOIN (SELECT char_id, user_id FROM user_data WHERE guild_id != 0 and delete_complete_date = 0) bb ON aa.master_id = bb.char_id );
    END IF;
END;
$$;

