-- [WARN] [REVIEW] aion_DeleteLegacyTables
--   Warning: CURSOR logic detected - converted to PG cursor syntax
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION aion_deletelegacytables(
    p_log_id bigint
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_table_name varchar(50);
    v_sql varchar(4000);
    cur_item CURSOR FOR SELECT table_name FROM legacy_table_list WHERE log_id = p_log_id;
BEGIN
    -- Transaction managed by PG function context
    OPEN cur_item;
    FETCH cur_item INTO v_table_name;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name = v_table_name) THEN
    v_sql := 'DROP TABLE ' || v_table_name;
    RAISE NOTICE '%', v_sql;
    EXECUTE v_sql;
    END IF;
    FETCH cur_item INTO v_table_name;
    v_fetch_found := FOUND;
    END LOOP;
    CLOSE cur_item;
    DELETE FROM legacy_table_list WHERE log_id = p_log_id;
    -- COMMIT (implicit in PG function)
END;
$$;

