-- [OK] [AUTO] aion_GetVendorItemListAllDark

CREATE OR REPLACE FUNCTION aion_getvendoritemlistalldark(
    p_warehouse smallint
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT vendor_item_dark.id, user_item.name_id, vendor_item_dark.sale_price, vendor_item_dark.user_price, vendor_item_dark.commit_amount, vendor_item_dark.commit_date,	vendor_item_dark.remain_amount, user_item.id,  user_data.char_id, user_data.user_id, COALESCE(user_item_option.soul_bound,0), COALESCE(user_item_option.enchant_count,0), COALESCE(user_item_option.skin_name_id,0), COALESCE(user_item_option.stat_enchant_name0,0), COALESCE(user_item_option.stat_enchant_name1,0), COALESCE(user_item_option.stat_enchant_name2,0), COALESCE(user_item_option.stat_enchant_name3,0), COALESCE(user_item_option.stat_enchant_name4,0), COALESCE(user_item_option.stat_enchant_name5,0), COALESCE(user_item_option.option_count,0), COALESCE(user_item_option.dye_info,0), COALESCE(user_item_option.proc_tool_nameid,0), user_item.producer, COALESCE(user_item_option.expire_dye_time, 0), COALESCE(user_item_option.limit_enchant_count, 0), COALESCE(user_item_option.random_option,0), COALESCE(user_item_option.reidentify_count,0), COALESCE(user_item_option.authorize_count, 0), COALESCE(user_item_option.vanish_point,0), COALESCE(user_item_option.enchant_prob_addition, 0), COALESCE(user_item_option.option_prob_addition, 0), COALESCE(user_item_option.keyNameId, 0), COALESCE(user_item_option.exceedState, 0), COALESCE(user_item_option.exceedSkillId1, 0), COALESCE(user_item_option.exceedSkillId2, 0), COALESCE(user_item_option.exceedSkillId3, 0) FROM	vendor_item_dark INNER JOIN user_item ON vendor_item_dark.user_item_id = user_item.id left JOIN user_item_option on user_item.id = user_item_option.id inner join user_data ON vendor_item_dark.char_id = user_data.char_id WHERE (user_item.warehouse = p_warehouse::integer);
END;
$$;

