-- [WARN] [REVIEW] GM_UserItem_SrchItemByType
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_useritem_srchitembytype(
    p_item_name_id varchar(2000),
    p_enchant_count_from varchar(30),
    p_enchant_count_to varchar(30),
    p_amount_from varchar(30),
    p_amount_to varchar(30),
    p_dbid_from varchar(30),
    p_dbid_to varchar(30),
    p_multi_user_ids varchar(1000),
    p_view_count varchar(6),
    p_top_count varchar(6),
    p_authorize_count_from varchar(30) DEFAULT 'NULL',
    p_authorize_count_to varchar(30) DEFAULT 'NULL'
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
BEGIN
    v_sql := ' SELECT TOP ' || p_view_count || '		i.tid, i.expired_time, i.buy_amount, i.buy_duration, i.id, i.char_id, i.name_id, i.amount, i.slot_id, i.slot, i.warehouse, TO_CHAR(i.create_date, ''YYYY-MM-DD HH24:MI:SS'') create_date, TO_CHAR(i.update_date, ''YYYY-MM-DD HH24:MI:SS'') update_date, i.producer ' || '		, u.char_id, u.user_id, u.account_id, u.account_name ' || '		, o.soul_bound, o.enchant_count, o.skin_name_id, o.stat_enchant_name0, o.stat_enchant_name1, o.stat_enchant_name2, o.stat_enchant_name3, o.stat_enchant_name4, o.stat_enchant_name5, o.option_count, o.dye_info, o.proc_tool_nameid, o.obtain_skin_type, o.expire_skin_time, o.expire_dye_time, COALESCE(o.random_option,0) AS random_option ' || '		, COALESCE(o.limit_enchant_count,0) AS limit_enchant_count, COALESCE(o.reidentify_count,0) AS reidentify_count ' || '		, COALESCE(f.freetradestate, 0) as freetradestate ' || '		, COALESCE(o.authorize_count, 0) as authorize_count, COALESCE(o.vanish_point, 0) as vanish_point ' || '		, COALESCE(attribute1, 0) as attribute1, COALESCE(attribute1value, 0) as attribute1value, COALESCE(attribute2, 0) as attribute2, COALESCE(attribute2value, 0) as attribute2value, COALESCE(attribute3, 0) as attribute3, COALESCE(attribute3value, 0) as attribute3value, COALESCE(attribute4, 0) as attribute4, COALESCE(attribute4value, 0) as attribute4value, COALESCE(attribute5, 0) as attribute5, COALESCE(attribute5value, 0) as attribute5value, COALESCE(attribute6, 0) as attribute6, COALESCE(attribute6value, 0) as attribute6value ' || '		, COALESCE(proc_break_count, 0) as proc_break_count, COALESCE(proc_break_flag, 0) as proc_break_flag ' || '		, COALESCE(exceedState, 0) as exceedState, COALESCE(exceedSkillId1, 0) as exceedSkillId1, COALESCE(exceedSkillId2, 0) as exceedSkillId2, COALESCE(exceedSkillId3, 0) as exceedSkillId3 ' || '		, COALESCE(baseSkillId, 0) as baseSkillId' || '		, COALESCE(enhanceSkillGroup, 0) as enhanceSkillGroup, COALESCE(enhanceSkillLevel, 0) as enhanceSkillLevel ' || '		, COALESCE(equipLevelDown, 0) as equipLevelDown' || '		, COALESCE(wardrobeSlotId, 0) as wardrobeSlotId' || '		, COALESCE(randomAttr1, 0) as randomAttr1, COALESCE(randomValue1, 0) as randomValue1 ' || '		, COALESCE(randomAttr2, 0) as randomAttr2, COALESCE(randomValue2, 0) as randomValue2 ' || '		, COALESCE(randomAttr3, 0) as randomAttr3, COALESCE(randomValue3, 0) as randomValue3 ' || '		, COALESCE(randomAttr4, 0) as randomAttr4, COALESCE(randomValue4, 0) as randomValue4 ' || '		, COALESCE(randomAttr5, 0) as randomAttr5, COALESCE(randomValue5, 0) as randomValue5 ' || '		, COALESCE(randomAttr6, 0) as randomAttr6, COALESCE(randomValue6, 0) as randomValue6 ' || '		, COALESCE(randomAttr7, 0) as randomAttr7, COALESCE(randomValue7, 0) as randomValue7 ' || '		, COALESCE(randomAttr8, 0) as randomAttr8, COALESCE(randomValue8, 0) as randomValue8 ' || '		, COALESCE(randomAttr9, 0) as randomAttr9, COALESCE(randomValue9, 0) as randomValue9 ' || '		, COALESCE(randomAttr10, 0) as randomAttr10, COALESCE(randomValue10, 0) as randomValue10 ' || ' FROM	user_item i  ' || ' JOIN	user_data u  on i.char_id = u.char_id ' || ' LEFT JOIN user_item_option o  on i.id = o.id and i.char_id = o.char_id ' || ' LEFT JOIN user_item_freeTrade f  on i.id = f.id ' || ' LEFT JOIN user_item_attribute a  on i.id = a.id ' || ' WHERE	u.delete_complete_date = 0 ' || ' AND	(i.warehouse IN (0, 1, 3, 4, 5) or (i.warehouse between 30 and 49) or (i.warehouse between 60 and 79)) ';
    IF p_multi_user_ids != 'null' THEN
    v_sql := v_sql || ' AND (' || p_multi_user_ids || ') ';
    END IF;
    IF p_item_name_id != 'null' THEN
    v_sql := v_sql || ' AND (' || p_item_name_id || ' ) ';
    END IF;
    IF p_enchant_count_from != 'null' AND p_enchant_count_to != 'null' THEN
    v_sql := v_sql || ' AND o.enchant_count >= ''' || p_enchant_count_from || ''' and o.enchant_count <= ''' || p_enchant_count_to || ''' ';
    END IF;
    IF p_amount_from != 'null' AND p_amount_to != 'null' THEN
    v_sql := v_sql || ' AND i.amount >= ''' || p_amount_from || ''' and i.amount <= ''' || p_amount_to || ''' ';
    END IF;
    IF p_dbid_from != 'null' AND p_dbid_to != 'null' THEN
    v_sql := v_sql || ' AND i.id >= ''' || p_dbid_from || ''' and i.id <= ''' || p_dbid_to || ''' ';
    END IF;
    IF p_authorize_count_from != 'null' AND p_authorize_count_to != 'null' THEN
    v_sql := v_sql || ' AND o.authorize_count >= ''' || p_authorize_count_from || ''' and o.authorize_count <= ''' || p_authorize_count_to || ''' ';
    END IF;
    v_sql := v_sql || ' AND i.id not in (' || ' SELECT top ' || p_top_count || ' i.id ' || ' FROM	user_item i, user_data u ' || ' WHERE	delete_complete_date = 0 and i.char_id = u.char_id ' || ' AND	(i.warehouse in (0, 1, 3, 4, 5) or (i.warehouse between 30 and 49) or (i.warehouse between 60 and 79))' IF p_multi_user_ids != 'null' BEGIN set v_sql = v_sql || ' AND (' || p_multi_user_ids || ') ' END IF p_item_name_id != 'null' BEGIN set v_sql = v_sql || ' AND (' || p_item_name_id || ' ) ' END IF p_enchant_count_from != 'null' AND p_enchant_count_to != 'null' BEGIN set v_sql = v_sql || ' AND o.enchant_count >= ''' || p_enchant_count_from || ''' and o.enchant_count <= ''' || p_enchant_count_to || ''' ' END IF p_amount_from != 'null' AND p_amount_to != 'null' BEGIN set v_sql = v_sql || ' AND i.amount >= ''' || p_amount_from || ''' and i.amount <= ''' || p_amount_to || ''' ' END IF p_dbid_from != 'null' AND p_dbid_to != 'null' BEGIN set v_sql = v_sql || ' AND i.id >= ''' || p_dbid_from || ''' and i.id <= ''' || p_dbid_to || ''' ' END IF p_authorize_count_from != 'null' AND p_authorize_count_to != 'null' BEGIN set v_sql = v_sql || ' AND o.authorize_count >= ''' || p_authorize_count_from || ''' and o.authorize_count <= ''' || p_authorize_count_to || ''' ' END set v_sql = v_sql || ' order by i.char_id asc' || ') order by i.char_id asc ';
    EXECUTE v_sql;
END;
$$;

