    p_nCharID integer,
    p_nGuildOfflineChangeFlag smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_nGuildOfflineChangeFlag = 0 THEN
    UPDATE user_data SET guild_offline_change_flag=0, change_info_time = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) WHERE char_id = p_nCharID::integer;
    ELSE
    UPDATE user_data SET guild_offline_change_flag = guild_offline_change_flag | p_nGuildOfflineChangeFlag, change_info_time = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) WHERE char_id = p_nCharID::integer;
    END IF;
END;
$$;

