-- [OK] [AUTO] aion_PutSkill

CREATE OR REPLACE FUNCTION aion_putskill(
    p_nCharId integer,
    p_nSkillId integer,
    p_nSkillData1 integer,
    p_nSkillData2 integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    -- Transaction managed by PG function context
    IF EXISTS (SELECT skill_id FROM user_skill WHERE  char_id = p_nCharId::integer and skill_id=p_nSkillId) THEN
    UPDATE user_skill SET skill_data1 = p_nSkillData1 , skill_data2 = p_nSkillData2 WHERE char_id = p_nCharId::integer and skill_id=p_nSkillId;
    ELSE
    INSERT INTO user_skill(char_id, skill_id, skill_data1, skill_data2) VALUES (p_nCharId, p_nSkillId, p_nSkillData1,p_nSkillData2);
    END IF;
    -- COMMIT (implicit in PG function)
END;
$$;

