-- [WARN] [REVIEW] GM_UserItem_SrchItemCntByType
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_useritem_srchitemcntbytype(
    p_item_name_id varchar(1000),
    p_enchant_count_from varchar(30),
    p_enchant_count_to varchar(30),
    p_amount_from varchar(30),
    p_amount_to varchar(30),
    p_dbid_from varchar(30),
    p_dbid_to varchar(30),
    p_authorize_count_from varchar(30) DEFAULT 'NULL',
    p_authorize_count_to varchar(30) DEFAULT 'NULL'
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(2000);
BEGIN
    v_sql := 'SELECT i.name_id, sum(i.amount) amount_sum ' || ' FROM	user_item i  ' || ' JOIN	user_data u  on i.char_id = u.char_id ' || ' LEFT JOIN	user_item_option o  on i.id = o.id and i.char_id = o.char_id ' || ' WHERE	u.delete_complete_date=0 ' || ' AND	(i.warehouse in (0,1,3,4,5,6,7) OR (i.warehouse between 30 and 49) OR (i.warehouse between 60 and 79)) ';
    IF (p_item_name_id != 'null') THEN
    v_sql := v_sql || ' AND (' || p_item_name_id || ' ) ';
    END IF;
    IF (p_enchant_count_from != 'null' AND p_enchant_count_to != 'null') THEN
    v_sql := v_sql || ' AND o.enchant_count >= ''' || p_enchant_count_from || ''' AND o.enchant_count <= ''' || p_enchant_count_to || ''' ';
    END IF;
    IF (p_amount_from != 'null' AND p_amount_to != 'null') THEN
    v_sql := v_sql || ' AND i.amount >= ''' || p_amount_from || ''' AND i.amount <= ''' || p_amount_to || ''' ';
    END IF;
    IF (p_dbid_from != 'null' AND p_dbid_to != 'null') THEN
    v_sql := v_sql || ' AND i.id >= ''' || p_dbid_from || ''' AND i.id <= ''' || p_dbid_to || ''' ';
    END IF;
    IF p_authorize_count_from != 'null' AND p_authorize_count_to != 'null' THEN
    v_sql := v_sql || ' AND o.authorize_count >= ''' || p_authorize_count_from || ''' and o.authorize_count <= ''' || p_authorize_count_to || ''' ';
    END IF;
    v_sql := v_sql || ' GROUP BY i.name_id ';
    EXECUTE v_sql;
END;
$$;

