-- [OK] [AUTO] aion_GetGuildMemberRankList_110705

CREATE OR REPLACE FUNCTION aion_getguildmemberranklist_110705(
    p_nGuildId integer,
    p_type integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_utc_adjust bigint;
BEGIN
    v_utc_adjust := GetUtcAdjustSecWithUTC_Local((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), CURRENT_TIMESTAMP);
    IF p_type = 0 THEN
    PERFORM char_id, user_id, class, gender, lev, world, guild_rank, guild_intro, guild_nickname, GetUnixtimeWithUTCAdjust(last_logout_time, v_utc_adjust) AS last_logout_time, a.race, 0, COALESCE(b.id, -1), COALESCE(permission,0) FROM user_data a left join house_instant b on a.char_id = b.id and b.state<>6 WHERE a.guild_id = p_nGuildId::integer and a.delete_complete_date = 0;
    ELSE
    PERFORM char_id, user_id, class, gender, lev, world, guild_rank, guild_intro, guild_nickname, GetUnixtimeWithUTCAdjust(last_logout_time, v_utc_adjust) AS last_logout_time, a.race, b.id, b.addr_id, COALESCE(permission, 0) FROM user_data a, house_field b WHERE a.guild_id = p_nGuildId::integer and a.delete_complete_date = 0 and a.char_id = b.owner_id AND b.owner_type = 2;
    END IF;
END;
$$;

