-- [OK] [AUTO] GM_WorldBotChannelInfoDA_SrchUserList

CREATE OR REPLACE FUNCTION gm_worldbotchannelinfoda_srchuserlist(
    p_zone_id_from integer,
    p_zone_id_to integer,
    p_account_id integer,
    p_char_id integer,
    p_user_id varchar(20)
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_query varchar(2000);
    v_where varchar(500);
BEGIN
    v_query := ';
    RETURN QUERY SELECT	w.char_id, w.account_id, w.world_id as zone_id, u.user_id, u.org_server FROM	world_bot_channel_info w JOIN	user_data u on u.char_id = w.char_id ';
    v_where := '1 = 1';
    IF (p_zone_id_from != 0) THEN
    v_where := v_where || ' AND	w.world_id >= ' || CAST(p_zone_id_from AS varchar);
    END IF;
    IF (p_zone_id_to != 0) THEN
    v_where := v_where || ' AND	w.world_id <= ' || CAST(p_zone_id_to AS varchar);
    END IF;
    IF (p_account_id != 0) THEN
    v_where := v_where || ' AND	w.account_id = ' || CAST(p_account_id AS varchar);
    END IF;
    IF (p_char_id != 0) THEN
    v_where := v_where || ' AND	w.char_id = ' || CAST(p_char_id AS varchar);
    END IF;
    IF (p_user_id != '') THEN
    v_where := v_where || ' AND	user_id = ''' || CAST(p_user_id AS varchar) || '''';
    END IF;
    v_query := v_query || ' WHERE ' || v_where || ' ORDER BY w.world_id, w.char_id DESC ';
    RAISE NOTICE '%', v_query;
    EXECUTE v_query;
END;
$$;

