-- [WARN] [REVIEW] GM_AbyssRankingDA_SrchAbyssRankingList
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_abyssrankingda_srchabyssrankinglist(
    p_race_type varchar(1),
    p_user_id varchar(50),
    p_view_count bigint,
    p_top_count bigint,
    p_from_date varchar(30),
    p_to_date varchar(30),
    p_world_id varchar(3)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(3000);
BEGIN
    v_sql := ' select * from (' || '	select top ' || CAST(p_top_count || p_view_count AS varchar) || ' rank() over (order by update_time desc, abyss_ranking) as ''num''' || '			, t3.name, t2.best_abyss_rank, t1.guild_id, t1.abyss_ranking, t1.old_ranking, t1.lev, t1.class, t1.race, t1.abyss_point, t1.rank, t1.update_time, t1.rank_updatedate' || '			, t2.char_id, t2.user_id, t2.account_id, t2.account_name, t2.gender, t2.delete_date, t2.org_server, t2.cur_server,COALESCE(t2.login_server, t2.org_server) login_server' || '			, case	WHEN t2.last_login_time = t2.last_logout_time and t2.last_login_time != ''1970-01-01 00:00:00.000'' and t2.last_logout_time > ''2007-12-12 00:00:00.000'' THEN ''#339900'' ' || '					WHEN t2.last_login_time != t2.last_logout_time or t2.last_login_time = ''1970-01-01 00:00:00.000''  THEN ''brown'' ' || '					WHEN t2.last_login_time = t2.last_logout_time and t2.last_login_time != ''1970-01-01 00:00:00.000'' THEN ''black'' ' || '					end as logonoff ' || '			, COALESCE(t1.gp,0) as glory_point, COALESCE(gp.ownership_bonus_gp,0) as ownership_bonus_gp ' || '	from	abyss_ranking t1 ' || '	left outer join guild t3 on t1.guild_id = t3.id ' || '	left outer join guild t4 on t1.guild_id = t4.id ' || '	left join user_gp_data gp on t1.char_id = gp.char_id ' || '	left join user_data t2 on t1.char_id = t2.char_id ' || '	where	t1.update_time between ''' || p_from_date || ''' and ''' || p_to_date || ''' ' || '	and		t2.org_server=''' || p_world_id || ''' ' IF p_user_id != 'null' BEGIN set v_sql = v_sql || '	and		t2.user_id = ''' || p_user_id || '''' END IF p_race_type != '2' BEGIN set v_sql = v_sql || '	and		t1.race = ''' || p_race_type || '''' END set v_sql = v_sql || '	order by update_time desc, abyss_ranking asc) x ' || ' where num between ' || CAST(p_top_count + 1 AS varchar) || ' and ' || CAST(p_top_count || p_view_count AS varchar) || ' order by update_time desc, abyss_ranking asc ';
    EXECUTE v_sql;
END;
$$;

