-- [OK] [AUTO] rename_constraint

CREATE OR REPLACE FUNCTION rename_constraint(
    p_table varchar(100),
    p_column varchar(100),
    p_newName varchar(250)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_oldName varchar(250);
BEGIN
    PERFORM get_constraint_name(p_table, p_column, v_oldName);
    RAISE NOTICE '%', v_oldName;
    PERFORM sp_rename(v_oldName, p_newName, 'object');
    PERFORM get_constraint_name(p_table, p_column, v_oldName);
    RAISE NOTICE '%', v_oldName;
END;
$$;

