    p_account_id integer DEFAULT NULL,
    p_account_name varchar(14) DEFAULT NULL
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    IF (p_account_id is not null and p_account_name is not null) THEN
    RETURN QUERY SELECT	access_id, account_id ,account_name, status, regdate from	access_allow_account where	account_id = p_account_id::integer and		account_name = p_account_name;
