    p_status integer DEFAULT NULL
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_query text;
BEGIN
    v_query := ';
    PERFORM  || ' LIMIT ' || CAST(p_view_count AS varchar) access_id, account_id ,account_name, status, regdate FROM	access_allow_account  WHERE	access_id NOT IN (SELECT /*INLINE_LIMIT:' || CAST(p_view_count*(p_page-1*/ AS varchar) || ') access_id FROM access_allow_account  WHERE	account_name IN (' || p_cvs_account_name || ') AND		(' || CAST(COALESCE(p_status, '-1') AS varchar) || '=-1 OR status = ' || CAST(COALESCE(p_status, '-1') AS varchar) || ') ORDER BY account_name ) AND		account_name IN (' || p_cvs_account_name || ') AND		(' || CAST(COALESCE(p_status, '-1') AS varchar) || '=-1 OR status = ' || CAST(COALESCE(p_status, '-1') AS varchar) || ') ORDER BY account_name ';
    EXECUTE v_query;
END;
$$;

