    p_id integer,
    p_addr_id integer,
    p_building_nameid integer,
    p_owner_id integer,
    p_owner_type smallint,
    p_owner_race smallint,
    p_state smallint,
    p_permission smallint,
    p_comment_state smallint,
    p_roof integer,
    p_outwall integer,
    p_frame integer,
    p_door integer,
    p_garden integer,
    p_fence integer,
    p_inwall1 integer,
    p_inwall2 integer,
    p_inwall3 integer,
    p_inwall4 integer,
    p_inwall5 integer,
    p_inwall6 integer,
    p_infloor1 integer,
    p_infloor2 integer,
    p_infloor3 integer,
    p_infloor4 integer,
    p_infloor5 integer,
    p_infloor6 integer,
    p_addon1 integer,
    p_addon2 integer,
    p_addon3 integer,
    p_flag1 boolean,
    p_flag2 boolean,
    p_flag3 boolean,
    p_flag4 boolean,
    p_flag5 boolean,
    p_flag6 boolean,
