    v_rs_attach_account bigint;
BEGIN
    SELECT COALESCE(sum(amount),0) INTO v_rs_inven FROM user_item t1, user_data t2 where t1.char_id=t2.char_id and t2.delete_complete_date=0 and t1.name_id=182400001 and t1.warehouse=0;
    SELECT COALESCE(sum(amount),0) INTO v_rs_account FROM user_item  where char_id in ( select distinct account_id from user_data  where delete_complete_date=0 ) and name_id=182400001 and (warehouse=6 or warehouse=7);
    SELECT COALESCE(sum(fund),0) INTO v_rs_guild FROM guild  where delete_time=0	and fund > 0;
    SELECT COALESCE(sum(sold_price),0) INTO v_rs_vendor_light FROM vendor_log_light t1, user_data t2 where t1.char_id=t2.char_id and t2.delete_complete_date=0;
    SELECT COALESCE(sum(sold_price),0) INTO v_rs_vendor_dark FROM vendor_log_dark t1, user_data t2 where t1.char_id=t2.char_id and t2.delete_complete_date=0;
    SELECT COALESCE(sum(t1.money),0) INTO v_rs_mail FROM user_mail t1, user_data t2 where t1.money > 0 and t1.to_id=t2.char_id and t2.delete_complete_date=0;
    SELECT COALESCE(sum(amount),0) INTO v_rs_attach FROM user_item t1, user_data t2 where t1.char_id=t2.char_id and t2.delete_complete_date=0 and t1.name_id=182400001 and t1.warehouse=50;
    SELECT COALESCE(sum(amount),0) INTO v_rs_attach_account FROM user_item  where char_id in ( select distinct account_id from user_data  where delete_complete_date=0 ) and name_id=182400001 and (warehouse=56 or warehouse=57);
    PERFORM v_rs_inven inven, v_rs_account account, v_rs_guild guild, v_rs_vendor_light vendor_light, v_rs_vendor_dark vendor_dark, v_rs_mail mail, v_rs_attach attach,v_rs_attach_account attach_account, v_rs_inven+v_rs_account+v_rs_guild+v_rs_vendor_light+v_rs_vendor_dark+v_rs_mail as total_qina;
    RETURN;
END;
$$;

