-- [OK] [AUTO] usp_trace_start

CREATE OR REPLACE FUNCTION usp_trace_start(
    p_TraceFileName varchar(128) DEFAULT NULL,
    p_TraceName varchar(128) DEFAULT 'trace',
    p_option integer DEFAULT 2,
    p_MaxFileSize bigint DEFAULT 5,
    p_StopTime timestamp DEFAULT NULL,
    p_Events varchar(1000) DEFAULT '10,11,12,13,14,15,16,21,22,25,33,37,40,41,42,44,43,53,55,61,67,68,69,71,72,74,76,79,80',
    p_Cols varchar(300) DEFAULT '1,3,8,10,11,12,13,14,15,16,17,18,28,35,48',
    p_IncludeFilter varchar(128) DEFAULT NULL,
    p_ExcludeFilter varchar(128) DEFAULT NULL
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_TraceID integer;
    v_On boolean;
    v_Rc integer;
    v_i integer;
    v_j integer;
    v_Event integer;
    v_Col integer;
    v_Colstring varchar(300);
BEGIN
    v_On := 1;
    IF p_Events IS NULL OR p_Cols IS NULL THEN
    RAISE NOTICE '%', 'No Events or Coloumns.';
    RETURN -1;
    END IF;
    IF p_TraceFileName IS NULL THEN
    p_TraceFileName := 'C:\Trace\Trace' || CAST(CURRENT_TIMESTAMP AS char(8));
    END IF;
    v_Rc := sp_trace_create(v_TraceID, p_option, p_TraceFileName, p_MaxFileSize, p_StopTime);
    IF v_Rc <> 0 THEN
    RAISE NOTICE '%', 'Trace not started';
    RETURN v_Rc;
    END IF;
    RAISE NOTICE '%', 'Trace started.';
    RAISE NOTICE '%', 'The trace file name is ' || p_TraceFileName || '.';
    IF RIGHT(p_Events, 1) <> ',' SET p_Events = p_Events || ',' THEN
    v_i := POSITION(' IN ');
    END IF;
    WHILE v_i <> 0 LOOP
    v_Event := CAST(LEFT(p_Events, v_i - 1) AS integer);
    v_Colstring := p_Cols;
    IF RIGHT(v_Colstring, 1) <> ',' SET v_Colstring = v_Colstring || ',' THEN
    v_j := POSITION(' IN ');
    END IF;
    WHILE v_j <> 0 LOOP
    v_Col := CAST(LEFT(v_Colstring,v_j-1) AS integer);
    PERFORM sp_trace_setevent(v_TraceID, v_Event, v_Col, v_On);
    v_Colstring := SUBSTRING(v_Colstring FROM v_j+1 FOR 300);
    v_j := POSITION(' IN ');
    END LOOP;
    p_Events := SUBSTRING(p_Events FROM v_i + 1 FOR 300);
    v_i := POSITION(' IN ');
    END LOOP;
    PERFORM sp_trace_setfilter(v_TraceID, 10, 0, 7, 'SQL Profiler');
    PERFORM sp_trace_setfilter(v_TraceID, 1, 0, 7, 'EXEC% sp_%trace%');
    IF p_IncludeFilter IS NOT NULL THEN
    PERFORM sp_trace_setfilter(v_TraceID, 1, 0, 6, p_IncludeFilter);
    END IF;
    IF p_ExcludeFilter IS NOT NULL THEN
    PERFORM sp_trace_setfilter(v_TraceID, 1, 0, 7, p_ExcludeFilter);
    END IF;
    PERFORM sp_trace_setstatus(v_TraceID, 1);
    IF object_id('tempdb..TraceQueueList') IS NULL THEN
    CREATE TABLE tempdb..TraceQueueList(TraceID int, TraceName varchar(20), TraceFile sysname);
    END IF;
    IF EXISTS(SELECT * FROM tempdb..TraceQueueList WHERE TraceName = p_TraceName) BEGIN;
    UPDATE temdb..TraceQueueList SET TraceID = v_TraceId, TraceFile = p_TraceFileName WHERE TraceName = p_TraceName;
    ELSE
    INSERT INTO tempdb..TraceQueueList VALUES (v_TraceID, p_TraceName, p_TraceFileName);
END;
$$;

