-- [OK] [AUTO] GM_UserItemDA_SrchCountByNameIdAndCreateDateTo

CREATE OR REPLACE FUNCTION gm_useritemda_srchcountbynameidandcreatedateto(
    p_name_id integer,
    p_create_date_to varchar(20) DEFAULT ''
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_vendor_log_dark_qina bigint;
    v_vendor_log_light_qina bigint;
    v_guild_fund bigint;
BEGIN
    v_vendor_log_dark_qina := 0;
    v_vendor_log_light_qina := 0;
    v_guild_fund := 0;
    IF (p_create_date_to = '') THEN
    IF (p_name_id = 182400001) THEN
    SELECT COALESCE(SUM(sold_price), 0) INTO v_vendor_log_dark_qina FROM vendor_log_dark ;
    SELECT COALESCE(SUM(sold_price), 0) INTO v_vendor_log_light_qina FROM vendor_log_light ;
    SELECT COALESCE(SUM(fund), 0) INTO v_guild_fund FROM guild ;
    END IF;
    PERFORM	(SUM(amount) + v_vendor_log_dark_qina + v_vendor_log_light_qina + v_guild_fund) as total_amount, name_id from	user_item  where	name_id = p_name_id and		(warehouse in (0,1,3,4,5,6,7) OR (warehouse between 30 and 49) OR (warehouse between 60 and 79)) group by name_id;
    ELSE
    IF (p_name_id = 182400001) THEN
    SELECT COALESCE(SUM(sold_price), 0) INTO v_vendor_log_dark_qina FROM vendor_log_dark  where sold_date <= (EXTRACT(EPOCH FROM (p_create_date_to)::timestamp - ('1970-01-01 09:00')::timestamp) / 60)::integer;
    SELECT COALESCE(SUM(sold_price), 0) INTO v_vendor_log_light_qina FROM vendor_log_light  where sold_date <= (EXTRACT(EPOCH FROM (p_create_date_to)::timestamp - ('1970-01-01 09:00')::timestamp) / 60)::integer;
    SELECT COALESCE(SUM(fund), 0) INTO v_guild_fund FROM guild ;
    END IF;
    PERFORM	(SUM(amount) + v_vendor_log_dark_qina + v_vendor_log_light_qina + v_guild_fund) as total_amount, name_id from	user_item  where	name_id = p_name_id and		(warehouse in (0,1,3,4,5,6,7) OR (warehouse between 30 and 49) OR (warehouse between 60 and 79)) and		create_date <= p_create_date_to group by name_id;
    END IF;
END;
$$;

