-- [OK] [AUTO] aion_GetHighestLevelCharacterOfAccount

CREATE OR REPLACE FUNCTION aion_gethighestlevelcharacterofaccount(
    p_accountNum integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_accountNum = 0 THEN
    RETURN QUERY SELECT u1.account_id as gameAccountNo, u1.org_server as gameServerNo, u1.char_id as characterId, u1.lev as characterLevel FROM ( select row_number() over (partition by account_id order by lev desc, char_id asc) as rank_lev, account_id, org_server, char_id, lev from user_data Where delete_complete_date=0 ) as u1 WHERE u1.rank_lev=1;
    ELSE
    RETURN QUERY SELECT u1.account_id as gameAccountNo, u1.org_server as gameServerNo, u1.char_id as characterId, u1.lev as characterLevel FROM ( select row_number() over (partition by account_id order by lev desc, char_id asc) as rank_lev, account_id, org_server, char_id, lev from user_data Where delete_complete_date=0 and account_id = p_accountNum::integer ) as u1 WHERE u1.rank_lev=1;
    END IF;
END;
$$;

