-- [OK] [AUTO] usp_trace_stop

CREATE OR REPLACE FUNCTION usp_trace_stop(
    p_TraceName varchar(128) DEFAULT 'trace'
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_TraceID integer;
    v_TraceFileName varchar(128);
BEGIN
    IF object_id('tempdb..TraceQueueList') IS NOT NULL THEN
    SELECT TraceID, TraceFile INTO v_TraceID, v_TraceFileName FROM tempdb..TraceQueueList WHERE TraceName = p_TraceName;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount <> 0 THEN
    PERFORM sp_trace_setstatus(v_TraceID, 0);
    PERFORM sp_trace_setstatus(v_TraceID, 2);
    DELETE FROM tempdb..TraceQueueList WHERE TraceName = p_TraceName;
    RAISE NOTICE '%', 'Trace is stopped.' || ' The trace output file name is ' || v_TraceFileName;
    ELSE
    RAISE NOTICE '%', 'No active traces.';
    END IF;
END;
$$;

