CREATE OR REPLACE FUNCTION aion_sethouseinstantscript(
    p_char_id integer,
    p_slot_id integer,
    p_script_size smallint,
    p_script_data bytea
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT char_id FROM house_instant_script WHERE char_id = p_char_id::integer AND slot_id = p_slot_id) THEN
    UPDATE house_instant_script SET script_size = p_script_size, script_data = p_script_data WHERE char_id = p_char_id::integer AND slot_id = p_slot_id;
    ELSE
    INSERT INTO house_instant_script(char_id, slot_id, script_size, script_data) VALUES (p_char_id, p_slot_id, p_script_size, p_script_data);
    END IF;
END;
$$;

