-- [OK] [AUTO] GM_AionTVContentsDA_InsertUpdate

CREATE OR REPLACE FUNCTION gm_aiontvcontentsda_insertupdate(
    p_id integer,
    p_server_id integer,
    p_url varchar(1024),
    p_start_date bigint,
    p_end_date bigint,
    p_login_id varchar(30),
    p_login_nm varchar(30),
    p_is_deleted smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    UPDATE	aion_tv_contents SET		url = p_url , start_date = p_start_date , end_date = p_end_date , login_id = p_login_id , login_nm = p_login_nm , is_deleted = p_is_deleted , reg_date = CURRENT_TIMESTAMP WHERE	id = p_id AND server_id = p_server_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (v_rowcount < 1) THEN
    INSERT INTO aion_tv_contents (id, url, start_date, end_date, server_id, login_id, login_nm, reg_date, is_deleted) VALUES (p_id, p_url, p_start_date, p_end_date, p_server_id, p_login_id, p_login_nm, CURRENT_TIMESTAMP, p_is_deleted);
    END IF;
END;
$$;

