CREATE OR REPLACE FUNCTION gm_aiontvcontentsda_srch(
    p_server_id integer,
    p_isDeleted varchar(1) DEFAULT ''
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    IF (p_isDeleted != '') THEN
    RETURN QUERY SELECT	id, url, start_date, end_date, server_id, login_id, login_nm, reg_date, is_deleted FROM	aion_tv_contents  WHERE	server_id = p_server_id::integer AND is_deleted = CAST(p_isDeleted AS smallint) ORDER BY server_id, reg_date DESC;
