-- [OK] [AUTO] aion_SetHouseObjectByMoveHouse

CREATE OR REPLACE FUNCTION aion_sethouseobjectbymovehouse(
    p_owner_id integer,
    p_owner_type integer,
    p_oldState smallint,
    p_newState smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    -- Transaction managed by PG function context
    UPDATE houseobject SET	state = p_newState, world = 0, xlocation = 0.0, ylocation = 0.0, zlocation = 0.0, dir = 0 WHERE owner_id = p_owner_id::integer and state = p_oldState;
    UPDATE houseobject SET owner_type = p_owner_type, update_time = CURRENT_TIMESTAMP WHERE owner_id = p_owner_id::integer and state != 0;
    -- COMMIT (implicit in PG function)
END;
$$;

