LESCE(user_item_option.randomAttr4, 0), COALESCE(user_item_option.randomValue4, 0), COALESCE(user_item_option.randomAttr5, 0), COALESCE(user_item_option.randomValue5, 0), COALESCE(user_item_option.randomAttr6, 0), COALESCE(user_item_option.randomValue6, 0), COALESCE(user_item_option.randomAttr7, 0), COALESCE(user_item_option.randomValue7, 0), COALESCE(user_item_option.randomAttr8, 0), COALESCE(user_item_option.randomValue8, 0), COALESCE(user_item_option.randomAttr9, 0), COALESCE(user_item_option.randomValue9, 0), COALESCE(user_item_option.randomAttr10, 0), COALESCE(user_item_option.randomValue10, 0) FROM	vendor_item_light INNER JOIN user_item ON vendor_item_light.user_item_id = user_item.id left JOIN user_item_option on user_item.id = user_item_option.id inner join user_data ON vendor_item_light.char_id = user_data.char_id WHERE (user_item.warehouse = p_warehouse::integer);
