mAttr2, 0) as randomAttr2, COALESCE(randomValue2, 0) as randomValue2 ' || '		, COALESCE(randomAttr3, 0) as randomAttr3, COALESCE(randomValue3, 0) as randomValue3 ' || '		, COALESCE(randomAttr4, 0) as randomAttr4, COALESCE(randomValue4, 0) as randomValue4 ' || '		, COALESCE(randomAttr5, 0) as randomAttr5, COALESCE(randomValue5, 0) as randomValue5 ' || '		, COALESCE(randomAttr6, 0) as randomAttr6, COALESCE(randomValue6, 0) as randomValue6 ' || '		, COALESCE(randomAttr7, 0) as randomAttr7, COALESCE(randomValue7, 0) as randomValue7 ' || '		, COALESCE(randomAttr8, 0) as randomAttr8, COALESCE(randomValue8, 0) as randomValue8 ' || '		, COALESCE(randomAttr9, 0) as randomAttr9, COALESCE(randomValue9, 0) as randomValue9 ' || '		, COALESCE(randomAttr10, 0) as randomAttr10, COALESCE(randomValue10, 0) as randomValue10 ' || ' FROM	user_item T1  ' || ' JOIN	guild g  on g.id = T1.char_id ' || ' JOIN	user_data T3  on g.master_id = T3.char_id ' || ' LEFT JOIN user_item_option o  on T1.id = o.id ' || ' LEFT JOIN user_item_freeTrade f  on T1.id = f.id ' || ' LEFT JOIN user_item_attribute a  on T1.id = a.id ' || ' WHERE	T1.warehouse = 3 and (' || p_cond || ')';
