(randomAttr2, 0) as randomAttr2, COALESCE(randomValue2, 0) as randomValue2 ' || '		, COALESCE(randomAttr3, 0) as randomAttr3, COALESCE(randomValue3, 0) as randomValue3 ' || '		, COALESCE(randomAttr4, 0) as randomAttr4, COALESCE(randomValue4, 0) as randomValue4 ' || '		, COALESCE(randomAttr5, 0) as randomAttr5, COALESCE(randomValue5, 0) as randomValue5 ' || '		, COALESCE(randomAttr6, 0) as randomAttr6, COALESCE(randomValue6, 0) as randomValue6 ' || '		, COALESCE(randomAttr7, 0) as randomAttr7, COALESCE(randomValue7, 0) as randomValue7 ' || '		, COALESCE(randomAttr8, 0) as randomAttr8, COALESCE(randomValue8, 0) as randomValue8 ' || '		, COALESCE(randomAttr9, 0) as randomAttr9, COALESCE(randomValue9, 0) as randomValue9 ' || '		, COALESCE(randomAttr10, 0) as randomAttr10, COALESCE(randomValue10, 0) as randomValue10 ' || ' FROM	user_item T1  ' || ' JOIN	user_data T2  on T2.account_id = T1.char_id and T2.delete_complete_date = 0 ' || ' LEFT JOIN user_item_option o  on T1.id = o.id and T1.char_id = o.char_id ' || ' LEFT JOIN user_item_freeTrade f  on T1.id = f.id ' || ' LEFT JOIN user_item_attribute a  on T1.id = a.id ' || ' WHERE	T2.org_server=''' || p_world_Id || ''' and (' || p_cond || ') ' || ' AND	T1.warehouse IN (2,6,56,7,57) ';
    ELSE
    v_sql := 'SELECT	T1.id, T1.char_id, T1.name_id, T1.amount, T1.slot, T1.warehouse, T1.producer, T1.tid, T1.expired_time, T1.buy_amount, T1.buy_duration ' || '		, T2.char_id, T2.user_id, T2.account_name, T2.account_id, T2.org_server ' || '		, o.soul_bound, o.enchant_count, o.skin_name_id, o.stat_enchant_name0, o.stat_enchant_name1, o.stat_enchant_name2, o.stat_enchant_name3, o.stat_enchant_name4, o.stat_enchant_name5, o.dye_info, o.proc_tool_nameid, o.obtain_skin_type, o.expire_skin_time, o.expire_dye_time, COALESCE(o.random_option,0) AS random_option ' || '		, o.limit_enchant_count, o.reidentify_count ' || '		, COALESCE(f.freetradestate, 0) as freetradestate ' || '		, COALESCE(o.authorize_count, 0) as authorize_count, COALESCE(o.vanish_point, 0) as vanish_point ' || '		, COALESCE(attribute1, 0) as attribute1, COALESCE(attribute1value, 0) as attribute1value, COALESCE(attribute2, 0) as attribute2, COALESCE(attribute2value, 0) as attribute2value, COALESCE(attribute3, 0) as attribute3, COALESCE(attribute3value, 0) as attribute3value, COALESCE(attribute4, 0) as attribute4, COALESCE(attribute4value, 0) as attribute4value, COALESCE(attribute5, 0) as attribute5, COALESCE(attribute5value, 0) as attribute5value, COALESCE(attribute6, 0) as attribute6, COALESCE(attribute6value, 0) as attribute6value ' || '		, COALESCE(proc_break_count, 0) as proc_break_count, COALESCE(proc_break_flag, 0) as proc_break_flag ' || '		, COALESCE(exceedState, 0) as exceedState, COALESCE(exceedSkillId1, 0) as exceedSkillId1, COALESCE(exceedSkillId2, 0) as exceedSkillId2, COALESCE(exceedSkillId3, 0) as exceedSkillId3 ' || '		, COALESCE(baseSkillId, 0) as baseSkillId ' || '		, COALESCE(enhanceSkillGroup, 0) as enhanceSkillGroup, COALESCE(enhanceSkillLevel, 0) as enhanceSkillLevel ' || '		, COALESCE(equipLevelDown, 0) as equipLevelDown ' || '		, COALESCE(wardrobeSlotId, 0) as wardrobeSlotId ' || '		, COALESCE(randomAttr1, 0) as randomAttr1, COALESCE(randomValue1, 0) as randomValue1 ' || '		, COALESCE(randomAttr2, 0) as randomAttr2, COALESCE(randomValue2, 0) as randomValue2 ' || '		, COALESCE(randomAttr3, 0) as randomAttr3, COALESCE(randomValue3, 0) as randomValue3 ' || '		, COALESCE(randomAttr4, 0) as randomAttr4, COALESCE(randomValue4, 0) as randomValue4 ' || '		, COALESCE(randomAttr5, 0) as randomAttr5, COALESCE(randomValue5, 0) as randomValue5 ' || '		, COALESCE(randomAttr6, 0) as randomAttr6, COALESCE(randomValue6, 0) as randomValue6 ' || '		, COALESCE(randomAttr7, 0) as randomAttr7, COALESCE(randomValue7, 0) as randomValue7 ' || '		, COALESCE(randomAttr8, 0) as randomAttr8, COALESCE(randomValue8, 0) as randomValue8 ' || '		, COALESCE(randomAttr9, 0) as randomAttr9, COALESCE(randomValue9, 0) as randomValue9 ' || '		, COALESCE(randomAttr10, 0) as randomAttr10, COALESCE(randomValue10, 0) as randomValue10 ' || ' FROM	user_item T1  ' || ' JOIN	user_data T2  on T1.char_id = T2.char_id ' || ' LEFT JOIN user_item_option o  on T1.id = o.id ' || ' LEFT JOIN user_item_freeTrade f  on T1.id = f.id ' || ' LEFT JOIN user_item_attribute a  on T1.id = a.id ' || ' WHERE	T2.org_server=''' || p_world_Id || ''' and (' || p_cond || ') ';
    IF (p_warehouse = '0') THEN
