CREATE OR REPLACE FUNCTION gm_builderlogda_srchbuilderlog(
    p_char_nm varchar(20),
    p_build_nm varchar(40),
    p_view_count varchar(5),
    p_top_count varchar(5),
    p_from_date varchar(30),
    p_to_date varchar(30),
    p_builder_lv varchar(5),
    p_command_from varchar(5) DEFAULT ''
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(1500);
    v_sql_tmp varchar(300);
    v_tmp integer;
BEGIN
    v_sql_tmp := ' ';
    IF p_char_nm != 'null' THEN
    v_sql_tmp := v_sql_tmp || ' and CHAR_NM = ''' || p_char_nm || '''';
    END IF;
    IF p_build_nm != 'null' THEN
    v_sql_tmp := v_sql_tmp || ' and BUILD_NM = ''' || p_build_nm || '''';
    END IF;
    IF p_builder_lv != 'null' THEN
    v_sql_tmp := v_sql_tmp || ' and builder_lv = ''' || p_builder_lv || '''';
    END IF;
    IF p_command_from != '' THEN
    v_sql_tmp := v_sql_tmp || ' and command_from = ''' || p_command_from || '''';
    END IF;
    v_sql := ' select top ' || p_view_count || ' BUILDER_LOG_ID, WORLD_ID, CHAR_NM, TARGET_CHAR_NM, BUILD_NM, BUILD_PARAMETER, BUILDER_TYPE, BUILDER_LV, TO_CHAR(REGDATE, ''YYYY-MM-DD HH24:MI:SS'') REGDATE, COMMAND_FROM, RESULT_MESSAGE ' || ' from	builder_log  ' || ' where	BUILDER_LOG_ID not in(select top ' || p_top_count || ' BUILDER_LOG_ID from builder_log where regdate between ''' || p_from_date || ''' and ''' || p_to_date || ''' ' || v_sql_tmp || ' order by BUILDER_LOG_ID desc) ' || ' and	regdate between ''' || p_from_date || ''' and ''' || p_to_date || ''' ' || v_sql_tmp || ' order by BUILDER_LOG_ID desc ';
    EXECUTE v_sql;
    RETURN;
END;
$$;

