-- [WARN] [REVIEW] GM_UserItemDA_SrchItemNameIDByType
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_useritemda_srchitemnameidbytype(
    p_item_name_id varchar(2000),
    p_enchant_count_from varchar(30),
    p_enchant_count_to varchar(30),
    p_amount_from varchar(30),
    p_amount_to varchar(30),
    p_dbid_from varchar(30),
    p_dbid_to varchar(30),
    p_view_count varchar(5),
    p_top_count varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(2500);
BEGIN
    v_sql := 'select top ' || p_view_count || ' sum(t1.amount) amount, t1.name_id, ' || ' t2.char_id, t2.user_id, t2.account_id, t2.account_name ' || ' from user_item t1 , user_data t2 ' || ' where t2.delete_complete_date=''0'' and t1.char_id = t2.char_id and (t1.warehouse=0 or t1.warehouse=1 or t1.warehouse=3 or t1.warehouse=4 or t1.warehouse=5) ';
    IF p_item_name_id != 'null' THEN
    v_sql := v_sql || ' and (' || p_item_name_id || ' ) ';
    END IF;
    IF p_enchant_count_from != 'null' AND p_enchant_count_to != 'null' THEN
    v_sql := v_sql || '     and t1.enchant_count >= ''' || p_enchant_count_from || ''' and t1.enchant_count <= ''' || p_enchant_count_to || ''' ';
    END IF;
    IF p_amount_from != 'null' AND p_amount_to != 'null' THEN
    v_sql := v_sql || '      and t1.amount >= ''' || p_amount_from || ''' and t1.amount <= ''' || p_amount_to || ''' ';
    END IF;
    IF p_dbid_from != 'null' AND p_dbid_to != 'null' THEN
    v_sql := v_sql || '      and t1.id >= ''' || p_dbid_from || ''' and t1.id <= ''' || p_dbid_to || ''' ';
    END IF;
    v_sql := v_sql || '       and t1.id not in (select top ' || p_top_count || ' t1.id from user_item t1 , user_data t2 ' || ' where delete_date=''0'' and t1.char_id = t2.char_id and (t1.warehouse=0 or t1.warehouse=1 or t1.warehouse=6 or t1.warehouse=7 or t1.warehouse=3 or t1.warehouse=4 or t1.warehouse=5) ' IF p_item_name_id != 'null' BEGIN set v_sql = v_sql || ' and (' || p_item_name_id || ' ) ' END IF p_enchant_count_from != 'null' AND p_enchant_count_to != 'null' BEGIN set v_sql = v_sql || '     and t1.enchant_count >= ''' || p_enchant_count_from || ''' and t1.enchant_count <= ''' || p_enchant_count_to || ''' ' END IF p_amount_from != 'null' AND p_amount_to != 'null' BEGIN set v_sql = v_sql || '     and t1.amount >= ''' || p_amount_from || ''' and t1.amount <= ''' || p_amount_to || ''' ' END IF p_dbid_from != 'null' AND p_dbid_to != 'null' BEGIN set v_sql = v_sql || '      and t1.id >= ''' || p_dbid_from || ''' and t1.id <= ''' || p_dbid_to || '''  ' END set v_sql = v_sql || ' order by t1.char_id asc ' || ' ) group by t1.name_id,  t2.char_id, t2.user_id, t2.account_id, t2.account_name      ';
    EXECUTE v_sql;
    RETURN;
END;
$$;

