CREATE OR REPLACE FUNCTION aion_setinfinityseasonrecord(
    p_charid integer,
    p_prev integer,
    p_current integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    -- Transaction managed by PG function context
    update user_extra_info set prevSeasonReward = p_prev, currentSeasonReward = p_current where char_id = p_charid::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    insert into user_extra_info (char_id, use_bot_channel, account_id, vip_icon, prevSeasonReward, currentSeasonReward) values (p_charid, 0, 0, 0, p_prev, p_current);
    END IF;
    -- COMMIT (implicit in PG function)
END;
$$;

