-- [OK] [AUTO] aion_SetInstance

CREATE OR REPLACE FUNCTION aion_setinstance(
    p_instance_id integer,
    p_validity_time integer,
    p_spawn_page integer,
    p_phase varchar(1024)
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT instance_id FROM instance WHERE instance_id = p_instance_id::integer) THEN
    UPDATE instance SET validity_time = p_validity_time, spawn_page = p_spawn_page, phase_data = p_phase WHERE instance_id = p_instance_id::integer;
    ELSE
