-- [WARN] [REVIEW] aion_randombuddy
--   Warning: CURSOR logic detected - converted to PG cursor syntax

CREATE OR REPLACE FUNCTION aion_randombuddy(
    p_ownerid integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_getCount integer;
    v_buddyid integer;
    v_count1 integer;
    v_count2 integer;
    buddycursor CURSOR FOR select a.buddy_id from user_buddy1 a inner join house_field b on buddy_id  = owner_id and permission = 1 where a.char_id = p_ownerid::integer union select a.buddy_id from user_buddy1 a inner join house_instant b on buddy_id  = ID and permission = 1 where a.char_id = p_ownerid::integer;
BEGIN
    SELECT count(a.buddy_id) INTO v_count1 FROM user_buddy1 a inner join house_field b on buddy_id  = owner_id and permission = 1 where a.char_id = p_ownerid::integer;
    SELECT count(a.buddy_id) INTO v_count2 FROM user_buddy1 a inner join house_instant b on buddy_id  = ID and permission = 1 where a.char_id = p_ownerid::integer;
    IF v_count1 + v_count2 = 0 THEN
    RETURN 0;
    END IF;
    v_getCount := (CAST(((rand()*100)) AS integer)%(v_count1 + v_count2));
    v_buddyid := 0;
    OPEN buddycursor;
    FETCH buddycursor INTO v_buddyid;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    IF v_getCount < 0 break THEN
    v_getCount := v_getCount - 1;
    END IF;
    FETCH buddycursor INTO v_buddyid;
    v_fetch_found := FOUND;
    END LOOP;
    CLOSE buddycursor;
    RETURN v_buddyid;
END;
$$;

