-- [OK] [AUTO] aion_RefundItem

CREATE OR REPLACE FUNCTION aion_refunditem(
    p_nItemNameId integer,
    p_nTid integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE user_mail SET item_id = 0, item_nameid = 0, item_amount = 0 WHERE item_id IN (SELECT id FROM user_item WHERE tid = p_nTid AND name_id = p_nItemNameId);
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN 0;
    END IF;
    UPDATE user_item SET warehouse = 13 WHERE tid = p_nTid AND name_id = p_nItemNameId;
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN 0;
    END IF;
    RETURN 1;
END;
$$;

