-- [OK] [AUTO] Z_SendItem

CREATE OR REPLACE FUNCTION z_senditem(
    p_to_name varchar(20),
    p_from_name varchar(20),
    p_title varchar(20),
    p_item_id bigint,
    p_item_amount bigint DEFAULT 1,
    p_enchant integer DEFAULT 0,
    p_mana_stone bigint DEFAULT 0,
    p_god_stone bigint DEFAULT 0,
    p_mana_stone_count bigint DEFAULT 4
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_char_id integer;
    v_dbid bigint;
BEGIN
    IF (p_item_id <> 0) THEN
    v_char_id := (SELECT  char_id FROM user_data WHERE user_id = p_to_name::integer and delete_date = 0 and delete_complete_date = 0 LIMIT 1);
    IF v_char_id >0 THEN
    INSERT INTO user_item (char_id,name_id,amount,slot,warehouse) VALUES (v_char_id,p_item_id,p_item_amount,'0',5);
    v_dbid := LASTVAL();
    IF p_enchant > 0 OR p_mana_stone > 0 OR p_god_stone > 0 THEN
    IF p_mana_stone_count = 0 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id,stat_enchant_name0,stat_enchant_name1,stat_enchant_name2,stat_enchant_name3,stat_enchant_name4,stat_enchant_name5,proc_tool_nameid,option_count) VALUES (v_dbid, v_char_id, p_enchant, p_item_id,0,0,0,0,0,0,p_god_stone,0);
    ELSIF p_mana_stone_count = 1 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id,stat_enchant_name0,stat_enchant_name1,stat_enchant_name2,stat_enchant_name3,stat_enchant_name4,stat_enchant_name5,proc_tool_nameid,option_count) VALUES (v_dbid, v_char_id, p_enchant, p_item_id,p_mana_stone,0,0,0,0,0,p_god_stone,0);
    ELSIF p_mana_stone_count = 2 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id,stat_enchant_name0,stat_enchant_name1,stat_enchant_name2,stat_enchant_name3,stat_enchant_name4,stat_enchant_name5,proc_tool_nameid,option_count) VALUES (v_dbid, v_char_id, p_enchant, p_item_id,p_mana_stone,p_mana_stone,0,0,0,0,p_god_stone,0);
    ELSIF p_mana_stone_count = 3 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id,stat_enchant_name0,stat_enchant_name1,stat_enchant_name2,stat_enchant_name3,stat_enchant_name4,stat_enchant_name5,proc_tool_nameid,option_count) VALUES (v_dbid, v_char_id, p_enchant, p_item_id,p_mana_stone,p_mana_stone,p_mana_stone,0,0,0,p_god_stone,0);
    ELSIF p_mana_stone_count = 4 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id,stat_enchant_name0,stat_enchant_name1,stat_enchant_name2,stat_enchant_name3,stat_enchant_name4,stat_enchant_name5,proc_tool_nameid,option_count) VALUES (v_dbid, v_char_id, p_enchant, p_item_id,p_mana_stone,p_mana_stone,p_mana_stone,p_mana_stone,0,0,p_god_stone,0);
    ELSIF p_mana_stone_count = 5 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id,stat_enchant_name0,stat_enchant_name1,stat_enchant_name2,stat_enchant_name3,stat_enchant_name4,stat_enchant_name5,proc_tool_nameid,option_count) VALUES (v_dbid, v_char_id, p_enchant, p_item_id,p_mana_stone,p_mana_stone,p_mana_stone,p_mana_stone,p_mana_stone,0,p_god_stone,0);
    ELSIF p_mana_stone_count = 6 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id,stat_enchant_name0,stat_enchant_name1,stat_enchant_name2,stat_enchant_name3,stat_enchant_name4,stat_enchant_name5,proc_tool_nameid,option_count) VALUES (v_dbid, v_char_id, p_enchant, p_item_id,p_mana_stone,p_mana_stone,p_mana_stone,p_mana_stone,p_mana_stone,p_mana_stone,p_god_stone,0);
    END IF;
    END IF;
    INSERT INTO user_mail (to_id,to_name,from_id,from_name,title,content,item_id,item_nameid,item_amount,express_mail) VALUES (v_char_id,p_to_name,0,p_from_name,p_title,'请查收系统发你的物品',v_dbid,p_item_id,p_item_amount,1);
    PERFORM '发送给 ' || p_to_name || ' 的物品成功';
    ELSE
    PERFORM '发送失败，角色名不存在：' || p_to_name;
    END IF;
    END IF;
END;
$$;

