-- [OK] [AUTO] aion_RegisterGameMoneyTradePhase1

CREATE OR REPLACE FUNCTION aion_registergamemoneytradephase1(
    p_seller integer,
    p_qina bigint,
    p_cash bigint,
    OUT p_id bigint,
    OUT p_return_code integer
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    Insert Into game_money_trade(seller, qina, cash) Values(p_seller, p_qina, p_cash);
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    p_return_code := -1;
    RETURN;
    ELSE
    p_id := LASTVAL();
    p_return_code := 0;
    RETURN;
    END IF;
END;
$$;

