--   Warning: Table variable converted to temp table

CREATE OR REPLACE FUNCTION aion_today_abyss_kill(
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    -- TODO: MANUAL REVIEW NEEDED - Table variable: DECLARE @temp TABLE ( user_id int, user_name NVARCHAR(25), user_race int, user_kill_cnt int, kill_cnt int, from_name NVARCHAR(25), mail_title NVARCHAR(25), mail_centent NVARCHAR(255), item_id int, item_count int )
    v_user_id integer;
    v_user_name varchar(20);
    v_user_race integer;
    v_user_kill_cnt integer;
    v_kill_cnt integer;
    v_from_name varchar(25);
    v_mail_title varchar(25);
    v_mail_centent varchar(255);
    v_item_id integer;
    v_item_count integer;
    v_string varchar(512);
BEGIN
    INSERT INTO v_temp(user_id, user_name, user_race, user_kill_cnt, kill_cnt, from_name, mail_title, mail_centent, item_id, item_count) select char_id, user_id, race, today_abyss_kill_cnt, 250, '人头奖励', '杀死 250 人奖励', '请查收以下物品', 188051885, 1 from user_data where today_abyss_kill_cnt >= 250 and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_login_time)::timestamp) / 86400)::integer=0 order by today_abyss_kill_cnt desc;
    INSERT INTO v_temp(user_id, user_name, user_race, user_kill_cnt, kill_cnt, from_name, mail_title, mail_centent, item_id, item_count) select char_id, user_id, race, today_abyss_kill_cnt, 200, '人头奖励', '杀死 200 人奖励', '请查收以下物品', 186000030, 1 from user_data where today_abyss_kill_cnt >= 200 and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_login_time)::timestamp) / 86400)::integer=0 order by today_abyss_kill_cnt desc;
    INSERT INTO v_temp(user_id, user_name, user_race, user_kill_cnt, kill_cnt, from_name, mail_title, mail_centent, item_id, item_count) select char_id, user_id, race, today_abyss_kill_cnt, 150, '人头奖励', '杀死 150 人奖励', '请查收以下物品', 188051720, 1 from user_data where today_abyss_kill_cnt >= 150 and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_login_time)::timestamp) / 86400)::integer=0 order by today_abyss_kill_cnt desc;
    INSERT INTO v_temp(user_id, user_name, user_race, user_kill_cnt, kill_cnt, from_name, mail_title, mail_centent, item_id, item_count) select char_id, user_id, race, today_abyss_kill_cnt, 100, '人头奖励', '杀死 100 人奖励', '请查收以下物品', 186000031, 1 from user_data where today_abyss_kill_cnt >= 100 and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_login_time)::timestamp) / 86400)::integer=0 order by today_abyss_kill_cnt desc;
    INSERT INTO v_temp(user_id, user_name, user_race, user_kill_cnt, kill_cnt, from_name, mail_title, mail_centent, item_id, item_count) select char_id, user_id, race, today_abyss_kill_cnt, 50, '人头奖励', '杀死 50 人奖励', '请查收以下物品', 186000051, 1 from user_data where today_abyss_kill_cnt >= 50 and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_login_time)::timestamp) / 86400)::integer=0 order by today_abyss_kill_cnt desc;
    RETURN QUERY SELECT * from v_temp order by user_kill_cnt desc;
    WHILE EXISTS(SELECT user_name FROM v_temp) LOOP
    -- SET ROWCOUNT 1 (handled via LIMIT in queries);
    SELECT user_id, user_name, user_race, user_kill_cnt, kill_cnt, from_name, mail_title, mail_centent, item_id, item_count INTO v_user_id, v_user_name, v_user_race, v_user_kill_cnt, v_kill_cnt, v_from_name, v_mail_title, v_mail_centent, v_item_id, v_item_count FROM v_temp;
    v_string := 'EXEC aion_SendMailItem ''' || v_user_name || ''', ''' || v_from_name || ''', ''' || v_mail_title || ''', ''' || v_mail_centent || ''', ' || CAST(v_item_id AS varchar) || ', ' || CAST(v_item_count AS varchar) || ', 0';
    IF EXISTS (select char_id from user_data where user_id = v_user_name) THEN
    EXECUTE v_string;
    ELSE
    RAISE NOTICE '%', v_string;
    END IF;
    -- SET ROWCOUNT 0 (handled via LIMIT in queries);
    DELETE FROM v_temp WHERE user_name=v_user_name and item_id=v_item_id  and kill_cnt=v_kill_cnt;
    END IF;
END;
$$;

