-- [WARN] [REVIEW] GM_ForbiddenWordDA_SrchForbiddenWord
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_forbiddenwordda_srchforbiddenword(
    p_world_id varchar(3),
    p_forbidden_word varchar(30),
    p_forbidden_type varchar(2),
    p_is_like varchar(2),
    p_forbidden_reason varchar(3),
    p_status varchar(1),
    p_view_count varchar(5),
    p_top_count varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(1000);
    v_tmp integer;
BEGIN
    v_sql := 'select top ' || p_view_count || ' forbidden_id, forbidden_type, forbidden_reason, is_like, world_id, forbidden_word, status, login_id, login_nm, regdate' || ' from forbidden_word ' || ' where FORBIDDEN_ID not in (select top ' || p_top_count || ' FORBIDDEN_ID from forbidden_word where world_id=''' || p_world_id || ''' ' set v_sql = v_sql || ' and status = ''' || p_status || ''' and is_like = ''' || p_is_like || ''' ' IF p_forbidden_type != '3' BEGIN set v_sql = v_sql || ' and forbidden_type = ''' || p_forbidden_type || '''' END IF p_forbidden_reason != '100' BEGIN set v_sql = v_sql || ' and forbidden_reason = ''' || p_forbidden_reason || '''' END IF p_forbidden_word != 'null' BEGIN set v_sql = v_sql || ' and forbidden_word like ''%' || p_forbidden_word || '%''' END set v_sql = v_sql || ' order by FORBIDDEN_ID desc) ';
    IF p_forbidden_type != '3' THEN
    v_sql := v_sql || ' and forbidden_type =' || p_forbidden_type || '';
    END IF;
    v_sql := v_sql || ' and status = ''' || p_status || ''' and is_like = ''' || p_is_like || ''' ';
    v_sql := v_sql || ' and world_id = ''' || p_world_id || '''';
    IF p_forbidden_reason != '100' THEN
    v_sql := v_sql || ' and forbidden_reason = ''' || p_forbidden_reason || '''';
    END IF;
    IF p_forbidden_word != 'null' THEN
    v_sql := v_sql || ' and forbidden_word like ''%' || p_forbidden_word || '%''';
    END IF;
    v_sql := v_sql || ' order by FORBIDDEN_ID desc';
    EXECUTE v_sql;
END;
$$;

