-- [OK] [AUTO] aion_SetInstanceExtraCountAbyssOP

CREATE OR REPLACE FUNCTION aion_setinstanceextracountabyssop(
    p_charId integer,
    p_mapNumber integer,
    p_extraCount smallint,
    p_nextResetTime bigint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_mapNumber = 0 THEN
    UPDATE user_instance_extracount SET next_reset_time = 0 WHERE char_id = p_charId::integer;
    ELSE
    IF EXISTS (SELECT map_number WHERE char_id = p_charId::integer AND map_number = p_mapNumber) THEN
    UPDATE user_instance_extracount SET extra_count_abyssop = p_extraCount, next_reset_time = p_nextResetTime WHERE char_id = p_charId::integer AND map_number = p_mapNumber;
    ELSE
    INSERT INTO user_instance_extracount VALUES(p_charId, p_mapNumber, p_extraCount, p_nextResetTime);
    END IF;
END;
$$;

