-- [OK] [AUTO] aion_RegisterGameMoneyTradePhase2

CREATE OR REPLACE FUNCTION aion_registergamemoneytradephase2(
    p_id bigint,
    p_seller integer,
    p_qina bigint,
    p_request_id varchar(64)
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    IF EXISTS (Select id From game_money_trade Where id=p_id and seller=p_seller and qina=p_qina and state IS NULL) THEN
    Update game_money_trade set state=1, register_date=CURRENT_TIMESTAMP, request_id=p_request_id Where id=p_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 1 THEN
    RETURN 0;
    ELSE
    RETURN -2;
    ELSE
    RETURN -1;
    END IF;
END;
$$;

