-- [WARN] [REVIEW] GM_ForbiddenWordDA_SrchReserveChar
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_forbiddenwordda_srchreservechar(
    p_world_id varchar(3),
    p_forbidden_char varchar(30),
    p_status varchar(1),
    p_view_count varchar(5),
    p_top_count varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(1000);
    v_tmp integer;
BEGIN
    v_sql := ' select top ' || p_view_count || ' forbidden_id, forbidden_type, forbidden_reason, world_id, forbidden_char, status, login_id, login_nm, regdate  ' || ' from forbidden_char  ' || ' where FORBIDDEN_ID not in (select top ' || p_top_count || ' FORBIDDEN_ID from forbidden_char where world_id=''' || p_world_id || ''' ' set v_sql = v_sql || ' and status = ''' || p_status || '''  ' IF p_forbidden_char != 'null' BEGIN set v_sql = v_sql || ' and forbidden_char like ''%' || p_forbidden_char || '%''' END set v_sql = v_sql || ' order by FORBIDDEN_ID desc) ';
    v_sql := v_sql || ' and status = ''' || p_status || '''  ';
    v_sql := v_sql || ' and world_id = ''' || p_world_id || '''';
    IF p_forbidden_char != 'null' THEN
    v_sql := v_sql || ' and forbidden_char like ''%' || p_forbidden_char || '%''';
    END IF;
    v_sql := v_sql || ' order by FORBIDDEN_ID desc ';
    EXECUTE v_sql;
    RETURN;
END;
$$;

