-- [WARN] [REVIEW] GM_GuildDA_SrchGuild
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_guildda_srchguild(
    p_world_id varchar(5),
    p_guild_nm varchar(32),
    p_guild_cond varchar(1),
    p_race varchar(5),
    p_view_count varchar(5),
    p_top_count varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(1200);
    v_sql_tmp varchar(100);
BEGIN
    v_sql_tmp := '';
    IF p_race != 'null' THEN
    v_sql_tmp := ' and t2.race = ''' || p_race || '''';
    END IF;
    IF p_guild_nm != 'null' and p_guild_cond = '2' THEN
    v_sql_tmp := v_sql_tmp || ' and t1.level = ''' || p_guild_nm || '''';
    END IF;
    v_sql := ' select top ' || p_view_count || ' t1.level, count(t1.id) cnt , (select user_id from user_data t3 where t1.master_id=t3.char_id) user_id, ' || ' (select account_id from user_data t3 where t1.master_id=t3.char_id) account_id, ' || ' (select account_name from user_data t3 where t1.master_id=t3.char_id) account_name, ' || ' t1.id, t1.name, t1.master_id, t1.rank, t1.point, t1.fund, t1.delete_requested, t1.delete_time, ' || ' t2.race, t2.org_server ' || ' , t1.point_max_time ' || ' from guild t1, user_data t2 ' || ' where t2.org_server=''' || p_world_id || ''' ' || v_sql_tmp || ' and t1.id=t2.guild_id and t1.id not in (select top ' || p_top_count || ' t1.id from guild t1, user_data t2 ' || ' where t2.org_server=''' || p_world_id || ''' ' || v_sql_tmp || ' and t1.id=t2.guild_id and t1.master_id=t2.char_id order by t1.id desc) ';
    IF p_guild_nm != 'null' and p_guild_cond = '0' THEN
    v_sql := v_sql || ' and t1.name = ''' || p_guild_nm || '''';
    END IF;
    IF p_guild_nm != 'null' and p_guild_cond = '1' THEN
    v_sql := v_sql || ' and t2.user_id = ''' || p_guild_nm || '''';
    END IF;
    v_sql := v_sql || ' group by t1.level, t1.id, t1.name, t1.master_id, t1.rank, t1.point, t1.fund, t1.delete_requested, t1.delete_time, t2.race, t2.org_server, t1.point_max_time ';
    v_sql := v_sql || ' order by t1.id desc ';
    EXECUTE v_sql;
END;
$$;

