-- [OK] [AUTO] aion_escrowadditem

CREATE OR REPLACE FUNCTION aion_escrowadditem(
    p_charid integer,
    p_itemid bigint,
    p_itemamount bigint
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    update user_item set warehouse = 154 where id = p_itemid;
    insert into user_escrow (seller, qina, itemid, itemamount, buyer, state, registerdate) values (p_charid, 0, p_itemid, p_itemamount, 0, 1, CURRENT_TIMESTAMP);
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN 0;
    END IF;
    RETURN LASTVAL();
END;
$$;

