-- [OK] [AUTO] aion_GetVendorItemListCharLight

CREATE OR REPLACE FUNCTION aion_getvendoritemlistcharlight(
    p_userId integer,
    p_warehouse smallint
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    -- SET ROWCOUNT 50 (handled via LIMIT in queries);
    RETURN QUERY SELECT vendor_item_light.id, user_item.id, user_item.name_id, vendor_item_light.user_price, vendor_item_light.sale_price, vendor_item_light.commit_amount, vendor_item_light.remain_amount, vendor_item_light.commit_date, COALESCE(user_item_option.soul_bound,0), COALESCE(user_item_option.enchant_count,0), COALESCE(user_item_option.skin_name_id,0), COALESCE(user_item_option.stat_enchant_name0,0), COALESCE(user_item_option.stat_enchant_name1,0), COALESCE(user_item_option.stat_enchant_name2,0), COALESCE(user_item_option.stat_enchant_name3,0), COALESCE(user_item_option.stat_enchant_name4,0), COALESCE(user_item_option.stat_enchant_name5,0), COALESCE(user_item_option.option_count,0), COALESCE(user_item_option.dye_info,0), COALESCE(user_item_option.proc_tool_nameid,0), user_item.producer, COALESCE(user_item_option.expire_dye_time, 0), COALESCE(user_item_option.limit_enchant_count, 0), COALESCE(user_item_option.random_option,0), COALESCE(user_item_option.reidentify_count, 0), COALESCE(user_item_option.authorize_count, 0), COALESCE(user_item_option.vanish_point,0), COALESCE(user_item_option.enchant_prob_addition, 0), COALESCE(user_item_option.option_prob_addition, 0), COALESCE(user_item_option.keyNameId, 0), COALESCE(user_item_option.exceedState, 0), COALESCE(user_item_option.exceedSkillId1, 0), COALESCE(user_item_option.exceedSkillId2, 0), COALESCE(user_item_option.exceedSkillId3, 0) FROM	vendor_item_light INNER JOIN	user_item ON vendor_item_light.user_item_id = user_item.id left join user_item_option on user_item.id = user_item_option.id WHERE (user_item.warehouse = p_warehouse::integer) AND (user_item.char_id = p_userId::integer);
    -- SET ROWCOUNT 0 (handled via LIMIT in queries);
END;
$$;

