-- [OK] [AUTO] aion_GetItem

CREATE OR REPLACE FUNCTION aion_getitem(
    p_userItemDbId bigint
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT   a.id, name_id, slot_id,  amount, tid, slot, COALESCE(soul_bound, 0), COALESCE(enchant_count,0), COALESCE(skin_name_id,0), COALESCE(b.stat_enchant_name0, 0), COALESCE(b.stat_enchant_name1, 0), COALESCE(b.stat_enchant_name2, 0), COALESCE(b.stat_enchant_name3, 0), COALESCE(b.stat_enchant_name4, 0), COALESCE(b.stat_enchant_name5, 0), COALESCE(option_count, 0), COALESCE(dye_info, 0), COALESCE(proc_tool_nameid, 0), producer, expired_time, buy_amount, buy_duration, COALESCE(obtain_skin_type, 0), COALESCE(expire_skin_time, 0), COALESCE(expire_dye_time, 0) AS expire_dye_time, COALESCE(random_option, 0) AS random_option, COALESCE(limit_enchant_count, 0) AS limit_enchant_count, COALESCE(reidentify_count, 0) as reidentify_count, COALESCE(authorize_count, 0) as authorize_count, COALESCE(vanish_point, 0) as vanish_point, COALESCE(b.enchant_prob_addition, 0), COALESCE(b.option_prob_addition, 0) FROM      user_item a left join  user_item_option b on a.id = b.id WHERE   (a.id = p_userItemDbId);
END;
$$;

