-- [OK] [AUTO] aion_escrowaddqina

CREATE OR REPLACE FUNCTION aion_escrowaddqina(
    p_charid integer,
    p_qina bigint,
    p_decrease integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_itemid integer;
    v_amount bigint;
BEGIN
    IF p_decrease = 1 THEN
    SELECT id, amount INTO v_itemid, v_amount FROM user_item where char_id = p_charid::integer and name_id=182400001 and warehouse=0;
    IF (v_amount < p_qina) THEN
    RETURN -2;
    END IF;
    IF v_itemid is null or v_itemid <= 0 THEN
    RETURN -1;
    END IF;
    update user_item set amount = amount - p_qina where id = v_itemid;
    END IF;
    insert into user_escrow (seller, qina, itemid, itemamount, buyer, state, registerdate) values (p_charid, p_qina, 0, 0, 0, 1, CURRENT_TIMESTAMP);
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN 0;
    END IF;
    RETURN LASTVAL();
END;
$$;

