-- [OK] [AUTO] aion_SetItemAttributeDelta

CREATE OR REPLACE FUNCTION aion_setitemattributedelta(
    p_id bigint,
    p_attr1 integer,
    p_attr1value integer,
    p_attr2 integer,
    p_attr2value integer,
    p_attr3 integer,
    p_attr3value integer,
    p_attr4 integer,
    p_attr4value integer,
    p_attr5 integer,
    p_attr5value integer,
    p_attr6 integer,
    p_attr6value integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    Update user_item_attribute set Attribute1 = p_attr1, Attribute1Value =p_attr1value, Attribute2 = p_attr2, Attribute2Value =p_attr2value, Attribute3 = p_attr3, Attribute3Value =p_attr3value, Attribute4 = p_attr4, Attribute4Value =p_attr4value, Attribute5 = p_attr5, Attribute5Value =p_attr5value, Attribute6 = p_attr6, Attribute6Value =p_attr6value where ID = p_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    insert into user_item_attribute (id, Attribute1, Attribute1Value, Attribute2, Attribute2Value, Attribute3, Attribute3Value, Attribute4, Attribute4Value, Attribute5, Attribute5Value, Attribute6, Attribute6Value) values  (p_id, p_attr1, p_attr1value, p_attr2, p_attr2value, p_attr3, p_attr3value, p_attr4, p_attr4value, p_attr5, p_attr5value, p_attr6, p_attr6value);
    END IF;
END;
$$;

