-- [OK] [AUTO] aion_addAuction

CREATE OR REPLACE FUNCTION aion_addauction(
    p_type integer,
    p_race integer,
    p_nameID integer,
    p_sellerID integer,
    p_sellerName varchar(64),
    p_qina bigint,
    p_stepqina bigint,
    p_createTime integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT id FROM user_auction WHERE goodsID = p_nameID and state in (0,1)) OR EXISTS(select filterid from user_auctionfilter where goodsID = p_nameID) THEN
    RETURN 0;
    ELSE
    insert into user_auction(type, race, goodsID, sellerID, sellerName, InitQina, qina, stepqina, state, buyerID, buyerName, lastupdate, createtime) values (p_type, p_race, p_nameID, p_sellerID, p_sellerName, p_qina, p_qina, p_stepqina, 0, 0, '', 0, p_createTime);
    RETURN LASTVAL();
    END IF;
END;
$$;

