-- [OK] [AUTO] aion_escrowset

CREATE OR REPLACE FUNCTION aion_escrowset(
    p_escId integer,
    p_state integer,
    p_buyer integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_orgState integer;
    v_qina bigint;
    v_item bigint;
    v_warehouse integer;
BEGIN
    SELECT qina, itemid, state INTO v_qina, v_item, v_orgState FROM user_escrow where ID = p_escId;
    IF v_orgState is null THEN
    RETURN -1;
    END IF;
    IF v_orgState <> 1 THEN
    RETURN -2;
    END IF;
    IF v_qina = 0 and v_item <> 0 THEN
    SELECT warehouse INTO v_warehouse FROM user_item  where id = v_item;
    IF v_warehouse is null THEN
    RETURN -3;
    END IF;
    IF v_warehouse <> 154 THEN
    RETURN -4;
    END IF;
    update user_item set warehouse = 0, char_id = 0 where id = v_item;
    END IF;
    update user_escrow set state = p_state, buyer = p_buyer, completedate = CURRENT_TIMESTAMP where ID = p_escId;
    RETURN 0;
END;
$$;

