-- [OK] [AUTO] aion_SetItemDropCtrlInfo

CREATE OR REPLACE FUNCTION aion_setitemdropctrlinfo(
    p_item_id integer,
    p_item_cur_count integer,
    p_next_reset_time bigint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    -- Transaction managed by PG function context
    IF EXISTS (SELECT item_name_id FROM item_drop_ctrl WHERE item_name_id=p_item_id) THEN
    UPDATE item_drop_ctrl SET cur_count = p_item_cur_count, next_reset_time = p_next_reset_time WHERE item_name_id = p_item_id;
    ELSE
    INSERT INTO item_drop_ctrl(item_name_id, cur_count, next_reset_time) VALUES (p_item_id, p_item_cur_count, p_next_reset_time);
    END IF;
    -- COMMIT (implicit in PG function)
END;
$$;

