-- [OK] [AUTO] aion_RemoveBuddy

CREATE OR REPLACE FUNCTION aion_removebuddy(
    p_nCharId integer,
    p_nBuddyId integer,
    p_flag smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    -- Transaction managed by PG function context
    DELETE FROM user_buddy1 WHERE char_id = p_nCharId::integer and buddy_id = p_nBuddyId;
    IF (p_flag = 0) THEN
    DELETE FROM user_buddy1 WHERE char_id = p_nBuddyId::integer and buddy_id = p_nCharId;
    ELSIF (p_flag = 1) THEN
    UPDATE user_buddy1 SET delete_flag = 1 WHERE char_id = p_nBuddyId::integer and buddy_id = p_nCharId;
    END IF;
    -- COMMIT (implicit in PG function)
END;
$$;

