-- [OK] [AUTO] aion_FinishGameMoneyTrade

CREATE OR REPLACE FUNCTION aion_finishgamemoneytrade(
    p_request_id varchar(64),
    p_eventType smallint,
    p_seller integer,
    p_buyer integer,
    OUT p_state smallint,
    OUT p_return_code integer
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_id bigint;
    v_oldBuyer integer;
    v_reward_seller smallint;
BEGIN
    p_state := 0;
    SELECT id, state, COALESCE(buyer, 0), COALESCE(reward_seller, 0) INTO v_id, p_state, v_oldBuyer, v_reward_seller FROM game_money_trade Where request_id=p_request_id and state=1;
    IF v_id<>0 THEN
    IF p_eventType = 1 THEN
    IF p_seller <> 0 and p_buyer = 0 and v_oldBuyer = 0 THEN
    UPDATE game_money_trade SET reward_seller=1 Where id=v_id;
    ELSIF p_seller <> 0 and p_buyer = 0 and v_oldBuyer <> 0 THEN
    Update game_money_trade set state=2, complete_date=CURRENT_TIMESTAMP, reward_seller=1 Where id=v_id;
    ELSIF p_seller = 0 and  p_buyer <> 0 and v_reward_seller = 0 THEN
    Update game_money_trade set buyer=p_buyer Where id=v_id;
    ELSIF p_seller = 0 and p_buyer <> 0 and v_reward_seller = 1 THEN
    Update game_money_trade set state=2, complete_date=CURRENT_TIMESTAMP, buyer=p_buyer Where id=v_id;
    ELSIF p_eventType = 2 THEN
    IF p_seller <> 0 THEN
    Update game_money_trade set state=-1, complete_date=CURRENT_TIMESTAMP Where id=v_id;
    ELSIF p_eventType = 3 THEN
    IF p_seller <> 0 and p_state = 1 and v_reward_seller = 0 THEN
    Update game_money_trade set state=-2, complete_date=CURRENT_TIMESTAMP Where id=v_id;
    ELSIF p_eventType = 4 THEN
    IF p_buyer <> 0 and p_state = 1 and v_oldBuyer <> 0 and v_reward_seller=0 THEN
    Update game_money_trade set state=-3, complete_date=CURRENT_TIMESTAMP Where id=v_id;
    END IF;
    END IF;
    IF v_rowcount = 1 THEN
    SELECT state INTO p_state WHERE id=v_id;
    p_return_code := 0;
    RETURN;
    ELSE
    p_return_code := -2;
    RETURN;
    ELSE
    p_return_code := -1;
    RETURN;
    END IF;
END;
$$;

