-- [OK] [AUTO] aion_SetItemDye_20111227

CREATE OR REPLACE FUNCTION aion_setitemdye_20111227(
    p_itemId bigint,
    p_dyeInfo integer,
    p_expireDyeTime integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_nCharId integer;
BEGIN
    IF EXISTS (select id  from user_item_option  where id = p_itemId) THEN
    update user_item_option set dye_info = p_dyeInfo, expire_dye_time = p_expireDyeTime where ID = p_itemId;
    ELSE
    SELECT char_id INTO v_nCharId FROM user_item where id = p_itemId;
    insert into user_item_option (id, char_id,dye_info, expire_dye_time) values (p_itemId, v_nCharId, p_dyeInfo, p_expireDyeTime);
    IF 0 /* @v_ERROR */ <> 0 THEN
    update user_item_option set dye_info = p_dyeInfo, expire_dye_time = p_expireDyeTime where ID = p_itemId;
    END IF;
    END IF;
END;
$$;

