-- [OK] [AUTO] aion_forbiddenlist

CREATE OR REPLACE FUNCTION aion_forbiddenlist(
    p_type integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_applyDate timestamp := CAST('2016-07-06 09:00:00' AS timestamp);
BEGIN
    IF p_type=1 THEN
    RETURN QUERY SELECT forbidden_word, forbidden_type*10+forbidden_reason as relate from forbidden_word where STATUS=0 and IS_LIKE=0;
    END IF;
    IF p_type=2 THEN
    RETURN QUERY SELECT forbidden_word, forbidden_type*10+forbidden_reason as relate from forbidden_word where STATUS=0 and IS_LIKE=1;
    END IF;
    IF p_type=3 THEN
    RETURN QUERY SELECT forbidden_char, forbidden_type*10+forbidden_reason as relate from forbidden_char where status=0 and (forbidden_reason in (3,4)) and ((REGDATE < v_applyDate and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (regdate)::timestamp) / 86400)::integer < 366) or ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (regdate)::timestamp) / 86400)::integer < 61));
    END IF;
END;
$$;

