-- [OK] [AUTO] aion_SetItemEnchant_20150429

CREATE OR REPLACE FUNCTION aion_setitemenchant_20150429(
    p_id bigint,
    p_soulBound smallint,
    p_enchantCount smallint,
    p_skinNameId integer,
    p_statEnchantName0 integer,
    p_statEnchantName1 integer,
    p_statEnchantName2 integer,
    p_statEnchantName3 integer,
    p_statEnchantName4 integer,
    p_statEnchantName5 integer,
    p_procToolNameId integer,
    p_obtainSkinType smallint,
    p_expireSkinTime integer,
    p_limit_enchant_count smallint,
    p_authorize_count smallint,
    p_vanish_point integer,
    p_enchantProbAddition integer,
    p_optionProbAddition integer,
    p_keyNameId integer,
    p_exceedState smallint,
    p_exceedSkillId1 integer,
    p_exceedSkillId2 integer,
    p_exceedSkillId3 integer,
    p_baseSkillId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_nCharId integer;
    v_mainItemId bigint;
BEGIN
    IF (p_enchantCount = 0) THEN
    SELECT COALESCE(main_item_dbid, 0) INTO v_mainItemId FROM user_item where id = p_id;
    IF (v_mainItemId > 0) THEN
    SELECT COALESCE(enchant_count, 0) INTO p_enchantCount FROM user_item_option  where id=p_id;
    END IF;
    END IF;
    UPDATE user_item_option SET soul_bound = p_soulBound, enchant_count = p_enchantCount, skin_name_id = p_skinNameId, stat_enchant_name0 = p_statEnchantName0, stat_enchant_Name1 = p_statEnchantName1, stat_enchant_Name2 = p_statEnchantName2, stat_enchant_Name3 = p_statEnchantName3, stat_enchant_Name4 = p_statEnchantName4, stat_enchant_Name5 = p_statEnchantName5, proc_tool_nameid = p_procToolNameId, obtain_skin_type = p_obtainSkinType, expire_skin_time = p_expireSkinTime, limit_enchant_count = p_limit_enchant_count, authorize_count = p_authorize_count, vanish_point=p_vanish_point, enchant_prob_addition = p_enchantProbAddition, option_prob_addition = p_optionProbAddition, KeyNameId = p_keyNameId, exceedState = p_exceedState, exceedSkillId1 = p_exceedSkillId1, exceedSkillId2 = p_exceedSkillId2, exceedSkillId3 = p_exceedSkillId3, baseSkillId = p_baseSkillId WHERE id=p_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    SELECT char_id INTO v_nCharId FROM user_item where id = p_id;
    INSERT INTO user_item_option (id, char_id, soul_bound, enchant_count, skin_name_id, stat_enchant_name0, stat_enchant_Name1, stat_enchant_Name2, stat_enchant_Name3, stat_enchant_Name4, stat_enchant_Name5, proc_tool_nameid, obtain_skin_type, expire_skin_time, limit_enchant_count, authorize_count, vanish_point, enchant_prob_addition, option_prob_addition, KeyNameId, exceedState, ExceedSkillId1, ExceedSkillId2, ExceedSkillId3, baseSkillId ) values (p_id, v_nCharId,p_soulBound,p_enchantCount,p_skinNameId, p_statEnchantName0, p_statEnchantName1, p_statEnchantName2, p_statEnchantName3, p_statEnchantName4, p_statEnchantName5, p_procToolNameId, p_obtainSkinType, p_expireSkinTime, p_limit_enchant_count, p_authorize_count, p_vanish_point, p_enchantProbAddition, p_optionProbAddition, p_keyNameId, p_exceedState, p_exceedSkillId1, p_exceedSkillId2, p_exceedSkillId3, p_baseSkillId );
    IF 0 /* @v_ERROR */ <> 0 THEN
    UPDATE user_item_option SET soul_bound = p_soulBound, enchant_count = p_enchantCount, skin_name_id = p_skinNameId, stat_enchant_name0 = p_statEnchantName0, stat_enchant_Name1 = p_statEnchantName1, stat_enchant_Name2 = p_statEnchantName2, stat_enchant_Name3 = p_statEnchantName3, stat_enchant_Name4 = p_statEnchantName4, stat_enchant_Name5 = p_statEnchantName5, proc_tool_nameid = p_procToolNameId, obtain_skin_type = p_obtainSkinType, expire_skin_time = p_expireSkinTime, limit_enchant_count = p_limit_enchant_count, authorize_count = p_authorize_count, vanish_point=p_vanish_point, enchant_prob_addition = p_enchantProbAddition, option_prob_addition = p_optionProbAddition, KeyNameId = p_keyNameId, exceedState = p_exceedState, exceedSkillId1 = p_exceedSkillId1, exceedSkillId2 = p_exceedSkillId2, exceedSkillId3 = p_exceedSkillId3, baseSkillId = p_baseSkillId WHERE id=p_id;
    END IF;
    END IF;
END;
$$;

