-- [WARN] [REVIEW] aion_RemoveItemBind
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION

CREATE OR REPLACE FUNCTION aion_removeitembind(
    p_nId bigint,
    p_nRemoveWarehouse integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    -- Transaction managed by PG function context
    DELETE FROM user_item_bind WHERE item_id = p_nId::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount <> 0 THEN
    UPDATE user_item SET warehouse = p_nRemoveWarehouse::integer, update_date = CURRENT_TIMESTAMP WHERE id = p_nId;
    -- COMMIT (implicit in PG function)
    RETURN 0;
    ELSE
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    END IF;
END;
$$;

