-- [OK] [AUTO] aion_GetAbnormalStatusList

CREATE OR REPLACE FUNCTION aion_getabnormalstatuslist(
    p_nCharId integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_useTime integer;
    v_cd integer;
    v_sk integer := 12885;
    v_reTime integer;
BEGIN
    WHILE v_sk < 12895 LOOP
    IF (EXISTS(SELECT * FROM user_abnormal_status WHERE skill_id = v_sk AND char_id = p_nCharId::integer)) THEN
    SELECT effect_remain2, logout_time INTO v_cd, v_useTime FROM user_abnormal_status WHERE skill_id = v_sk AND char_id = p_nCharId::integer;
    v_reTime := (GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) - v_useTime) * 1000;
    IF (v_cd > v_reTime) THEN
    UPDATE user_abnormal_status SET effect_remain2 = v_cd - v_reTime, effect_remain3 = v_cd - v_reTime, effect_remain4 = v_cd - v_reTime WHERE skill_id = v_sk AND char_id = p_nCharId::integer;
    ELSE
    DELETE WHERE skill_id = v_sk AND char_id = p_nCharId::integer;
    END IF;
    END IF;
    v_sk := v_sk + 1;
    END IF;
