-- [WARN] [REVIEW] aion_RemoveItemBind_All
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION

CREATE OR REPLACE FUNCTION aion_removeitembind_all(
    p_nRollbackWarehouse integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    -- Transaction managed by PG function context
    UPDATE user_item SET warehouse = p_nRollbackWarehouse::integer, update_date = CURRENT_TIMESTAMP WHERE id IN (SELECT DISTINCT item_id FROM user_item_bind);
    DELETE FROM user_item_bind;
    IF 0 /* @v_ERROR */ = 0 THEN
    -- COMMIT (implicit in PG function)
    RETURN 0;
    ELSE
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    END IF;
END;
$$;

