-- [OK] [AUTO] GM_GuildDA_SrchGuildMembers

CREATE OR REPLACE FUNCTION gm_guildda_srchguildmembers(
    p_guild_id varchar(10),
    p_view_count integer,
    p_top_count integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    PERFORM  t1.org_server, t1.char_id, t1.user_id, t1.account_id, t1.account_name, t1.race, t1.class, t1.gender, t1.guild_rank, t1.guild_intro, t1.guild_nickname, t1.lev, TO_CHAR(t1.last_logout_time, 'YYYY-MM-DD HH24:MI:SS') last_logout_time, case WHEN last_login_time = last_logout_time and last_login_time != '1970-01-01 00:00:00.000' and last_logout_time > '2007-12-12 00:00:00.000' THEN '339900' WHEN last_login_time != last_logout_time or last_login_time = '1970-01-01 00:00:00.000'  THEN 'brown' WHEN last_login_time = last_logout_time and last_login_time != '1970-01-01 00:00:00.000' THEN AS black LIMIT p_view_count;
    end as logonoff from	user_data t1 where	t1.guild_id = p_guild_id::integer and t1.char_id not in (SELECT  char_id from user_data where guild_id = p_guild_id::integer order by char_id asc LIMIT p_top_count) order by t1.char_id asc;
END;
$$;

