-- [OK] [AUTO] aion_AddCharRankPoint

CREATE OR REPLACE FUNCTION aion_addcharrankpoint(
    p_char_id integer,
    p_rank_id integer,
    p_point_to_add integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT id FROM user_rank WHERE char_id = p_char_id::integer AND rank_id = p_rank_id) THEN
    UPDATE user_rank SET point = point + p_point_to_add WHERE char_id = p_char_id::integer AND rank_id = p_rank_id;
    ELSE
    INSERT INTO user_rank(char_id, rank_id, point) VALUES (p_char_id, p_rank_id, p_point_to_add);
    END IF;
END;
$$;

