-- [OK] [AUTO] GM_house_give

CREATE OR REPLACE FUNCTION gm_house_give(
    p_addrId integer,
    p_ownerId integer,
    OUT p_ownerName varchar(32),
    OUT p_return_code integer
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_ret integer;
    v_lastcharge integer;
BEGIN
    IF EXISTS (select addr_id from house_field where addr_id = p_addrId and state = 2) THEN
    IF EXISTS (select addr_id from house_field where owner_id = p_ownerId::integer) THEN
    v_ret := 2;
    ELSE
    IF EXISTS (select ID from user_auction where buyerID = p_ownerId and state =1) THEN
    v_ret := 3;
    ELSE
    IF EXISTS (select ID from house_instant where id = p_ownerId and state = 5) THEN
    v_ret := 0;
    PERFORM aion_deleteAuctionBetting(p_ownerId);
    SELECT user_id INTO p_ownerName FROM user_data WHERE char_id = p_ownerId::integer;
    update house_field set owner_id = p_ownerId::integer, state = 5, owner_name = p_ownerName where addr_id = p_addrId;
    SELECT max(lastcharge) INTO v_lastcharge FROM house_field;
    PERFORM aion_SetHouseFieldCharge(p_addrId, 1, 0, v_lastcharge);
    ELSE
    v_ret := 4;
    END IF;
    ELSE
    v_ret := 1;
    END IF;
    p_return_code := 0;
        -- RETURN_EXPR: v_ret;
END;
$$;

