-- [OK] [AUTO] aion_GetAbyssRankingNew

CREATE OR REPLACE FUNCTION aion_getabyssrankingnew(
    p_nServerId integer,
    p_nRace integer,
    p_nNum integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_update_time bigint;
BEGIN
    v_update_time := (SELECT max(update_time) FROM abyss_ranking WHERE race = p_nRace::integer and server_id = p_nServerId::integer);
    PERFORM  abyss_ranking, abyss_ranking.char_id, user_data.user_id, abyss_ranking.class, user_data.gender, abyss_ranking.lev, abyss_ranking.abyss_point, abyss_ranking.gp, update_time, COALESCE(guild.name, ''), old_ranking FROM abyss_ranking JOIN user_data on abyss_ranking.char_id = user_data.char_id LEFT JOIN guild on abyss_ranking.guild_id = guild.id WHERE update_time = v_update_time AND abyss_ranking.race = p_nRace::integer AND abyss_ranking.server_id = p_nServerId::integer ORDER BY abyss_ranking LIMIT p_nNum;
END;
$$;

