CREATE OR REPLACE FUNCTION gm_house_give_check(
    p_ownerId integer,
    OUT p_ownerName varchar(26),
    OUT p_level integer,
    OUT p_quest integer
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
