-- [OK] [AUTO] aion_SetItemExpiredTime

CREATE OR REPLACE FUNCTION aion_setitemexpiredtime(
    p_nDBId bigint,
    p_nExpiredTime integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_nTTL integer;
    v_result integer;
BEGIN
    SELECT Expired_Time INTO v_nTTL FROM user_item WHERE id = p_nDBId;
    IF v_nTTL >= 0 THEN
        RETURN v_nTTL;
    END IF;
    v_result := p_nExpiredTime - v_nTTL;
    UPDATE user_item SET Expired_Time = v_result WHERE id = p_nDBId;
    RETURN v_result;
END;
$$;

