-- [WARN] [REVIEW] aion_AddedService_Type4_MoveChar_CheckConn_ORS
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION aion_addedservice_type4_movechar_checkconn_ors(
    p_fromServerId integer,
    p_db_userId varchar(64),
    p_db_passwd varchar(64),
    OUT p_ret integer,
    OUT p_err_str varchar(256)
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_connectString varchar(256);
    v_serverName varchar(128);
    v_databaseName varchar(64);
    v_db_info varchar(256);
    v_retVal integer;
    v_sql varchar(4000);
BEGIN
    p_ret := 0;
    p_err_str := '';
    RAISE NOTICE '%', 'Check ServerConnection To ServerId(' || CAST(p_fromServerId AS varchar) || ')';
    v_connectString := '';
    v_serverName := '';
    v_databaseName := '';
    SELECT datasource, database_name INTO v_serverName, v_databaseName FROM AionAddedService_Servername where server_id = p_fromServerId::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    p_ret := -1;
    p_err_str := 'Cannot find serverName of server Id(' || CAST(p_fromServerId AS varchar) || ')';
    RAISE NOTICE '%', p_err_str;
    RETURN;
    END IF;
    v_db_info := '''' || v_serverName || ''';''' || p_db_userId || ''';''' || p_db_passwd || '''';
    v_sql := 'select v_retVal = result from openrowset (''SQLOLEDB'', ' || v_db_info || ', ''' || v_databaseName || '.aion_AddedService_Type4_MoveChar_CheckConn_local_ORS'' )';
    EXECUTE v_sql, 'v_retVal int output', v_retVal output;
    IF 0 /* @v_ERROR */ <> 0 THEN
    p_ret := -2;
    p_err_str := 'Connection Error!!! to serverName of server Id(' || CAST(p_fromServerId AS varchar) || ')';
    END IF;
END;
$$;

