-- [OK] [AUTO] aion_ReplaceAbnormalStatus

CREATE OR REPLACE FUNCTION aion_replaceabnormalstatus(
    p_nCharId integer,
    p_nSkillId integer,
    p_nSkillLevel smallint,
    p_nTargetSlot smallint,
    p_nRemain1 integer,
    p_nRemain2 integer,
    p_nRemain3 integer,
    p_nRemain4 integer,
    p_nIntervalValue1 integer,
    p_nIntervalValue2 integer,
    p_nIntervalValue3 integer,
    p_nIntervalValue4 integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT char_id FROM user_abnormal_status WHERE  char_id = p_nCharId::integer and skill_id=p_nSkillId) THEN
    UPDATE user_abnormal_status SET skill_level=p_nSkillLevel, target_slot=p_nTargetSlot, effect_remain1=p_nRemain1, effect_remain2=p_nRemain2, effect_remain3=p_nRemain3, effect_remain4=p_nRemain4, interval_value1=p_nIntervalValue1, interval_value2=p_nIntervalValue2, interval_value3=p_nIntervalValue3, interval_value4=p_nIntervalValue4 WHERE  char_id = p_nCharId::integer and skill_id=p_nSkillId;
    ELSE
    INSERT INTO user_abnormal_status(char_id, skill_id, skill_level, target_slot, effect_remain1, effect_remain2, effect_remain3, effect_remain4, interval_value1, interval_value2, interval_value3, interval_value4) VALUES (p_nCharId, p_nSkillId, p_nSkillLevel, p_nTargetSlot, p_nRemain1, p_nRemain2, p_nRemain3, p_nRemain4, p_nIntervalValue1,  p_nIntervalValue2,  p_nIntervalValue3,  p_nIntervalValue4);
    END IF;
END;
$$;

