AS $$
DECLARE
    v_char_count integer;
    v_count integer;
BEGIN
    p_ret := 0;
    v_count := 0;
    SELECT count(*) INTO v_count FROM user_data  where account_id = p_fromUid::integer and delete_complete_date = 0 and race <> p_fromRace::integer;
    IF v_count <> 0 THEN
    p_ret := -10002;
    END IF;
    v_char_count := 0;
    v_char_count := (select count(*) from user_data where account_id = p_fromUid::integer and delete_complete_date = 0);
    IF v_char_count >= 10 THEN
    p_ret := -10018;
    END IF;
END;
$$;

