-- [OK] [AUTO] aion_SetItemExportFlag

CREATE OR REPLACE FUNCTION aion_setitemexportflag(
    p_id bigint,
    p_exportto integer,
    p_date integer,
    OUT p_exportid bigint
) RETURNS bigint
LANGUAGE plpgsql
AS $$
BEGIN
    IF NOT EXISTS (SELECT id FROM user_item WHERE id = p_id AND export_id <> 0) THEN
    INSERT INTO export_item_log(item_id, export_to_sv, export_to_id, export_date) VALUES (p_id, p_exportto, 0, p_date);
    p_exportid := LASTVAL();
    UPDATE user_item SET export_id = p_exportid WHERE id = p_id;
    ELSE
    p_exportid := 0;
    END IF;
END;
$$;

