-- [WARN] [REVIEW] aion_AddedService_Type4_MoveChar_CheckOrgChar_ORS
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION aion_addedservice_type4_movechar_checkorgchar_ors(
    p_fromServerId integer,
    p_toServerId integer,
    p_db_userId varchar(64),
    p_db_passwd varchar(64),
    p_orgCharId integer,
    p_orgCharName varchar(20),
    p_premium integer,
    p_withAccountWarehouse integer,
    p_byOnline integer,
    OUT p_ret integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_connectString varchar(256);
    v_serverName varchar(128);
    v_databaseName varchar(64);
    v_db_info varchar(256);
    v_retVal integer;
    v_sql varchar(4000);
BEGIN
    v_connectString := '';
    v_serverName := '';
    v_databaseName := '';
    SELECT datasource, database_name INTO v_serverName, v_databaseName FROM AionAddedService_Servername where server_id = p_fromServerId::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    p_ret := -10101;
    RETURN;
    END IF;
    v_db_info := '''' || v_serverName || ''';''' || p_db_userId || ''';''' || p_db_passwd || '''';
    v_sql := 'select v_retVal = result from openrowset (''SQLOLEDB'', ' || v_db_info || ', ''' || v_databaseName || '.aion_AddedService_Type4_MoveChar_CheckOrgChar_local_ORS ' || CAST(p_fromServerId AS varchar) || ', ' || CAST(p_toServerId AS varchar) || ', ' || CAST(p_orgCharId AS varchar) || ', ''''' || p_orgCharName || ''''' ' || ', ' || CAST(p_premium AS varchar) || ', ' || CAST(p_withAccountWarehouse AS varchar) || ', ' || CAST(p_byOnline AS varchar) || ''' )';
    EXECUTE v_sql, 'v_retVal int output', v_retVal output;
