BEGIN
    v_ret := 0;
    IF p_orgCharId <> 0 THEN
    insert into forbidden_char ( FORBIDDEN_TYPE, FORBIDDEN_REASON, WORLD_ID, FORBIDDEN_CHAR, FORBIDDEN_ACCOUNT_NM, STATUS, LOGIN_ID, LOGIN_NM, REGDATE) values(1, 3, p_fromServerId, p_orgCharName, '', 0, 'AddedService', 'Type4_MoveServer', CURRENT_TIMESTAMP);
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF 0 /* @v_ERROR */ <> 0	or v_rowcount = 0 THEN
    v_ret := -11029;
    -- TODO: MANUAL REVIEW NEEDED - GOTO send_result
    RETURN;  -- Originally: GOTO send_result
    END IF;
    v_delete_date := GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0);
    update user_data set delete_date = v_delete_date, delete_complete_date = v_delete_date, delete_type	= p_toServerId where char_id = p_orgCharId::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF 0 /* @v_ERROR */ <> 0	or v_rowcount = 0 THEN
    v_ret := -11030;
    -- TODO: MANUAL REVIEW NEEDED - GOTO send_result
    RETURN;  -- Originally: GOTO send_result
    END IF;
    update user_item set warehouse = 0 where char_id = p_orgCharId::integer and warehouse = 4;
    DELETE FROM vendor_item_light where char_id = p_orgCharId::integer;
    DELETE FROM vendor_item_dark where char_id = p_orgCharId::integer;
    END IF;
    -- Label: send_result
