--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_useritemda_srchmywarehouseitems(
    p_char_id varchar(20),
    p_warehouse varchar(5),
    p_uid varchar(1000),
    p_view_count varchar(5),
    p_top_count varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
    v_sql_where varchar(1500);
BEGIN
    v_sql_where := ' ';
    IF p_warehouse = '17' THEN
    v_sql_where := v_sql_where || 'where (warehouse=''' || p_warehouse || ''') and i.char_id=''' || p_char_id || ''' and main_item_dbid != 0 ';
    ELSIF p_warehouse = '7' THEN
    v_sql_where := v_sql_where || 'where (warehouse=''' || p_warehouse || ''' or warehouse=57) and i.char_id=''' || p_char_id || ''' ';
    ELSIF p_warehouse = '6' THEN
    v_sql_where := v_sql_where || 'where (warehouse=''' || p_warehouse || ''' or warehouse=56) and i.char_id=''' || p_char_id || ''' ';
    ELSE
    v_sql_where := v_sql_where || 'where (warehouse=''' || p_warehouse || ''') and i.char_id=''' || p_char_id || ''' ';
    END IF;
    IF p_uid != 'null' THEN
    v_sql_where := v_sql_where || ' and (' || p_uid || ') ';
    END IF;
    v_sql := 'SELECT	TOP ' || p_view_count || '		i.id, i.char_id, i.name_id, slot_id, amount, slot, warehouse, TO_CHAR(create_date, ''YYYY-MM-DD HH24:MI:SS'') AS create_date, TO_CHAR(update_date, ''YYYY-MM-DD HH24:MI:SS'') AS update_date, producer, tid, expired_time, buy_amount, buy_duration, main_item_dbid, dynamic_property, import_id, export_id, server_of_origin, ' || '		soul_bound, enchant_count, skin_name_id, stat_enchant_name0, stat_enchant_name1, stat_enchant_name2, stat_enchant_name3, stat_enchant_name4, stat_enchant_name5, option_count, dye_info, proc_tool_nameid, obtain_skin_type, expire_skin_time, expire_dye_time, COALESCE(random_option,0) AS random_option, COALESCE(limit_enchant_count,0) AS limit_enchant_count, COALESCE(reidentify_count,0) AS reidentify_count ' || '		, COALESCE(freetradestate, 0) as freetradestate ' || '		, COALESCE(authorize_count, 0) as authorize_count, COALESCE(vanish_point, 0) as vanish_point ' || '		, COALESCE(attribute1, 0) as attribute1, COALESCE(attribute1value, 0) as attribute1value, COALESCE(attribute2, 0) as attribute2, COALESCE(attribute2value, 0) as attribute2value, COALESCE(attribute3, 0) as attribute3, COALESCE(attribute3value, 0) as attribute3value, COALESCE(attribute4, 0) as attribute4, COALESCE(attribute4value, 0) as attribute4value, COALESCE(attribute5, 0) as attribute5, COALESCE(attribute5value, 0) as attribute5value, COALESCE(attribute6, 0) as attribute6, COALESCE(attribute6value, 0) as attribute6value ' || '		, COALESCE(proc_break_count, 0) as proc_break_count, COALESCE(proc_break_flag, 0) as proc_break_flag ' || '		, COALESCE(exceedState, 0) as exceedState, COALESCE(exceedSkillId1, 0) as exceedSkillId1, COALESCE(exceedSkillId2, 0) as exceedSkillId2, COALESCE(exceedSkillId3, 0) as exceedSkillId3 ' || '		, COALESCE(baseSkillId, 0) as baseSkillId' || '		, COALESCE(enhanceSkillGroup, 0) as enhanceSkillGroup, COALESCE(enhanceSkillLevel, 0) as enhanceSkillLevel ' || '		, COALESCE(equipLevelDown, 0) as equipLevelDown' || '		, COALESCE(wardrobeSlotId, 0) as wardrobeSlotId' || '		, COALESCE(randomAttr1, 0) as randomAttr1, COALESCE(randomValue1, 0) as randomValue1 ' || '		, COALESCE(randomAttr2, 0) as randomAttr2, COALESCE(randomValue2, 0) as randomValue2 ' || '		, COALESCE(randomAttr3, 0) as randomAttr3, COALESCE(randomValue3, 0) as randomValue3 ' || '		, COALESCE(randomAttr4, 0) as randomAttr4, COALESCE(randomValue4, 0) as randomValue4 ' || '		, COALESCE(randomAttr5, 0) as randomAttr5, COALESCE(randomValue5, 0) as randomValue5 ' || '		, COALESCE(randomAttr6, 0) as randomAttr6, COALESCE(randomValue6, 0) as randomValue6 ' || '		, COALESCE(randomAttr7, 0) as randomAttr7, COALESCE(randomValue7, 0) as randomValue7 ' || '		, COALESCE(randomAttr8, 0) as randomAttr8, COALESCE(randomValue8, 0) as randomValue8 ' || '		, COALESCE(randomAttr9, 0) as randomAttr9, COALESCE(randomValue9, 0) as randomValue9 ' || '		, COALESCE(randomAttr10, 0) as randomAttr10, COALESCE(randomValue10, 0) as randomValue10 ' || ' FROM	user_item i  ' || ' LEFT JOIN user_item_option o  ON i.id = o.id and o.char_id = i.char_id ' || ' LEFT JOIN user_item_freeTrade f  on i.id = f.id ' || ' LEFT JOIN user_item_attribute a  on i.id = a.id ' || v_sql_where;
    v_sql := v_sql || ' and i.id not in (select top ' || p_top_count || ' id from user_item i ' || v_sql_where || ' order by id desc) ';
    v_sql := v_sql || ' order by i.id desc';
    EXECUTE v_sql;
END;
$$;

