-- [WARN] [REVIEW] aion_AddedService_Type4_MoveChar_OnLine_Execute_ORS
--   Warning: GOTO statements detected - converted to RETURN where possible

CREATE OR REPLACE FUNCTION aion_addedservice_type4_movechar_online_execute_ors(
    p_serviceId integer,
    p_db_userId varchar(64),
    p_db_passwd varchar(64),
    OUT p_ret integer,
    OUT p_err_str varchar(50)
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_checkConnectServerId integer;
    v_checkError integer;
    v_toServer integer;
    v_serverId integer;
    v_idx integer;
    v_fromServer integer;
    v_fromCharId integer;
    v_fromCharName varchar(20);
    v_toCharId integer;
    v_toCharName varchar(20);
    v_fromUid integer;
    v_fromRace integer;
    v_linkedServerName varchar(50);
    v_retVal integer;
    v_retStatus integer;
    v_newCharId integer;
    v_serviceType integer;
    v_preminum integer;
    v_withAccountWarehouse integer;
BEGIN
    p_ret := 0;
    v_checkError := 0;
    p_err_str := 'Process';
    SELECT fromServer, toServer INTO v_checkConnectServerId, v_toServer FROM AionAddedService  where serviceType = 4 and serviceFlag = 0 and status = 0 and idx = p_serviceId;
    PERFORM aion_AddedService_Type4_MoveChar_CheckConn_ORS(v_checkConnectServerId, p_db_userId, p_db_passwd, p_ret, p_err_str);
    IF p_ret != 0 THEN
    v_checkError := 1;
    RAISE NOTICE '%', p_err_str;
    END IF;
    IF v_checkError <> 0 THEN
    p_ret := -100;
    RAISE EXCEPTION '%', 'CheckConn Error!!!';
    RETURN;
    END IF;
    SELECT idx, fromServer, fromCharacterId, fromCharacter, toCharacterId, toCharacter, fromUid, fromRace, serviceType, warehouse INTO v_idx, v_fromServer, v_fromCharId, v_fromCharName, v_toCharId, v_toCharName, v_fromUid, v_fromRace, v_serviceType, v_withAccountWarehouse FROM AionAddedService  where (serviceType = 4 or serviceType = 14) and serviceFlag = 0 and status = 0 and idx = p_serviceId;
    v_newCharId := v_toCharId;
    v_retStatus := -1;
    p_err_str := 'No success';
    IF v_serviceType = 8 THEN
    v_preminum := 1;
    ELSE
    v_preminum := 0;
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_CheckLocalChar_ORS(v_fromUid, v_fromRace, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_CheckOrgChar_ORS(v_fromServer, v_toServer, p_db_userId, p_db_passwd, v_fromCharId, v_fromCharName, v_preminum, v_withAccountWarehouse, 1, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_Process_ORS(p_db_userId, p_db_passwd, v_fromServer, v_fromCharId, v_fromCharName, v_toServer, v_toCharId, v_toCharName, v_preminum, v_withAccountWarehouse, v_newCharId, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    v_retStatus := 1;
    p_err_str := 'success' UpdateRetVal:;
    update AionAddedService Set status = v_retStatus, serviceFlag = v_retVal, toCharacterId = v_newCharId, applyDate = CURRENT_TIMESTAMP where idx = v_idx;
    p_ret := v_retVal;
END;
$$;

