-- [OK] [AUTO] aion_SetItemImportFlag

CREATE OR REPLACE FUNCTION aion_setitemimportflag(
    p_id bigint,
    p_importfrom integer,
    p_importfromid bigint,
    p_date integer,
    OUT p_importid bigint
) RETURNS bigint
LANGUAGE plpgsql
AS $$
BEGIN
    IF NOT EXISTS (SELECT id FROM user_item WHERE id = p_id AND import_id <> 0) THEN
    INSERT INTO import_item_log(item_id, import_from_sv, import_from_id, import_date) VALUES (p_id, p_importfrom, p_importfromid, p_date);
    p_importid := LASTVAL();
    UPDATE user_item SET import_id = p_importid WHERE id = p_id;
    ELSE
    p_importid := 0;
    END IF;
END;
$$;

