-- [WARN] [REVIEW] aion_AddedService_Type4_MoveChar_ORS
--   Warning: GOTO statements detected - converted to RETURN where possible
--   Warning: CURSOR logic detected - converted to PG cursor syntax

CREATE OR REPLACE FUNCTION aion_addedservice_type4_movechar_ors(
    p_serverId integer,
    p_db_userId varchar(64),
    p_db_passwd varchar(64)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_checkConnectServerId integer;
    v_ret integer;
    v_err_str varchar(256);
    v_checkError integer;
    v_toServer integer;
    checkConn_cursor CURSOR FOR select fromServer from AionAddedService  where (serviceType = 4 or serviceType = 14 or serviceType = 16) and serviceFlag = 0 and status = 0 and toServer = v_toServer group by fromServer;
    v_idx integer;
    v_fromServer integer;
    v_fromCharId integer;
    v_fromCharName varchar(20);
    v_toCharId integer;
    v_toCharName varchar(20);
    v_fromUid integer;
    v_fromRace integer;
    v_linkedServerName varchar(50);
    v_retVal integer;
    v_retStatus integer;
    v_newCharId integer;
    v_serviceType integer;
    v_preminum integer;
    v_withAccountWarehouse integer;
    moveChar_cursor CURSOR FOR select idx, fromServer, fromCharacterId, fromCharacter, toCharacterId, toCharacter, fromUid, fromRace, serviceType, warehouse from AionAddedService  where (serviceType = 4  or serviceType = 14 or serviceType = 16) and serviceFlag = 0 and status = 0 and toServer = v_toServer;
BEGIN
    v_toServer := 0;
    SELECT server_id INTO v_toServer FROM server_info where info_name = 'SERVER_START_TIME' order by int_value desc LIMIT 1;
    IF v_toServer = 0 or (p_serverId <> 0 and v_toServer <> p_serverId) THEN
    RAISE EXCEPTION '%', 'Check ServerId Error!!!';
    RETURN;
    END IF;
    v_checkError := 0;
    OPEN checkConn_cursor;
    FETCH checkConn_cursor INTO v_checkConnectServerId;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    PERFORM aion_AddedService_Type4_MoveChar_CheckConn_ORS(v_checkConnectServerId, p_db_userId, p_db_passwd, v_ret, v_err_str);
    IF v_ret != 0 THEN
    v_checkError := 1;
    RAISE NOTICE '%', v_err_str;
    END IF;
    FETCH checkConn_cursor INTO v_checkConnectServerId;
    v_fetch_found := FOUND;
    END LOOP;
    CLOSE checkConn_cursor;
    IF v_checkError <> 0 THEN
    RAISE EXCEPTION '%', 'CheckConn Error!!!';
    RETURN;
    END IF;
    OPEN moveChar_cursor;
    FETCH moveChar_cursor INTO v_idx, v_fromServer, v_fromCharId, v_fromCharName, v_toCharId, v_toCharName, v_fromUid, v_fromRace, v_serviceType, v_withAccountWarehouse;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    v_newCharId := v_toCharId;
    v_retStatus := -1;
    IF v_serviceType = 14 THEN
    v_preminum := 1;
    ELSE
    v_preminum := 0;
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_CheckLocalChar_ORS(v_fromUid, v_fromRace, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_CheckOrgChar_ORS(v_fromServer, v_toServer, p_db_userId, p_db_passwd, v_fromCharId, v_fromCharName, v_preminum, v_withAccountWarehouse, 0, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_Process_ORS(p_db_userId, p_db_passwd, v_fromServer, v_fromCharId, v_fromCharName, v_toServer, v_toCharId, v_toCharName, v_preminum, v_withAccountWarehouse, v_newCharId, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    v_retStatus := 1 UpdateRetVal:;
    update AionAddedService Set status = v_retStatus, serviceFlag = v_retVal, toCharacterId = v_newCharId, applyDate = CURRENT_TIMESTAMP where idx = v_idx;
    FETCH moveChar_cursor INTO v_idx, v_fromServer, v_fromCharId, v_fromCharName, v_toCharId, v_toCharName, v_fromUid, v_fromRace, v_serviceType, v_withAccountWarehouse;
    v_fetch_found := FOUND;
    END IF;
    CLOSE moveChar_cursor;
END;
$$;

