-- [OK] [AUTO] aion_rollbackGameMoneyTrade

CREATE OR REPLACE FUNCTION aion_rollbackgamemoneytrade(
    p_request_id varchar(64),
    OUT p_id bigint,
    OUT p_seller integer,
    OUT p_qina bigint,
    OUT p_cash bigint,
    OUT p_return_code integer
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    UPDATE game_money_trade SET state=-3, complete_date=CURRENT_TIMESTAMP Where request_id=p_request_id and state=1;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 1 THEN
    SELECT id, seller, qina, cash INTO p_id, p_seller, p_qina, p_cash WHERE request_id=p_request_id;
    p_return_code := 0;
    RETURN;
    ELSE
    p_return_code := -1;
    RETURN;
    END IF;
END;
$$;

