-- [OK] [AUTO] aion_savelimitedsales

CREATE OR REPLACE FUNCTION aion_savelimitedsales(
    p_npcid bigint,
    p_checktime bigint,
    p_totalstock integer,
    p_itemid bigint,
    p_curstock smallint,
    p_limitbuy smallint,
    p_limitnum smallint,
    p_turncnt smallint,
    p_charid bigint,
    p_count bigint,
    p_purchasetime bigint
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    update npc_limited_sales set cur_stock = p_curstock, limit_buy = p_limitbuy, limit_num = p_limitnum, turn_count = p_turncnt where npc_id = p_npcid::integer and item_id = p_itemid::integer and delete_flag = 0;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    insert into npc_limited_sales (npc_id, check_time, total_stock, item_id, cur_stock, limit_buy, limit_num, turn_count) values(p_npcid, p_checktime, p_totalstock, p_itemid, p_curstock, p_limitbuy, p_limitnum, p_turncnt);
    END IF;
    update npc_limited_sales set check_time=p_checktime, total_stock=p_totalstock where npc_id = p_npcid::integer and delete_flag = 0;
    update npc_user_sales_log set purchase_time=p_purchasetime, turn_count = p_turncnt, count = p_count::integer where npc_id = p_npcid::integer and item_id = p_itemid::integer and char_id = p_charid::integer and delete_flag = 0;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    insert into npc_user_sales_log (npc_id, item_id, char_id, purchase_time, count, turn_count) values (p_npcid, p_itemid, p_charid, p_purchasetime, p_count, p_turncnt);
    END IF;
END;
$$;

