-- [WARN] [REVIEW] aion_AddedService_Type4_MoveChar_ORS_DIRECT_TEST_by_venny
--   Warning: GOTO statements detected - converted to RETURN where possible

CREATE OR REPLACE FUNCTION aion_addedservice_type4_movechar_ors_direct_test_by_venny(
    p_serverId integer,
    p_db_userId varchar(64),
    p_db_passwd varchar(64),
    p_service_db_idx integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_checkConnectServerId integer;
    v_ret integer;
    v_err_str varchar(256);
    v_checkError integer;
    v_toServer integer;
    v_idx integer;
    v_fromServer integer;
    v_fromCharId integer;
    v_fromCharName varchar(20);
    v_toCharId integer;
    v_toCharName varchar(20);
    v_fromUid integer;
    v_fromRace integer;
    v_linkedServerName varchar(50);
    v_retVal integer;
    v_retStatus integer;
    v_newCharId integer;
BEGIN
    v_toServer := p_serverId;
    v_checkError := 0;
    SELECT fromServer INTO v_checkConnectServerId FROM AionAddedService  where serviceType = 4 and serviceFlag = 0 and status = 0 and idx = p_service_db_idx;
    PERFORM aion_AddedService_Type4_MoveChar_CheckConn_ORS(v_checkConnectServerId, p_db_userId, p_db_passwd, v_ret, v_err_str);
    IF v_ret != 0 THEN
    v_checkError := 1;
    RAISE NOTICE '%', v_err_str;
    END IF;
    IF v_checkError <> 0 THEN
    RAISE EXCEPTION '%', 'CheckConn Error!!!';
    RETURN;
    END IF;
    SELECT idx, fromServer, fromCharacterId, fromCharacter, toCharacterId, toCharacter, fromUid, fromRace INTO v_idx, v_fromServer, v_fromCharId, v_fromCharName, v_toCharId, v_toCharName, v_fromUid, v_fromRace FROM AionAddedService  where serviceType = 4 and serviceFlag = 0 and status = 0 and idx = p_service_db_idx;
    v_newCharId := v_toCharId;
    v_retStatus := -1;
    PERFORM aion_AddedService_Type4_MoveChar_CheckLocalChar_ORS(v_fromUid, v_fromRace, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_CheckOrgChar_ORS(v_fromServer, v_toServer, p_db_userId, p_db_passwd, v_fromCharId, v_fromCharName, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    PERFORM aion_AddedService_Type4_MoveChar_Process_ORS(p_db_userId, p_db_passwd, v_fromServer, v_fromCharId, v_fromCharName, v_toServer, v_toCharId, v_toCharName, v_newCharId, v_retVal);
    IF v_retVal != 0 THEN
        RETURN;  -- Originally: GOTO UpdateRetVal
    END IF;
    v_retStatus := 1 UpdateRetVal:;
    update AionAddedService Set status = v_retStatus, serviceFlag = v_retVal, toCharacterId = v_newCharId, applyDate = CURRENT_TIMESTAMP where idx = v_idx;
END;
$$;

