-- [OK] [AUTO] aion_SetAbyssGuildRank

CREATE OR REPLACE FUNCTION aion_setabyssguildrank(
    p_nRace integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE guild SET old_rank = rank where race = p_nRace::integer;
    UPDATE guild SET rank=0 WHERE race = p_nRace::integer;
    UPDATE guild set rank = RankList.rnk from (SELECT  id, RANK( AS rnk) over (order by point desc, point_max_time,id desc) WHERE race = p_nRace::integer order by point desc,point_max_time, id desc LIMIT 50) as RankList where guild.id = RankList.id;
    delete from abyss_region_ranking;
    insert into abyss_region_ranking select rank,old_rank,id,race,level,cnt,point,name, GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0) from guild inner join (select guild_id,cnt = count(*) from user_data where guild_id !=0 group by guild_id) AS UserCount on guild.id = UserCount.guild_id where rank <= 50 and rank>0 order by race,rank;
END;
$$;

