-- [WARN] [REVIEW] GM_UserItemDAO_AddCompound
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION

CREATE OR REPLACE FUNCTION gm_useritemdao_addcompound(
    p_char_id integer,
    p_item_id bigint,
    p_main_item_dbid bigint
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_charge_point_main integer;
    v_charge_point_sub integer;
BEGIN
    -- Transaction managed by PG function context
    IF EXISTS (select id from user_item where id = p_main_item_dbid and main_item_dbid != 0 and char_id = p_char_id::integer) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    END IF;
    IF EXISTS (select id from user_item where main_item_dbid = p_main_item_dbid and warehouse = 16 and char_id = p_char_id::integer) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 2;
    END IF;
    IF EXISTS (select id from user_item where main_item_dbid = p_item_id and warehouse = 16 and char_id = p_char_id::integer) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 3;
    END IF;
    IF EXISTS (select id from user_item where id = p_item_id and main_item_dbid != 0 and char_id = p_char_id::integer) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 4;
    ELSE
    update user_item set warehouse = 16, main_item_dbid = p_main_item_dbid, update_date=CURRENT_TIMESTAMP where id = p_item_id and char_id = p_char_id::integer;
    IF NOT EXISTS (select id from user_item_option where id = p_item_id) THEN
    insert into user_item_option (id, char_id) values (p_item_id, p_char_id);
    END IF;
    SELECT charge_point INTO v_charge_point_main FROM user_item_charge where id = p_main_item_dbid;
    SELECT charge_point INTO v_charge_point_sub FROM user_item_charge where id = p_item_id;
    IF v_charge_point_main is null THEN
    v_charge_point_main := 0;
    END IF;
    IF v_charge_point_sub is null THEN
    v_charge_point_sub := 0;
    END IF;
    IF v_charge_point_main > 0 or v_charge_point_sub > 0 THEN
    IF not EXISTS (select id from user_item_charge where id = p_main_item_dbid) THEN
    update user_item_charge set id = p_main_item_dbid, charge_point=v_charge_point_sub where id=p_item_id;
    ELSE
    IF v_charge_point_main < v_charge_point_sub THEN
    update user_item_charge set charge_point=v_charge_point_sub where id=p_main_item_dbid;
    END IF;
    END IF;
    END IF;
    END IF;
    -- COMMIT (implicit in PG function)
    RETURN 0;
END;
$$;

