-- [OK] [AUTO] GM_UserItemDAO_CompoundDeletedItemToInven

CREATE OR REPLACE FUNCTION gm_useritemdao_compounddeleteditemtoinven(
    p_main_item_dbid bigint,
    p_char_id integer,
    OUT p_returnValue integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_error integer;
BEGIN
    p_returnValue := 0;
    UPDATE user_item SET warehouse=16 WHERE id  = (SELECT  id WHERE char_id = p_char_id::integer AND main_item_dbid=p_main_item_dbid AND warehouse=17 order by update_date desc LIMIT 1) AND 0 = (select count(*) FROM user_item  WHERE char_id = p_char_id::integer AND main_item_dbid=p_main_item_dbid AND warehouse=16);
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    v_error := 0 /* @v_ERROR */;
    v_rowCount := v_rowcount;
    IF v_error <> 0 OR v_rowCount < 1 THEN
    RETURN;
    END IF;
    p_returnValue := 1;
    RETURN;
END;
$$;

