-- [OK] [AUTO] aion_GetItemListAll

CREATE OR REPLACE FUNCTION aion_getitemlistall(
    p_nCharId integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT   id, name_id, slot_id, amount, tid, slot, producer, expired_time, buy_amount, buy_duration, warehouse FROM user_item WHERE char_id = p_nCharId::integer and warehouse not in (2,6,7, 10, 11, 12) AND export_id = 0;
END;
$$;

