-- [OK] [AUTO] GM_HouseDA_SrchHouseObjectByOwnerID

CREATE OR REPLACE FUNCTION gm_houseda_srchhouseobjectbyownerid(
    p_char_id integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT	o.id, o.object_nameid, o.object_type, o.owner_id, o.owner_type, o.state, o.expired_time, o.general_use_count, o.world, o.xlocation, o.ylocation, o.zlocation, o.dir, o.update_time, o.created_time, o.dye_info, o.expire_dye_time, e.char_id, e.accumulated_usecount, e.next_resettime_for_owner, e.resource_id, e.account_id, e.cur_owner_usecnt_per_day FROM	houseobject o  LEFT JOIN houseobject_extdata e  on o.owner_id = p_char_id::integer and o.id = e.obj_id WHERE	o.owner_id = p_char_id::integer ORDER BY o.object_type, o.id DESC;
END;
$$;

