-- [OK] [AUTO] aion_getauctionstate_20110609

CREATE OR REPLACE FUNCTION aion_getauctionstate_20110609(
    p_id integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT buyerid, buyername, InitQina, qina, state from user_auction where ID=p_id;
END;
$$;

