-- [OK] [AUTO] aion_SetItemPreserved

CREATE OR REPLACE FUNCTION aion_setitempreserved(
    p_nCharId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE user_item SET warehouse=16, update_date=CURRENT_TIMESTAMP  WHERE char_id = p_nCharId::integer AND warehouse=0;
END;
$$;

