-- [OK] [AUTO] aion_SetAbyssInfoNew_20160520

CREATE OR REPLACE FUNCTION aion_setabyssinfonew_20160520(
    p_nAbyssId integer,
    p_nOwnerServer integer,
    p_nOwnerGuild integer,
    p_nOwnerRace smallint,
    p_nDefenseCnt integer,
    p_nReward bigint,
    p_nOccupyBonus bigint,
    p_nUserRewardSum bigint,
    p_nChangeOwnerTime integer,
    p_nCurPvPStatus smallint,
    p_nNextPvPStatus smallint,
    p_nDoorUpgradePoint integer,
    p_nShieldUpgradePoint integer,
    p_nPeaceCount smallint,
    p_nNewOwnerCharId integer,
    p_nPrevOwnerCharId integer,
    p_nOwnershipBonusGloryPoint integer,
    p_nLastPvPOnTime integer,
    p_nOccupyPoint smallint,
    p_nOccupyCount smallint,
    p_nOccupyRewardCountL smallint,
    p_nOccupyRewardCountD smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_bIsLastOwnershipBonusUpdated integer;
    v_nLastOwnershipBonusGp integer;
BEGIN
    v_bIsLastOwnershipBonusUpdated := 0;
    IF (p_nPrevOwnerCharId != p_nNewOwnerCharId) THEN
    IF (0 < p_nPrevOwnerCharId) THEN
    v_nLastOwnershipBonusGp := (select COALESCE(last_ownership_bonus_gp, 0) FROM abyss where abyss_id = p_nAbyssId::integer);
    IF (0 < v_nLastOwnershipBonusGp) THEN
    UPDATE user_gp_data SET ownership_bonus_gp = ownership_bonus_gp - v_nLastOwnershipBonusGp where char_id = p_nPrevOwnerCharId::integer;
    END IF;
    END IF;
    IF (0 < p_nNewOwnerCharId) AND (0 < p_nOwnershipBonusGloryPoint) THEN
    v_bIsLastOwnershipBonusUpdated := 1;
    IF EXISTS (SELECT char_id WHERE char_id = p_nNewOwnerCharId::integer) THEN
    UPDATE user_gp_data SET ownership_bonus_gp = ownership_bonus_gp + p_nOwnershipBonusGloryPoint where char_id = p_nNewOwnerCharId::integer;
    ELSE
    INSERT INTO user_gp_data (char_id, glory_point, ownership_bonus_gp) VALUES (p_nNewOwnerCharId, 0, p_nOwnershipBonusGloryPoint);
    END IF;
    UPDATE user_data SET today_glory_point = today_glory_point + p_nOwnershipBonusGloryPoint, this_week_glory_point = this_week_glory_point + p_nOwnershipBonusGloryPoint where char_id = p_nNewOwnerCharId::integer;
    END IF;
    END IF;
    IF EXISTS (SELECT abyss_id FROM abyss WHERE abyss_id = p_nAbyssId::integer) THEN
    IF (0 < v_bIsLastOwnershipBonusUpdated) THEN
    UPDATE abyss SET owner_guild = p_nOwnerGuild, owner_race =  p_nOwnerRace, defense_count =  p_nDefenseCnt, reward = p_nReward, cur_pvp_status = p_nCurPvPStatus, next_pvp_status = p_nNextPvPStatus, door_upgrade_point = p_nDoorUpgradePoint, shield_upgrade_point = p_nShieldUpgradePoint, peace_count = p_nPeaceCount, occupy_bonus = p_nOccupyBonus, user_reward_sum = p_nUserRewardSum, change_owner_time = p_nChangeOwnerTime, owner_server = p_nOwnerServer, owner_char_id=p_nNewOwnerCharId, last_ownership_bonus_gp=p_nOwnershipBonusGloryPoint, last_pvp_on_time = p_nLastPvPOnTime, occupy_point = p_nOccupyPoint, occupy_count = p_nOccupyCount, occupy_reward_count_l = p_nOccupyRewardCountL, occupy_reward_count_d = p_nOccupyRewardCountD WHERE abyss_id = p_nAbyssId::integer;
    ELSE
    UPDATE abyss SET owner_guild = p_nOwnerGuild, owner_race =  p_nOwnerRace, defense_count =  p_nDefenseCnt, reward = p_nReward, cur_pvp_status = p_nCurPvPStatus, next_pvp_status = p_nNextPvPStatus, door_upgrade_point = p_nDoorUpgradePoint, shield_upgrade_point = p_nShieldUpgradePoint, peace_count = p_nPeaceCount, occupy_bonus = p_nOccupyBonus, user_reward_sum = p_nUserRewardSum, change_owner_time = p_nChangeOwnerTime, owner_server = p_nOwnerServer, owner_char_id=p_nNewOwnerCharId, last_pvp_on_time = p_nLastPvPOnTime, occupy_point = p_nOccupyPoint, occupy_count = p_nOccupyCount, occupy_reward_count_l = p_nOccupyRewardCountL, occupy_reward_count_d = p_nOccupyRewardCountD WHERE abyss_id = p_nAbyssId::integer;
    ELSE
    IF (0 < v_bIsLastOwnershipBonusUpdated) THEN
    INSERT INTO abyss (abyss_id, owner_server, owner_guild, owner_race, defense_count, reward, occupy_bonus, user_reward_sum, change_owner_time, last_ownership_bonus_gp, last_pvp_on_time, occupy_point, occupy_count, occupy_reward_count_l, occupy_reward_count_d) VALUES (p_nAbyssId, p_nOwnerServer, p_nOwnerGuild, p_nOwnerRace, p_nDefenseCnt, p_nReward, p_nOccupyBonus, p_nUserRewardSum, p_nChangeOwnerTime, p_nOwnershipBonusGloryPoint, p_nLastPvPOnTime, p_nOccupyPoint, p_nOccupyCount, p_nOccupyRewardCountL, p_nOccupyRewardCountD);
    ELSE
    INSERT INTO abyss (abyss_id, owner_server, owner_guild, owner_race, defense_count, reward, occupy_bonus, user_reward_sum, change_owner_time, last_ownership_bonus_gp, last_pvp_on_time, occupy_point, occupy_count, occupy_reward_count_l, occupy_reward_count_d) VALUES (p_nAbyssId, p_nOwnerServer, p_nOwnerGuild, p_nOwnerRace, p_nDefenseCnt, p_nReward, p_nOccupyBonus, p_nUserRewardSum, p_nChangeOwnerTime, 0, p_nLastPvPOnTime, p_nOccupyPoint, p_nOccupyCount, p_nOccupyRewardCountL, p_nOccupyRewardCountD);
    END IF;
    END IF;
END;
$$;

