-- [OK] [AUTO] aion_IsExist

CREATE OR REPLACE FUNCTION aion_isexist(
    p_uCharName varchar(20)
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    PERFORM char_id FROM user_data WHERE user_id = p_uCharName::integer and delete_complete_date = 0;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount=0 THEN
    RETURN 0;
    RETURN 1;
END;
$$;

