-- [OK] [AUTO] GM_UserItemDAO_CompoundItemToInven

CREATE OR REPLACE FUNCTION gm_useritemdao_compounditemtoinven(
    p_main_item_dbid bigint,
    p_char_id integer,
    OUT p_returnValue integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_error integer;
BEGIN
    p_returnValue := 0;
    UPDATE USER_ITEM SET warehouse=0, main_item_dbid=0 WHERE warehouse=16 and main_item_dbid=p_main_item_dbid AND char_id = p_char_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    v_error := 0 /* @v_ERROR */;
    v_rowCount := v_rowcount;
    IF v_error <> 0 OR v_rowCount < 1 THEN
    RETURN;
    END IF;
    p_returnValue := 1;
    RETURN;
END;
$$;

