-- [OK] [AUTO] aion_GetItemListCompoundedTwoHand

CREATE OR REPLACE FUNCTION aion_getitemlistcompoundedtwohand(
    p_nCharId integer,
    p_nWarehouse integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT   a.id, a.name_id, a.main_item_dbid, COALESCE(b.stat_enchant_name0, 0), COALESCE(b.stat_enchant_name1, 0), COALESCE(b.stat_enchant_name2, 0), COALESCE(b.stat_enchant_name3, 0), COALESCE(b.stat_enchant_name4, 0), COALESCE(b.stat_enchant_name5, 0), COALESCE(b.option_count, 0), COALESCE(b.random_option, 0) AS random_option FROM user_item a, user_item_option b WHERE a.char_id = p_nCharId::integer and a.id = b.id AND a.warehouse = p_nWarehouse::integer;
END;
$$;

