-- [OK] [AUTO] aion_addErrorIgnore

CREATE OR REPLACE FUNCTION aion_adderrorignore(
    p_ignore varchar(256)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_count integer;
BEGIN
    SELECT COUNT(*) INTO v_count FROM error_ignore where ignore = p_ignore;
    IF v_count > 0 THEN
    RETURN;
    END IF;
    insert into error_ignore values(p_ignore);
END;
$$;

