-- [OK] [AUTO] aion_SetAbyssOPPointAndResetTime

CREATE OR REPLACE FUNCTION aion_setabyssoppointandresettime(
    p_race integer,
    p_quest integer,
    p_fortress integer,
    p_artifact integer,
    p_basecamp integer,
    p_op_object integer,
    p_raid_object integer,
    p_ownership_object integer,
    p_next_reset_time integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT race FROM abyss_op_point  WHERE race = p_race::integer) THEN
    UPDATE abyss_op_point SET quest = p_quest, fortress = p_fortress, artifact = p_artifact, basecamp = p_basecamp, op_object = p_op_object, raid_object = p_raid_object, ownership_object = p_ownership_object, next_reset_time = p_next_reset_time WHERE race = p_race::integer;
    ELSE
    INSERT INTO abyss_op_point VALUES (p_race, p_quest, p_fortress, p_artifact, p_basecamp, p_op_object, p_raid_object, p_ownership_object, p_next_reset_time);
    END IF;
END;
$$;

