BEGIN
    -- Transaction managed by PG function context
    SELECT main_item_dbid INTO v_main_item_dbid FROM user_item where id = p_item_id and char_id = p_char_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (v_rowcount = 0) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    END IF;
    IF not EXISTS (select char_id from user_item where char_id = p_char_id::integer and warehouse=16 and main_item_dbid=v_main_item_dbid) THEN
    update user_item set warehouse = p_warehouse::integer where char_id = p_char_id::integer and warehouse=17 and id = p_item_id and char_id = p_char_id::integer;
    ELSE
    RAISE EXCEPTION 'Rollback requested';
    RETURN 2;
    END IF;
    -- COMMIT (implicit in PG function)
    RETURN 0;
END;
$$;

