-- [OK] [AUTO] GM_LegionDominionDA_Srch

CREATE OR REPLACE FUNCTION gm_legiondominionda_srch(
    p_world_id integer,
    p_legion_id integer DEFAULT 0,
    p_legion_name varchar(32) DEFAULT '',
    p_dominion_id integer DEFAULT 0,
    p_page_num integer DEFAULT 1,
    p_view_count integer DEFAULT 1000,
    p_order_col varchar(200) DEFAULT 'dominion_id, score desc, played_time_in_sec, game_end_time'
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_query varchar(2000);
    v_where varchar(1000);
BEGIN
    v_where := ' where	server_id = ' || CAST(p_world_id AS varchar);
    IF (p_legion_id != 0) THEN
    v_where := v_where || ' and		legion_id = ' || CAST(p_legion_id AS varchar);
    END IF;
    IF (p_legion_name != '') THEN
    v_where := v_where || ' and		name = ''' || p_legion_name || '''';
    END IF;
    IF (p_dominion_id != 0) THEN
    v_where := v_where || ' and		dominion_id = ' || CAST(p_dominion_id AS varchar);
    ELSE
    v_where := v_where || ' and		dominion_id != 0';
    END IF;
    v_query := ';
    PERFORM  || ' LIMIT ' || CAST(p_view_count AS varchar) x.*, COALESCE(x.name, ''unknown'') as legion_name from (SELECT /*INLINE_LIMIT:' || CAST(p_page_num*p_view_count AS varchar*/ || ') ROW_NUMBER() over (order by ' || p_order_col || ') as num, legion_id, g.name, dominion_id, score, played_time_in_sec, game_end_time, take_over_processed_time, server_id from	legion_dominion_rankings d LEFT JOIN guild g  on d.legion_id = g.id ' || v_where || ' ) x ' || v_where || ' and		num > ' || CAST((p_page_num-1)*p_view_count AS varchar) || ' order by ' || p_order_col;
    EXECUTE v_query;
END;
$$;

