-- [OK] [AUTO] aion_AddOfflineBuddy

CREATE OR REPLACE FUNCTION aion_addofflinebuddy(
    p_charId integer,
    p_inviterId integer,
    p_inviterName varchar(50),
    p_message text,
    p_level integer,
    p_class integer,
    p_gender integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_buddyCount integer;
    v_offCount integer;
    v_interCount integer;
BEGIN
    IF EXISTS (select inviter_id from user_buddy_offline where user_id = p_charId::integer and inviter_id = p_inviterId) THEN
    RETURN 12;
    END IF;
    IF EXISTS (select inviter_id from user_buddy_offline where user_id = p_inviterId::integer and inviter_id = p_charId) THEN
    RETURN 19;
    END IF;
    SELECT COUNT(*) INTO v_buddyCount FROM user_buddy1 where char_id = p_charId::integer;
    SELECT COUNT(*) INTO v_offCount FROM user_buddy_offline where user_id = p_charId::integer;
    SELECT COUNT(*) INTO v_interCount FROM user_buddy_inter where char_id = p_charId::integer;
    IF (v_buddyCount + v_offCount + v_interCount>= 100) THEN
    RETURN 14;
    END IF;
    SELECT COUNT(*) INTO v_buddyCount FROM user_buddy1 where char_id = p_inviterId::integer;
    SELECT COUNT(*) INTO v_offCount FROM user_buddy_offline where inviter_id = p_inviterId;
    SELECT COUNT(*) INTO v_interCount FROM user_buddy_inter where char_id = p_inviterId::integer;
    IF (v_buddyCount + v_offCount+v_interCount >= 100) THEN
    RETURN 13;
    END IF;
    insert into user_buddy_offline (user_id, inviter_id, inviter_name, inviter_msg, userlevel, userclass, gender) values (p_charId, p_inviterId, p_inviterName, p_message, p_level, p_class, p_gender);
    RETURN 11;
END;
$$;

