    p_ownerid integer,
    p_auctionid integer,
    p_qina bigint
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (select ownerid from user_betting where ownerid = p_ownerid) THEN
