-- [OK] [AUTO] aion_GetBuddy_130319

CREATE OR REPLACE FUNCTION aion_getbuddy_130319(
    p_nCharId integer,
    p_type integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_utc_adjust bigint;
BEGIN
    v_utc_adjust := GetUtcAdjustSecWithUTC_Local((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), CURRENT_TIMESTAMP);
    IF p_type = 0 THEN
    PERFORM buddy_id, user_id, lev, class, gender, world, GetUnixtimeWithUTCAdjust(last_logout_time, v_utc_adjust), b.delete_flag, d.daily_comment, d.race, 0, COALESCE(e.id, -1), COALESCE(permission,0), COALESCE(b.comment, '') FROM user_buddy1 AS b INNER JOIN user_data AS d ON b.buddy_id=d.char_id left join house_instant as e on e.id = d.char_id  and e.state<>6 WHERE b.char_id = p_nCharId::integer;
    ELSE
    PERFORM buddy_id, user_id, lev, class, gender, world, GetUnixtimeWithUTCAdjust(last_logout_time, v_utc_adjust), b.delete_flag, d.daily_comment, d.race, e.id, e.addr_id, COALESCE(permission,0), COALESCE(b.comment, '') FROM user_buddy1 AS b INNER JOIN user_data AS d ON b.buddy_id=d.char_id  inner join house_field as e on e.owner_id = d.char_id AND e.owner_type = 2 WHERE b.char_id = p_nCharId::integer;
    END IF;
END;
$$;

