-- [OK] [AUTO] aion_AnswerOfflineBuddy

CREATE OR REPLACE FUNCTION aion_answerofflinebuddy(
    p_charId integer,
    p_charname varchar(20),
    p_inviterId integer,
    p_invitername varchar(20),
    OUT p_level integer,
    OUT p_class integer,
    OUT p_gender integer,
    OUT p_worldnum integer,
    OUT p_todayword varchar(53),
    OUT p_return_code integer
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_result integer;
    v_buddyCount integer;
    v_offCount integer;
BEGIN
    p_level := 0;
    p_class := 0;
    p_gender := 0;
    p_worldnum := 0;
    p_todayword := '';
    IF EXISTS (SELECT char_id FROM user_buddy1 WHERE char_id = p_charId::integer and buddy_id = p_inviterId) THEN
    p_return_code := 2;
    RETURN;
    END IF;
    IF not EXISTS (select char_id from user_data where char_id = p_inviterId::integer and race = (select race from user_data where char_id = p_charId::integer)) THEN
    p_return_code := 3;
    RETURN;
    END IF;
    SELECT COUNT(*) INTO v_buddyCount FROM user_buddy1 where char_id = p_charId::integer;
    IF (v_buddyCount >= 200) THEN
    p_return_code := 5;
    RETURN;
    END IF;
    SELECT COUNT(*) INTO v_buddyCount FROM user_buddy1 where char_id = p_inviterId::integer;
    IF (v_buddyCount >= 200) THEN
    p_return_code := 5;
    RETURN;
    END IF;
    INSERT INTO user_buddy1 (char_id, buddy_id, delete_flag) VALUES (p_inviterId, p_charId, 0);
    SELECT lev, class, gender, world, daily_comment INTO p_level, p_class, p_gender, p_worldnum, p_todayword FROM user_data  where char_id = p_inviterId::integer;
    p_return_code := 0;
    RETURN;
END;
$$;

