-- [OK] [AUTO] aion_AvatarAddedService_ClearUserData

CREATE OR REPLACE FUNCTION aion_avataraddedservice_clearuserdata(
    p_char_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_rowcnt integer;
BEGIN
    v_rowcnt := 0;
    DELETE FROM vendor_item_dark where char_id = p_char_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    v_rowcnt := v_rowcnt + v_rowcount;
    DELETE FROM vendor_item_light where char_id = p_char_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    v_rowcnt := v_rowcnt + v_rowcount;
    update	user_item set		warehouse = 0 output	CURRENT_TIMESTAMP, inserted.char_id, inserted.id, deleted.warehouse, inserted.warehouse into	AvatarAddedService_ClearVendorLog where	char_id = p_char_id::integer and warehouse = 4 set v_rowcnt = v_rowcnt + v_rowcount;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    update	user_data set		guild_id = 0, guild_rank = 0 where	char_id = p_char_id::integer set v_rowcnt = v_rowcnt + v_rowcount;
    PERFORM v_rowcnt as rowcnt;
END;
$$;

