-- [OK] [AUTO] GM_UserItemDAO_InsertUpdateAttribute

CREATE OR REPLACE FUNCTION gm_useritemdao_insertupdateattribute(
    p_id bigint,
    p_attribute1 integer,
    p_attribute1value integer,
    p_attribute2 integer,
    p_attribute2value integer,
    p_attribute3 integer,
    p_attribute3value integer,
    p_attribute4 integer,
    p_attribute4value integer,
    p_attribute5 integer,
    p_attribute5value integer,
    p_attribute6 integer,
    p_attribute6value integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    update	user_item_attribute set		attribute1 = p_attribute1, attribute1value = p_attribute1value, attribute2 = p_attribute2, attribute2value = p_attribute2value, attribute3 = p_attribute3, attribute3value = p_attribute3value, attribute4 = p_attribute4, attribute4value = p_attribute4value, attribute5 = p_attribute5, attribute5value = p_attribute5value, attribute6 = p_attribute6, attribute6value = p_attribute6value where	id = p_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (0 < v_rowcount) THEN
    RETURN 1;
    ELSE
    insert into user_item_attribute (id, attribute1, attribute2, attribute3, attribute4, attribute5, attribute6, attribute1value, attribute2value, attribute3value, attribute4value, attribute5value, attribute6value) values (p_id, p_attribute1, p_attribute2, p_attribute3, p_attribute4, p_attribute5, p_attribute6, p_attribute1value, p_attribute2value, p_attribute3value, p_attribute4value, p_attribute5value, p_attribute6value);
    END IF;
END;
$$;

