-- [OK] [AUTO] aion_AvatarAddedService_Type4_MoveChar_CheckOrgChar_local_ORS

CREATE OR REPLACE FUNCTION aion_avataraddedservice_type4_movechar_checkorgchar_local_ors(
    p_fromServerId integer,
    p_toServerId integer,
    p_orgCharId integer,
    p_orgCharName varchar(20),
    p_premium integer,
    p_withAccountWarehouse integer,
    p_byOnline integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_ret integer;
    v_lev integer;
    v_delete_date integer;
    v_guild integer;
    v_qina_restrict_value bigint;
    v_level_restrict_value integer;
    v_ap_restrict_value integer;
    v_gp_restrict_value integer;
    v_user_qina bigint;
    v_user_mail_qina bigint;
    v_warehouse_qina bigint;
    v_ap bigint;
    v_user_restrict_item_cnt integer;
    v_vendor_item_cnt integer;
    v_vendor_log_item_cnt integer;
    v_charName varchar(20);
    v_user_restrict_recipe_cnt integer;
    v_last_login_time timestamp;
    v_last_logout_time timestamp;
    v_house_count integer;
    v_escrow_count integer;
    v_house_auction_count integer;
    v_buddy_count integer;
    v_account_id integer;
    v_gp bigint;
    v_ownership_bonus_gp integer;
    v_realtime_move_char_status integer;
BEGIN
    v_ret := 0;
    v_realtime_move_char_status := (select user_state from user_server_transfer where char_id = p_orgCharId::integer);
    v_qina_restrict_value := (select value from (SELECT  item_name_id, value , world_id from restricted_item where RESTRICT_STATUS = 1 and service_type in (0,2) and type = 2 and service_class_type = p_premium and world_id in (0, p_toServerId) and start_date <= CURRENT_TIMESTAMP and (end_date is null or CURRENT_TIMESTAMP < end_date) order by world_id desc LIMIT 1) as b);
    v_level_restrict_value := (select value from (SELECT  item_name_id, value , world_id from restricted_item where RESTRICT_STATUS = 1 and service_type in (0,2) and type = 4 and world_id in (0, p_toServerId) and service_class_type = p_premium and start_date <= CURRENT_TIMESTAMP and (end_date is null or CURRENT_TIMESTAMP < end_date) order by world_id desc LIMIT 1) as b);
    v_ap_restrict_value := (select value from (SELECT  item_name_id, value , world_id from restricted_item where RESTRICT_STATUS = 1 and service_type in (0,2) and type = 3 and world_id in (0, p_toServerId) and service_class_type = p_premium and start_date <= CURRENT_TIMESTAMP and (end_date is null or CURRENT_TIMESTAMP < end_date) order by world_id desc LIMIT 1) as b);
    v_lev := 0;
    SELECT lev, delete_date, guild_id, abyss_point, user_id, last_login_time, last_logout_time, account_id INTO v_lev, v_delete_date, v_guild, v_ap, v_charName, v_last_login_time, v_last_logout_time, v_account_id FROM user_data  where char_id = p_orgCharId::integer;
    IF v_lev <> 0 THEN
    IF v_charName <> p_orgCharName and not exists(select id from user_name_change_log where char_id = p_orgCharId::integer and old_name = p_orgCharName) THEN
    v_ret := -10103;
    END IF;
    IF (v_level_restrict_value is not null and v_lev < v_level_restrict_value)	set v_ret = -10001 THEN
    IF v_delete_date<> 0	set v_ret = -10009 THEN
    IF (v_ap_restrict_value is not null and v_ap > v_ap_restrict_value) set v_ret = -10004 THEN
    SELECT COALESCE(glory_point, 0), COALESCE(ownership_bonus_gp, 0) INTO v_gp, v_ownership_bonus_gp FROM user_gp_data where char_id = p_orgCharId::integer;
    END IF;
    END IF;
    END IF;
    IF (v_ownership_bonus_gp > 0 ) set v_ret = -10017 THEN
    IF EXISTS (select * from user_punishment where char_id = p_orgCharId::integer and status = 0 and ((play_block = 1 and end_date > CURRENT_TIMESTAMP) or (play_block = 0 and Remain_Minute > 0)) and (punish_code != 101 and punish_code != 102)) THEN
    v_ret := -10010;
    END IF;
    END IF;
    v_house_count := 0;
    v_house_count := (select count(*) from house_field where owner_id = p_orgCharId::integer);
    IF v_house_count > 0 THEN
    v_ret := -10011;
    END IF;
    v_escrow_count := 0;
    v_escrow_count := (select count(*) from user_escrow where seller = p_orgCharId and state = 1);
    IF v_escrow_count > 0 THEN
    v_ret := -10014;
    END IF;
    v_house_auction_count := 0;
    v_house_auction_count := (select COUNT(*) from user_auction where (sellerID = p_orgCharId and state = 0) or (buyerID = p_orgCharId and state = 1));
    IF v_house_auction_count > 0 THEN
    v_ret := -10013;
    END IF;
    IF EXISTS (select complete_date from game_money_trade where seller =  p_orgCharId and complete_date is NULL) THEN
    v_ret := -10105;
    ELSE
    v_ret := -10103;
    END IF;
    PERFORM v_ret as result;
END;
$$;

