-- [OK] [AUTO] sp_whale_fall_record_kill

CREATE OR REPLACE FUNCTION sp_whale_fall_record_kill(
    p_victim_char_id integer,
    p_killer_char_id integer,
    p_kill_type varchar(20) DEFAULT 'PVP',
    p_world_id integer DEFAULT 0
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_killer_name varchar(64);
BEGIN
    SELECT cn.name INTO v_killer_name FROM character_name cn JOIN user_data ud ON cn.name_id = ud.name_id WHERE ud.char_id = p_killer_char_id::integer;
    DELETE FROM whale_fall_kill_record WHERE victim_char_id = p_victim_char_id;
    INSERT INTO whale_fall_kill_record (victim_char_id, killer_char_id, killer_name, kill_type, world_id) VALUES (p_victim_char_id, p_killer_char_id, v_killer_name, p_kill_type, p_world_id);
END;
$$;

