    v_buddyCheck2 integer;
    v_receiver_guild_id2 integer;
    v_tmp integer;
BEGIN
    v_char_id := 0;
    SELECT char_id, race, optionflags INTO v_char_id, v_recverRace, v_optionflags FROM user_data where user_id = p_receiver::integer and delete_complete_date = 0 and delete_date = 0 order by char_id desc LIMIT 1;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (v_rowcount = 0) THEN
    PERFORM 1, v_char_id;
    RETURN;
    END IF;
    IF (p_useBlockOption = 1) THEN
    IF ((v_optionflags & 16777216) = 16777216) THEN
    SELECT char_id INTO v_buddyCheck FROM user_buddy1 where char_id = v_char_id and buddy_id =p_sender_id;
    IF (v_buddyCheck <> 0) THEN
    -- TODO: MANUAL REVIEW NEEDED - GOTO BlockOption_Check_Success
    RETURN;  -- Originally: GOTO BlockOption_Check_Success
    ELSE
    IF (p_sender_guild_id <> 0) THEN
    SELECT guild_id INTO v_receiver_guild_id FROM user_data where char_id = v_char_id;
    IF (p_sender_guild_id = v_receiver_guild_id) THEN
    -- TODO: MANUAL REVIEW NEEDED - GOTO BlockOption_Check_Success
    RETURN;  -- Originally: GOTO BlockOption_Check_Success
    END IF;
    END IF;
    END IF;
    PERFORM 5, v_char_id;
    RETURN;
    ELSIF ((v_optionflags & 8388608) = 8388608) THEN
    IF (p_sender_level < p_minReceiveLevel) THEN
    SELECT char_id INTO v_buddyCheck2 FROM user_buddy1 where char_id = v_char_id and buddy_id =p_sender_id;
    IF (v_buddyCheck2 <> 0) THEN
    -- TODO: MANUAL REVIEW NEEDED - GOTO BlockOption_Check_Success
    RETURN;  -- Originally: GOTO BlockOption_Check_Success
    ELSE
    IF (p_sender_guild_id <> 0) THEN
    SELECT guild_id INTO v_receiver_guild_id2 FROM user_data where char_id = v_char_id;
    IF (p_sender_guild_id = v_receiver_guild_id2) THEN
    -- TODO: MANUAL REVIEW NEEDED - GOTO BlockOption_Check_Success
    RETURN;  -- Originally: GOTO BlockOption_Check_Success
    END IF;
    END IF;
    END IF;
    PERFORM 6, v_char_id;
    RETURN;
    END IF;
    END IF;
    END IF;
    -- Label: BlockOption_Check_Success
    SELECT char_id INTO v_tmp FROM user_block where char_id = v_char_id and block_id = p_sender_id::integer;
    IF (v_tmp <>0) THEN
    PERFORM 4, v_char_id;
    RETURN;
    END IF;
    SELECT count(*) INTO v_count FROM user_mail where to_id = v_char_id;
    IF (v_count >= p_max) THEN
    PERFORM 2, v_char_id;
    RETURN;
    END IF;
    IF (p_senderRace = v_recverRace) THEN
    PERFORM 0, v_char_id;
    RETURN;
    ELSE
    PERFORM 3, v_char_id;
    RETURN;
    END IF;
END;
$$;

