-- [WARN] [REVIEW] GM_RestrictedItemDA_SrchInfo
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_restricteditemda_srchinfo(
    p_type varchar(4),
    p_restrict_status varchar(4),
    p_ing varchar(4),
    p_will_be_ing varchar(4),
    p_end varchar(4),
    p_cur_date varchar(30),
    p_name_id varchar(2450),
    p_world_id varchar(5),
    p_view_count varchar(5),
    p_top_count varchar(5),
    p_service_class_type varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
    v_sql_etc varchar(2500);
    v_tmp smallint;
BEGIN
    v_sql_etc := ' ';
    v_tmp := 0;
    IF p_name_id != 'null' THEN
    v_sql_etc := ' and (' || p_name_id || ')  ';
    END IF;
    IF p_ing != 'null' or p_will_be_ing != 'null' or p_end != 'null' THEN
    v_sql_etc := v_sql_etc || ' and (' END IF p_ing != 'null' BEGIN set v_sql_etc = v_sql_etc || ' ((start_date <= ''' || p_cur_date || ''' and end_date is NULL) or (start_date <= ''' || p_cur_date || ''' and end_date is not NULL and end_date >= ''' || p_cur_date || '''))  ' set v_tmp = 1 END IF p_will_be_ing != 'null' BEGIN IF v_tmp = 1 set v_sql_etc = v_sql_etc || ' or ((start_date > ''' || p_cur_date || ''' and end_date is NULL) or (start_date > ''' || p_cur_date || ''' and end_date is not NULL and end_date >= ''' || p_cur_date || '''))  ' else begin set v_sql_etc = v_sql_etc || ' ((start_date > ''' || p_cur_date || ''' and end_date is NULL) or (start_date > ''' || p_cur_date || ''' and end_date is not NULL and end_date >= ''' || p_cur_date || '''))  ' set v_tmp = 1 end END IF p_end != 'null' BEGIN IF v_tmp = 1 set v_sql_etc = v_sql_etc || ' or (end_date is not NULL and end_date < ''' || p_cur_date || ''') ' else begin set v_sql_etc = v_sql_etc || ' (end_date is not NULL and end_date < ''' || p_cur_date || ''') ' end END IF p_ing != 'null' or p_will_be_ing != 'null' or p_end != 'null' BEGIN set v_sql_etc = v_sql_etc || ')';
    END IF;
    IF p_type != 'null' THEN
    v_sql_etc := v_sql_etc || ' and type = ''' || p_type || '''  ';
    END IF;
    IF p_restrict_status != 'null' THEN
    v_sql_etc := v_sql_etc || ' and restrict_status = ''' || p_restrict_status || '''  ';
    END IF;
    IF p_service_class_type != 'null' THEN
    v_sql_etc := v_sql_etc || ' and service_class_type = ''' || p_service_class_type || '''  ';
    END IF;
    v_sql := ' select top ' || p_view_count || ' TO_CHAR(regdate, ''YYYY-MM-DD HH24:MI:SS'') regdate,TO_CHAR(START_DATE, ''YYYY-MM-DD HH24:MI:SS'') START_DATE,TO_CHAR(end_date, ''YYYY-MM-DD HH24:MI:SS'') end_date,id,RESTRICTED_ID,WORLD_ID,SERVICE_TYPE,TYPE,ITEM_NAME_ID,VALUE,RESTRICT_STATUS,LOGIN_ID,LOGIN_NM,UP_INFO,SERVICE_CLASS_TYPE ' || ' from restricted_item ' || ' where (world_id= ''' || p_world_id || ''' or world_id=''0'') and id not in (select top ' || p_top_count || ' id from restricted_item  where  (world_id= ''' || p_world_id || ''' or world_id=''0'') ' || v_sql_etc || ' order by type, item_name_id, service_class_type) ';
    v_sql := v_sql || v_sql_etc;
    v_sql := v_sql || ' order by type, item_name_id, service_class_type ';
    EXECUTE v_sql;
    RETURN;
END;
$$;

