-- [OK] [AUTO] aion_SetCaptchaInfo

CREATE OR REPLACE FUNCTION aion_setcaptchainfo(
    p_nCharId integer,
    p_nProhibitionFlag smallint,
    p_nCount smallint,
    p_nProhibitionTime integer,
    p_nElapsedTime integer,
    p_nFirstGenerationTime integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT char_id FROM user_captcha  WHERE char_id = p_nCharId::integer) THEN
    UPDATE user_captcha SET prohibition_flag=p_nProhibitionFlag, user_captcha.count = p_nCount::integer, prohibition_time=p_nProhibitionTime, elapsed_time=p_nElapsedTime, first_generation_time=p_nFirstGenerationTime WHERE char_id = p_nCharId::integer;
    ELSE
    INSERT INTO user_captcha(char_id, prohibition_flag, user_captcha.count, prohibition_time, elapsed_time, first_generation_time) VALUES (p_nCharId, p_nProhibitionFlag, p_nCount, p_nProhibitionTime, p_nElapsedTime, p_nFirstGenerationTime);
    END IF;
END;
$$;

