-- [OK] [AUTO] aion_MailDelete

CREATE OR REPLACE FUNCTION aion_maildelete(
    p_char_id integer,
    p_mail_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_item_id integer;
    v_state integer;
BEGIN
    SELECT item_id, state INTO v_item_id, v_state FROM user_mail where id = p_mail_id and to_id = p_char_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (v_rowcount = 0) THEN
    PERFORM 1, v_state;
    END IF;
    IF (v_item_id <> 0) THEN
    PERFORM aion_DeleteItem(v_item_id);
    END IF;
    delete from user_mail where id = p_mail_id and to_id = p_char_id;
    PERFORM 0, v_state;
END;
$$;

