-- [OK] [AUTO] GM_UserItemDAO_InsertUpdateFreeTradeState

CREATE OR REPLACE FUNCTION gm_useritemdao_insertupdatefreetradestate(
    p_id bigint,
    p_name_id integer,
    p_freetradestate smallint
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    update user_item_freetrade set freeTradeState=p_freetradestate where id=p_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (0 < v_rowcount) THEN
    RETURN 1;
    ELSE
    IF (p_freetradestate != 0) THEN
    insert into user_item_freetrade (id, name_id, freeTradeState) values (p_id, p_name_id, p_freetradestate);
    ELSE
    RETURN 1;
    END IF;
    END IF;
END;
$$;

