-- [OK] [AUTO] aion_MailGetBoxSize

CREATE OR REPLACE FUNCTION aion_mailgetboxsize(
    p_user_id integer,
    p_now_time integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_total integer;
    v_unread integer;
    v_unreadexpress integer;
    v_unreadcashmail integer;
BEGIN
    SELECT count(*) INTO v_total FROM user_mail where to_id = p_user_id and arrive_time <= p_now_time;
    SELECT count(*) INTO v_unread FROM user_mail where to_id = p_user_id and state = 0 and arrive_time <= p_now_time;
    SELECT count(*) INTO v_unreadexpress FROM user_mail where to_id = p_user_id and state = 0 and express_mail > 0 and arrive_time <= p_now_time;
    SELECT count(*) INTO v_unreadcashmail FROM user_mail where to_id = p_user_id and state = 0 and express_mail = 2 and arrive_time <= p_now_time;
    PERFORM v_total, v_unread, v_unreadexpress, v_unreadcashmail;
END;
$$;

