CREATE OR REPLACE FUNCTION aion_avataraddedservice_type4_movechar_process_ors(
    p_db_userId varchar(64),
    p_db_passwd varchar(64),
    p_fromServer integer,
    p_fromCharId integer,
    p_fromCharName varchar(20),
    p_toServer integer,
    p_toCharId integer,
    p_toCharName varchar(20),
    p_premium integer,
    p_withAccountWarehouse integer,
    p_mileage integer,
    OUT p_newCharId integer,
    OUT p_ret integer
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_rowcount integer := 0;
    v_connectString varchar(256);
    v_serverName varchar(128);
    v_databaseName varchar(64);
    v_db_info varchar(256);
    v_gp_restrict_value integer;
    v_delete_date integer;
    v_sql varchar(4000);
    v_fromCharNameReal varchar(20);
    v_accountId integer;
    v_toCharCountLight integer;
    v_toCharCountDark integer;
    v_fromCharNameChanged integer;
    tmpItem_cursor CURSOR FOR select id from #temp_user_item ;
    v_sum_sold_price bigint;
    v_sum_warehouse_qina bigint;
    v_tmp_house_object_id bigint;
    v_tmp_house_object_new_id bigint;
    tmpHouse_cursor CURSOR FOR select id from #temp_house_object ;
    v_checkUseOrgCharName integer;
    v_avatar_serverType smallint;
    v_avatar_race smallint;
BEGIN
    p_newCharId := 0;
    IF p_toCharId is null THEN
    p_toCharId := 0;
    END IF;
    v_connectString := '';
    v_serverName := '';
    v_databaseName := '';
    SELECT datasource, database_name INTO v_serverName, v_databaseName FROM AionAddedService_Servername where server_id = p_fromServer::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    p_ret := -10104;
    RETURN;
    END IF;
    v_db_info := '''' || v_serverName || ''';''' || p_db_userId || ''';''' || p_db_passwd || '''';
    v_gp_restrict_value := (select value from (SELECT  item_name_id, value , world_id from restricted_item where RESTRICT_STATUS = 1 and service_type in (0,2) and type = 6 and world_id in (0, p_toServer) and service_class_type = p_premium and start_date <= CURRENT_TIMESTAMP and (end_date is null or CURRENT_TIMESTAMP < end_date) order by world_id desc LIMIT 1) as b);
    v_delete_date := GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0);
    IF p_toCharId <> 0 THEN
    UPDATE user_data SET delete_date = v_delete_date, delete_complete_date = v_delete_date, delete_type	= 10000 where char_id = p_toCharId::integer;
    IF 0 /* @v_ERROR */ <> 0 THEN
    p_ret := -11001;
    RETURN;
    END IF;
    END IF;
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name IN ('temp_item_index_change_info')) THEN
    drop table temp_item_index_change_info;
    END IF;
    CREATE TABLE temp_item_index_change_info ( old_id bigint, new_id bigint, name_id int );
    v_accountId := 0;
    v_sql := 'select v_fromCharNameReal = user_id, v_accountId = account_id ' || 'from openrowset (''SQLOLEDB'', ' || v_db_info || ',' || '''select user_id, account_id, race from ' || v_databaseName || '.user_data where char_id = ' || CAST(p_fromCharId AS varchar) || ''') ';
    EXECUTE v_sql, 'v_fromCharNameReal nvarchar(20) output, v_accountId int output', v_fromCharNameReal output, v_accountId output;
    IF 0 /* @v_ERROR */ <> 0 or v_fromCharNameReal is null THEN
    p_ret := -11002;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN;  -- Originally: GOTO error_process
    END IF;
    SELECT COUNT(char_id) INTO v_toCharCountLight WHERE account_id = v_accountId and delete_complete_date = 0 and delete_date = 0 and race = 0;
    SELECT COUNT(char_id) INTO v_toCharCountDark FROM user_data where account_id = v_accountId and delete_complete_date = 0 and delete_date = 0 and race = 1;
    IF v_fromCharNameReal <> p_fromCharName THEN
    v_fromCharNameChanged := 0;
    v_sql := 'select v_fromCharNameChanged = id ' || 'from openrowset (''SQLOLEDB'', ' || v_db_info || ',' || '''select id from ' || v_databaseName || '.user_name_change_log where char_id = ' || CAST(p_fromCharId AS varchar) || ' and old_name = ''''' || p_fromCharName || '''''  '') ';
    EXECUTE v_sql, 'v_fromCharNameChanged int output', v_fromCharNameChanged output;
    IF v_fromCharNameChanged = 0 THEN
    p_ret := -11002;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN;  -- Originally: GOTO error_process
    END IF;
    END IF;
    IF p_toCharName is null THEN
    p_toCharName := v_fromCharNameReal;
    END IF;
    v_sql := 'INSERT user_data (' || 'user_id,' || 'account_id,' || 'account_name,' || 'race,' || 'class,' || 'is_banned,' || 'gender,' || 'head_face_color,' || 'head_hair_color,' || 'head_face_type,' || 'head_hair_type,' || 'name_id,' || 'guild_id,' || 'guild_rank,' || 'guild_intro,' || 'guild_nickname,' || 'recreate_guild_time,' || 'org_server,' || 'cur_server,' || 'world,' || 'xlocation,' || 'ylocation,' || 'zlocation,' || 'dir,' || 'last_normal_world,' || 'last_normal_xlocation,' || 'last_normal_ylocation,' || 'last_normal_zlocation,' || 'last_normal_dir,' || 'death_count,' || 'temporary_lost_exp,' || 'resurrect_world,' || 'resurrect_xlocation,' || 'resurrect_ylocation,' || 'resurrect_zlocation,' || 'builder,' || 'now_hit,' || 'now_mana,' || 'exp,' || 'abyss_point,' || 'lev,' || 'stigmaPoint,' || 'event,' || 'create_date,' || 'petition_msg,' || 'jobfaction_id,' || 'jobfaction_rank,' || 'jobfaction_friendship,' || 'npcfaction_id,' || 'npcfaction_rank,' || 'cur_title_id,' || 'last_login_time,' || 'last_logout_time,' || 'playtime,' || 'fly_gauge,' || 'max_fly_gauge,' || 'fly_cool_time,' || 'delete_date,' || 'inventory_growth,' || 'char_warehouse_growth,' || 'cur_title_attr_id,' || 'daily_comment ' || ') ' || 'select ' || 'CAST(f.org_server AS varchar(4)) || ''s'' || replace(ltrim(replace(replace(upper(encode(f.char_id)), ''0'', '' ''), ''X'', '' '')), '' '', ''0''),' || 'f.account_id,' || 'f.account_name,' || 'f.race,' || 'f.class,' || 'f.is_banned,' || 'f.gender,' || 'f.head_face_color,' || 'f.head_hair_color,' || 'f.head_face_type,' || 'f.head_hair_type,' || 'f.name_id,' || '0, 0, '''', '''',' || 'f.recreate_guild_time,' || CAST(p_toServer AS varchar) || ',' || CAST(p_toServer AS varchar) || ',' || 'f.world,' || 'f.xlocation,' || 'f.ylocation,' || 'f.zlocation,' || 'f.dir,' || 'f.last_normal_world,' || 'f.last_normal_xlocation,' || 'f.last_normal_ylocation,' || 'f.last_normal_zlocation,' || 'f.last_normal_dir,' || 'f.death_count,' || 'f.temporary_lost_exp,' || 'f.resurrect_world,' || 'f.resurrect_xlocation,' || 'f.resurrect_ylocation,' || 'f.resurrect_zlocation,' || 'f.builder,' || 'f.now_hit,' || 'f.now_mana,' || 'f.exp,' || 'f.abyss_point,' || 'f.lev,' || 'f.stigmaPoint,' || 'f.event,' || 'f.create_date,' || 'f.petition_msg,' || 'f.jobfaction_id,' || 'f.jobfaction_rank,' || 'f.jobfaction_friendship,' || 'f.npcfaction_id,' || 'f.npcfaction_rank,' || 'f.cur_title_id,' || 'f.last_login_time,' || 'f.last_logout_time,' || 'f.playtime,' || 'f.fly_gauge,' || 'f.max_fly_gauge,' || 'f.fly_cool_time,' || 'f.delete_date,' || 'f.inventory_growth,' || 'f.char_warehouse_growth,' || 'f.cur_title_attr_id,' || 'f.daily_comment ' || 'from openrowset (''SQLOLEDB'', ' || v_db_info || ',' || '''select * from ' || v_databaseName || '.user_data where char_id = ' || CAST(p_fromCharId AS varchar) || ''') as f';
    EXECUTE v_sql;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF 0 /* @v_ERROR */ <> 0	or v_rowcount = 0 THEN
    p_ret := -11002;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN;  -- Originally: GOTO error_process
