-- [OK] [AUTO] sp_whale_fall_execute

CREATE OR REPLACE FUNCTION sp_whale_fall_execute(
    p_char_id integer,
    p_force_mode varchar(20) DEFAULT NULL
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_race smallint;
    v_level integer;
    v_death_count integer;
    v_char_name varchar(64);
    v_account_id integer;
    v_fall_mode varchar(20);
    v_broker_price bigint := 1;
    v_commit_date integer;
    v_total_items integer := 0;
    v_log_id bigint;
    v_exclude_bound boolean := 1;
    v_killer_char_id integer := NULL;
    v_killer_name varchar(64) := NULL;
    v_killer_timeout integer := 5;
BEGIN
    SELECT COALESCE(p_force_mode, config_value) INTO v_fall_mode FROM whale_fall_config WHERE config_name = 'fall_mode';
    SELECT CAST(config_value AS bigint) INTO v_broker_price FROM whale_fall_config WHERE config_name = 'broker_price';
    SELECT CAST(config_value AS boolean) INTO v_exclude_bound FROM whale_fall_config WHERE config_name = 'exclude_bound_items';
    SELECT CAST(config_value AS integer) INTO v_killer_timeout FROM whale_fall_config WHERE config_name = 'killer_timeout_minutes';
    v_commit_date := EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - ('1970-01-01')::timestamp)::integer;
    SELECT race, lev, death_count, account_id INTO v_race, v_level, v_death_count, v_account_id FROM user_data WHERE char_id = p_char_id::integer;
    SELECT cn.name INTO v_char_name FROM character_name cn JOIN user_data ud ON cn.name_id = ud.name_id WHERE ud.char_id = p_char_id::integer;
    IF v_race IS NULL THEN
        RETURN -1;
    END IF;
    IF v_fall_mode = 'KILLER' THEN
    SELECT killer_char_id, killer_name INTO v_killer_char_id, v_killer_name FROM whale_fall_kill_record WHERE victim_char_id = p_char_id AND (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (kill_time)::timestamp) / 60)::integer <= v_killer_timeout ORDER BY kill_time DESC LIMIT 1;
    IF v_killer_char_id IS NULL SET v_fall_mode = 'BROKER' THEN
    END IF;
    INSERT INTO whale_fall_log (char_id, char_name, account_id, race, level, death_count, fall_mode, killer_char_id, killer_name, total_items, total_value) VALUES (p_char_id, v_char_name, v_account_id, v_race, v_level, v_death_count, v_fall_mode, v_killer_char_id, v_killer_name, 0, 0);
    END IF;
    v_log_id := LASTVAL();
    CREATE TEMP TABLE items (user_item_id BIGINT, name_id INT, amount BIGINT);
    INSERT INTO items SELECT ui.id, ui.name_id, ui.amount FROM user_item ui WHERE ui.char_id = p_char_id::integer AND ui.warehouse IN (0, 1);
    IF v_exclude_bound = 1 DELETE t FROM #items t WHERE EXISTS (SELECT 1 FROM user_item_bind b WHERE b.item_id = t.user_item_id) THEN
    SELECT COUNT(*) INTO v_total_items FROM #items;
    END IF;
    IF v_fall_mode = 'BROKER' THEN
    IF v_race = 0 THEN
    INSERT INTO vendor_item_light (char_id, user_item_id, user_price, sale_price, commit_amount, remain_amount, commit_date, can_buy_partial, afterUnitFee, afterUnitTax) SELECT p_char_id, user_item_id, v_broker_price, v_broker_price, amount, amount, v_commit_date, 1, 0, 0 FROM items;
    ELSE
    INSERT INTO vendor_item_dark (char_id, user_item_id, user_price, sale_price, commit_amount, remain_amount, commit_date, can_buy_partial, afterUnitFee, afterUnitTax) SELECT p_char_id, user_item_id, v_broker_price, v_broker_price, amount, amount, v_commit_date, 1, 0, 0 FROM items;
    END IF;
    INSERT INTO whale_fall_items (log_id, char_id, user_item_id, item_name_id, amount, destination, price) SELECT v_log_id, p_char_id, user_item_id, name_id, amount, CASE v_race WHEN 0 THEN 'BROKER_LIGHT' ELSE 'BROKER_DARK' END, v_broker_price FROM items;
    ELSIF v_fall_mode = 'KILLER' THEN
    UPDATE ui SET ui.char_id = v_killer_char_id, ui.warehouse = 0, ui.update_date = CURRENT_TIMESTAMP FROM user_item ui JOIN items t ON ui.id = t.user_item_id;
    INSERT INTO whale_fall_items (log_id, char_id, user_item_id, item_name_id, amount, destination, dest_char_id) SELECT v_log_id, p_char_id, user_item_id, name_id, amount, 'KILLER', v_killer_char_id FROM items;
    ELSIF v_fall_mode = 'DESTROY' THEN
    INSERT INTO whale_fall_items (log_id, char_id, user_item_id, item_name_id, amount, destination) SELECT v_log_id, p_char_id, user_item_id, name_id, amount, 'DESTROYED' FROM items;
    DELETE FROM ui FROM user_item ui JOIN items t ON ui.id = t.user_item_id;
    END IF;
    UPDATE whale_fall_log SET total_items = v_total_items, total_value = v_total_items * v_broker_price WHERE log_id = v_log_id;
    DROP TABLE IF EXISTS items;
    UPDATE user_data SET delete_date = EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - ('1970-01-01')::timestamp)::integer, CASE AS delete_type v_fall_mode WHEN 'BROKER' THEN 101 WHEN 'KILLER' THEN 102 WHEN 'DESTROY' THEN 103 ELSE 100 END WHERE char_id = p_char_id::integer;
    RETURN v_total_items;
END;
$$;

