-- [WARN] [REVIEW] aion_MailGetItem
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION

CREATE OR REPLACE FUNCTION aion_mailgetitem(
    p_char_id integer,
    p_mail_id integer,
    p_warehouse integer,
    p_flag integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_item_id bigint;
    v_money bigint;
    v_ap bigint;
BEGIN
    v_item_id := 0;
    v_money := 0;
    v_ap := 0;
    -- Transaction managed by PG function context
    SELECT item_id, money, abyss_point INTO v_item_id, v_money, v_ap FROM user_mail where id = p_mail_id and to_id = p_char_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (v_rowcount = 0) THEN
    PERFORM v_item_id, v_money, v_ap;
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    END IF;
    IF (p_flag = 0) THEN
    IF (v_item_id = 0) THEN
    PERFORM v_item_id, v_money, v_ap;
    RAISE EXCEPTION 'Rollback requested';
    RETURN 2;
    ELSIF (p_flag = 1) THEN
    IF (v_money = 0) THEN
    PERFORM v_item_id, v_money, v_ap;
    RAISE EXCEPTION 'Rollback requested';
    RETURN 2;
    ELSIF (p_flag = 2) THEN
    IF (v_ap = 0) THEN
    PERFORM v_item_id, v_money, v_ap;
    RAISE EXCEPTION 'Rollback requested';
    RETURN 2;
    END IF;
    END IF;
    IF (p_flag = 0) THEN
    update user_item set warehouse = p_warehouse::integer where id = v_item_id;
    update user_mail set item_id = 0, item_nameid = 0, item_amount = 0 where id = p_mail_id;
    ELSIF (p_flag = 1) THEN
    update user_mail set money = 0 where id = p_mail_id;
    ELSIF (p_flag = 2) THEN
    update user_mail set abyss_point = 0 where id = p_mail_id;
    END IF;
    PERFORM v_item_id, v_money, v_ap;
    -- COMMIT (implicit in PG function)
    RETURN 0;
END;
$$;

