-- [OK] [AUTO] GM_UserItemDAO_InsertUpdateSealedItem

CREATE OR REPLACE FUNCTION gm_useritemdao_insertupdatesealeditem(
    p_id bigint,
    p_sealExpiredTime integer,
    p_sealState smallint,
    p_char_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
