-- [OK] [AUTO] aion_BlockOfflineBuddy

CREATE OR REPLACE FUNCTION aion_blockofflinebuddy(
    p_charId integer,
    p_inviterId integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_result integer;
    v_blockcount integer;
BEGIN
    IF EXISTS (select buddy_id from user_buddy1 where char_id = p_charId::integer and  buddy_id = p_inviterId and delete_flag = 0) THEN
    RETURN 4;
    END IF;
    IF EXISTS (select block_id from user_block where char_id = p_charId::integer and block_id = p_inviterId::integer) THEN
    RETURN 0;
    END IF;
    SELECT COUNT(*) INTO v_blockcount FROM user_block where char_id = p_charId::integer;
    IF (v_blockcount >= 200) THEN
    RETURN 3;
    END IF;
    insert into user_block (char_id, block_id, comment) values (p_charId, p_inviterId, '');
    RETURN 0;
END;
$$;

