    p_nStatus smallint,
    p_nCompleteCnt smallint,
    p_nLastCompleteTime integer,
    p_nRepeat smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_nRepeat=1 THEN
    Update challenge_task Set status = p_nStatus::integer, complete_count=p_nCompleteCnt, last_complete_time=p_nLastCompleteTime Where id=p_nTaskDbId;
    Update challenge_task_quest Set complete_count=0 Where challenge_task_id=p_nTaskDbId;
    Update challenge_task_contributor Set score=0 Where challenge_task_id=p_nTaskDbId;
    ELSE
    Update challenge_task Set status = p_nStatus::integer, complete_count=p_nCompleteCnt, last_complete_time=p_nLastCompleteTime Where id=p_nTaskDbId;
    END IF;
END;
$$;

