-- [WARN] [REVIEW] GM_UserItemDAO_RegacyRecovery
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_useritemdao_regacyrecovery(
    p_char_id varchar(20)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_sql varchar(2000);
    v_rs_item_legacy varchar(10);
BEGIN
    SELECT item_legacy INTO v_rs_item_legacy FROM user_data where char_id = p_char_id::integer;
    IF v_rs_item_legacy != '0' THEN
    set IDENTITY_INSERT user_item on;
    v_sql := 'insert into user_item(id, char_id, name_id, slot_id, amount,slot,warehouse,soul_bound,enchant_count,skin_name_id,stat_enchant_0, stat_enchant_val0, stat_enchant_1, stat_enchant_val1,stat_enchant_2, stat_enchant_val2, stat_enchant_3, stat_enchant_val3,stat_enchant_4, stat_enchant_val4, stat_enchant_5, stat_enchant_val5,dye_info, proc_tool_nameid, create_date, update_date, producer,tid, expired_time, option_count, buy_amount, buy_duration,obtain_skin_type, expire_skin_time, main_item_dbid, dynamic_property) select id, char_id, name_id, slot_id, amount,slot,warehouse,soul_bound,enchant_count,skin_name_id,stat_enchant_0, stat_enchant_val0, stat_enchant_1, stat_enchant_val1,stat_enchant_2, stat_enchant_val2, stat_enchant_3, stat_enchant_val3,stat_enchant_4, stat_enchant_val4, stat_enchant_5, stat_enchant_val5,dye_info, proc_tool_nameid, create_date, update_date, producer,tid, expired_time, option_count, buy_amount, buy_duration,obtain_skin_type, expire_skin_time, main_item_dbid, dynamic_property from user_item_legacy_' || v_rs_item_legacy || ' where char_id=' || p_char_id;
    EXECUTE v_sql;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount > 0 THEN
    v_sql := 'delete from user_item_legacy_' || v_rs_item_legacy || ' where char_id=' || p_char_id;
    EXECUTE v_sql;
    END IF;
    set IDENTITY_INSERT user_item off;
    END IF;
END;
$$;

