-- [WARN] [REVIEW] aion_MailRestoreItem
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION

CREATE OR REPLACE FUNCTION aion_mailrestoreitem(
    p_char_id integer,
    p_mail_id integer,
    p_item_id bigint
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_name_id integer;
    v_item_amount integer;
BEGIN
    -- Transaction managed by PG function context
    SELECT name_id, amount INTO v_name_id, v_item_amount FROM user_item where id = p_item_id and char_id = p_char_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (v_rowcount = 0) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    END IF;
    update user_item set warehouse = 5 where id=p_item_id and char_id = p_char_id::integer;
    -- COMMIT (implicit in PG function)
    update user_mail set item_id = p_item_id::integer, item_nameid = v_name_id, item_amount = v_item_amount  where id = p_mail_id;
    RETURN 0;
END;
$$;

