    UPDATE user_item SET amount = amount - p_useditem_amount where id = (SELECT  id WHERE char_id = p_char_id::integer and warehouse = p_warehouse::integer and name_id=p_useditem_nameid and amount >= p_useditem_amount::integer order by id desc LIMIT 1);
