-- [OK] [AUTO] GM_UserBuddyDA_SrchMyBuddy

CREATE OR REPLACE FUNCTION gm_userbuddyda_srchmybuddy(
    p_char_id varchar(20),
    p_world_id varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    PERFORM	0 is_what, t2.delete_date, t2.char_id, t2.user_id, t2.account_id, t2.account_name, t2.org_server, t2.cur_server, COALESCE(t2.login_server, t2.org_server) login_server, TO_CHAR(t2.create_date, 'YYYY-MM-DD HH24:MI:SS') create_date, CAST(t2.gender AS char) gender, CAST(t2.race AS char) race, CAST(t2.class AS char) class, CAST(t2.lev AS char) lev, CAST(t2.builder AS char) builder, t2.world, case WHEN t2.last_login_time = t2.last_logout_time and t2.last_login_time != '1970-01-01 00:00:00.000' and t2.last_logout_time > '2007-12-12 00:00:00.000' THEN '339900' WHEN t2.last_login_time != t2.last_logout_time or t2.last_login_time = '1970-01-01 00:00:00.000'  THEN 'brown' WHEN t2.last_login_time = t2.last_logout_time and t2.last_login_time != '1970-01-01 00:00:00.000' THEN AS black;
    end as logonoff , COALESCE(comment, '') as comment from	user_buddy1 t1, user_data t2 where	t1.char_id = p_char_id::integer and t2.org_server=p_world_id and		t1.buddy_id=t2.char_id union all select	1 is_what, t2.delete_date, t2.char_id, t2.user_id, t2.account_id, t2.account_name, t2.org_server, t2.cur_server, COALESCE(t2.login_server, t2.org_server) login_server, TO_CHAR(t2.create_date, 'YYYY-MM-DD HH24:MI:SS') create_date, CAST(t2.gender AS char) gender, CAST(t2.race AS char) race, CAST(t2.class AS char) class, CAST(t2.lev AS char) lev, CAST(t2.builder AS char) builder, t2.world, case WHEN t2.last_login_time = t2.last_logout_time and t2.last_login_time != '1970-01-01 00:00:00.000' and t2.last_logout_time > '2007-12-12 00:00:00.000' THEN '339900' WHEN t2.last_login_time != t2.last_logout_time or t2.last_login_time = '1970-01-01 00:00:00.000'  THEN 'brown' WHEN t2.last_login_time = t2.last_logout_time and t2.last_login_time != '1970-01-01 00:00:00.000' THEN AS black;
    end as logonoff , COALESCE(comment, '') as comment from	user_block t1, user_data t2 where	t1.char_id = p_char_id::integer and t2.org_server =p_world_id and		t1.block_id=t2.char_id;
END;
$$;

