-- [OK] [AUTO] aion_GetCharGlobalRankPoint_byClass

CREATE OR REPLACE FUNCTION aion_getcharglobalrankpoint_byclass(
    p_rankId integer,
    p_class integer
) RETURNS bigint
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    PERFORM  a.point, a.global_ranking, a.global_old_ranking, a.char_id, b.race, b.class, b.user_id from user_rank as a, user_data as b where a.char_id = b.char_id and b.delete_complete_date = 0 and a.rank_id = p_rankId and a.point > 0 and b.class = p_class::integer order by a.point desc LIMIT 300;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    RETURN v_rowcount;
END;
$$;

