-- [OK] [AUTO] aion_SetNpcGoodsInfo

CREATE OR REPLACE FUNCTION aion_setnpcgoodsinfo(
    p_world_no integer,
    p_merchant_nameid integer,
    p_goods_list_no smallint,
    p_goods_nameid integer,
    p_sold_count bigint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (select world_no from npc_goods_info where world_no=p_world_no and merchant_nameid=p_merchant_nameid and goods_list_no=p_goods_list_no and goods_nameid=p_goods_nameid) THEN
    update npc_goods_info set sold_count=p_sold_count where world_no=p_world_no and merchant_nameid=p_merchant_nameid and goods_list_no=p_goods_list_no	and goods_nameid=p_goods_nameid;
    ELSE
    INSERT INTO npc_goods_info(world_no, merchant_nameid, goods_list_no, goods_nameid, sold_count) values	(p_world_no, p_merchant_nameid, p_goods_list_no, p_goods_nameid, p_sold_count);
    END IF;
END;
$$;

