    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF 0 /* @v_ERROR */ <> 0 or v_rowcount = 0 THEN
    v_ret := -4;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN NULL;  -- Originally: GOTO error_process
    END IF;
    v_change_log_id := LASTVAL();
    v_forbidden_id := 0;
    insert into forbidden_char ( FORBIDDEN_TYPE, FORBIDDEN_REASON, WORLD_ID, FORBIDDEN_CHAR, FORBIDDEN_ACCOUNT_NM, STATUS, LOGIN_ID, LOGIN_NM, REGDATE) values(1, 4, p_nServerID, p_strOldName, p_strAccount, 0, 'UseItem', 'ChangeCharName', CURRENT_TIMESTAMP);
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF 0 /* @v_ERROR */ <> 0	or v_rowcount = 0 THEN
    v_ret := -5;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN NULL;  -- Originally: GOTO error_process
    END IF;
    v_forbidden_id := LASTVAL();
    UPDATE user_data SET 	user_id = p_strNewName::integer, change_info_time = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) WHERE char_id = p_nCharID::integer;
    IF 0 /* @v_ERROR */ <> 0 THEN
    v_ret := -6;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN NULL;  -- Originally: GOTO error_process
    END IF;
    RETURN p_nCharID;
    -- Label: error_process
    IF v_change_log_id <> 0 THEN
    DELETE FROM user_name_change_log where id = v_change_log_id;
    END IF;
