-- [OK] [AUTO] aion_GetCharGlobalRankPoint_byRating

CREATE OR REPLACE FUNCTION aion_getcharglobalrankpoint_byrating(
    p_rateId integer
) RETURNS bigint
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    PERFORM  CAST(c.mu AS integer), COALESCE(a.global_ranking, 0), COALESCE(a.global_old_ranking, 0), c.char_id, b.race, b.class, b.user_id from user_rate as c left join user_rank as a on c.char_id = a.char_id and a.rank_id = p_rateId join user_data as b on c.char_id = b.char_id where c.rate_id = p_rateId::integer and b.delete_complete_date = 0 and c.update_cnt >= 5 order by c.mu desc LIMIT 3000;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    RETURN v_rowcount;
END;
$$;

