-- [OK] [AUTO] GM_UserItemDAO_UpdateItem

CREATE OR REPLACE FUNCTION gm_useritemdao_updateitem(
    p_id bigint,
    p_char_id integer,
    p_amount bigint,
    p_warehouse smallint,
    p_enchant_count smallint,
    p_stat_enchant_name0 integer,
    p_stat_enchant_name1 integer,
    p_stat_enchant_name2 integer,
    p_stat_enchant_name3 integer,
    p_stat_enchant_name4 integer,
    p_stat_enchant_name5 integer,
    p_option_count smallint,
    p_dye_info integer,
    p_proc_tool_nameid integer,
    p_skin_name_id integer,
    p_random_option integer,
    p_authorize_count smallint,
    p_vanish_point integer,
    p_exceedState smallint,
    p_exceedSkillId1 integer,
    p_exceedSkillId2 integer,
    p_exceedSkillId3 integer,
    p_baseSkillId integer,
    p_enhanceSkillGroup integer,
    p_enhanceSkillLevel integer,
    p_equipLevelDown integer,
    p_randomAttr1 integer,
    p_randomValue1 integer,
    p_randomAttr2 integer,
    p_randomValue2 integer,
    p_randomAttr3 integer,
    p_randomValue3 integer,
    p_randomAttr4 integer,
    p_randomValue4 integer,
    p_randomAttr5 integer,
    p_randomValue5 integer,
    p_randomAttr6 integer,
    p_randomValue6 integer,
    p_randomAttr7 integer,
    p_randomValue7 integer,
    p_randomAttr8 integer,
    p_randomValue8 integer,
    p_randomAttr9 integer,
    p_randomValue9 integer,
    p_randomAttr10 integer,
    p_randomValue10 integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    UPDATE	user_item SET		amount = p_amount::integer , warehouse = p_warehouse::integer WHERE	id = p_id and char_id = p_char_id::integer;
    UPDATE	user_item_option SET		enchant_count			= p_enchant_count , stat_enchant_name0	= p_stat_enchant_name0 , stat_enchant_name1	= p_stat_enchant_name1 , stat_enchant_name2	= p_stat_enchant_name2 , stat_enchant_name3	= p_stat_enchant_name3 , stat_enchant_name4	= p_stat_enchant_name4 , stat_enchant_name5	= p_stat_enchant_name5 , option_count			= p_option_count , dye_info				= p_dye_info , proc_tool_nameid		= p_proc_tool_nameid , skin_name_id			= p_skin_name_id , random_option			= p_random_option , authorize_count		= p_authorize_count , vanish_point			= p_vanish_point , exceedState			= p_exceedState , exceedSkillId1		= p_exceedSkillId1 , exceedSkillId2		= p_exceedSkillId2 , exceedSkillId3		= p_exceedSkillId3 , baseSkillId			= p_baseSkillId , enhanceSkillGroup		= p_enhanceSkillGroup , enhanceSkillLevel		= p_enhanceSkillLevel , equipLevelDown		= p_equipLevelDown , randomAttr1			= p_randomAttr1, randomValue1			= p_randomValue1 , randomAttr2			= p_randomAttr2, randomValue2			= p_randomValue2 , randomAttr3			= p_randomAttr3, randomValue3			= p_randomValue3 , randomAttr4			= p_randomAttr4, randomValue4			= p_randomValue4 , randomAttr5			= p_randomAttr5, randomValue5			= p_randomValue5 , randomAttr6			= p_randomAttr6, randomValue6			= p_randomValue6 , randomAttr7			= p_randomAttr7, randomValue7			= p_randomValue7 , randomAttr8			= p_randomAttr8, randomValue8			= p_randomValue8 , randomAttr9			= p_randomAttr9, randomValue9			= p_randomValue9 , randomAttr10			= p_randomAttr10, randomValue10			= p_randomValue10 WHERE	id = p_id and char_id = p_char_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    INSERT INTO user_item_option (id, char_id, enchant_count, skin_name_id, soul_bound, stat_enchant_name0, stat_enchant_name1, stat_enchant_name2, stat_enchant_name3, stat_enchant_name4, stat_enchant_name5, option_count, dye_info, proc_tool_nameid, obtain_skin_type, expire_skin_time, expire_dye_time, random_option, authorize_count, vanish_point , exceedState, exceedSkillId1, exceedSkillId2, exceedSkillId3, baseSkillId, enhanceSkillGroup, enhanceSkillLevel, equipLevelDown , randomAttr1, randomValue1, randomAttr2, randomValue2, randomAttr3, randomValue3, randomAttr4, randomValue4, randomAttr5, randomValue5 , randomAttr6, randomValue6, randomAttr7, randomValue7, randomAttr8, randomValue8, randomAttr9, randomValue9, randomAttr10, randomValue10) VALUES	(p_id, p_char_id, p_enchant_count, p_skin_name_id, 0, p_stat_enchant_name0, p_stat_enchant_name1, p_stat_enchant_name2, p_stat_enchant_name3, p_stat_enchant_name4, p_stat_enchant_name5, p_option_count, p_dye_info, p_proc_tool_nameid, 0, 0, 0, p_random_option, p_authorize_count, p_vanish_point , p_exceedState, p_exceedSkillId1, p_exceedSkillId2, p_exceedSkillId3, p_baseSkillId, p_enhanceSkillGroup, p_enhanceSkillLevel, p_equipLevelDown , p_randomAttr1, p_randomValue1, p_randomAttr2, p_randomValue2, p_randomAttr3, p_randomValue3, p_randomAttr4, p_randomValue4, p_randomAttr5, p_randomValue5 , p_randomAttr6, p_randomValue6, p_randomAttr7, p_randomValue7, p_randomAttr8, p_randomValue8, p_randomAttr9, p_randomValue9, p_randomAttr10, p_randomValue10);
    END IF;
END;
$$;

