-- [OK] [AUTO] aion_SetPetitionMsg

CREATE OR REPLACE FUNCTION aion_setpetitionmsg(
    p_nCharId integer,
    p_nPetSvId integer,
    p_nLocalSv integer,
    p_sPetMsg varchar(1024)
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_nPetSvId = p_nLocalSv THEN
    UPDATE user_data SET petition_msg = p_sPetMsg WHERE char_id = p_nCharId::integer;
    ELSE
    IF EXISTS (SELECT id FROM user_petition_msg WHERE char_id = p_nCharId::integer AND petition_sv_id = p_nPetSvId) THEN
    UPDATE user_petition_msg SET msg = p_sPetMsg WHERE char_id = p_nCharId::integer AND petition_sv_id = p_nPetSvId;
    ELSE
    INSERT INTO user_petition_msg VALUES (p_nCharId, p_nPetSvId, p_sPetMsg);
    END IF;
    END IF;
END;
$$;

