-- [OK] [AUTO] aion_MailWrite_20160804

CREATE OR REPLACE FUNCTION aion_mailwrite_20160804(
    p_to_id integer,
    p_to_name varchar(20),
    p_from_id integer,
    p_from_name varchar(20),
    p_title varchar(20),
    p_content varchar(1000),
    p_item_id bigint,
    p_item_nameid integer,
    p_item_amount bigint,
    p_money bigint,
    p_abyss_point bigint,
    p_warehouse integer,
    p_arrive_time integer,
    p_express_mail integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF (p_item_id <> 0) THEN
    update user_item set warehouse = p_warehouse::integer, char_id = p_to_id::integer where id = p_item_id and char_id = p_from_id::integer;
    update user_item_option set char_id = p_to_id::integer where id = p_item_id and char_id = p_from_id::integer;
    END IF;
    insert into user_mail (to_id, to_name, from_id, from_name, title, content, item_id, item_nameid, item_amount, money, abyss_point, arrive_time, express_mail) values (p_to_id, p_to_name, p_from_id, p_from_name, p_title, p_content, p_item_id, p_item_nameid, p_item_amount, p_money, p_abyss_point, p_arrive_time, p_express_mail);
END;
$$;

