    p_char_id integer,
    p_used_money bigint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    update user_item set amount = amount + p_used_money where char_id = p_char_id::integer and warehouse=0 and name_id=182400001;
END;
$$;

