-- [OK] [AUTO] aion_SetCharEXPS_RewardTime

CREATE OR REPLACE FUNCTION aion_setcharexps_rewardtime(
    p_charId integer,
    p_rewardTime integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF not EXISTS (select char_id from user_data_ext where char_id = p_charId::integer) THEN
    insert into user_data_ext (char_id, exps_login_reward_time, exps_npckill_reward_num) values(p_charId, p_rewardTime, 0);
    ELSE
    UPDATE user_data_ext SET exps_login_reward_time = p_rewardTime, exps_npckill_reward_num = 0 where char_id = p_charId::integer;
    END IF;
END;
$$;

