CREATE OR REPLACE FUNCTION aion_getkinaasset(
    p_nCharacterId integer,
    p_nAccountId integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT  warehouse, amount FROM user_item WHERE char_id = p_nCharacterId::integer and name_id = 182400001 and warehouse = 0 UNION SELECT  warehouse, amount FROM user_item WHERE char_id = p_nAccountId::integer and name_id = 182400001 and (warehouse = 6 OR warehouse = 7) LIMIT 1;
END;
$$;

