CREATE OR REPLACE FUNCTION gm_useritemdao_updatewarehousedeleteditem(
    p_char_id integer,
    p_db_id bigint,
    p_warehouse smallint,
    OUT p_returnValue integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_error integer;
BEGIN
    p_returnValue := 0;
    UPDATE user_item SET warehouse = p_warehouse::integer where id=p_db_id and char_id = p_char_id::integer and warehouse=10;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    v_error := 0 /* @v_ERROR */;
    v_rowCount := v_rowcount;
    IF v_error <> 0 OR v_rowCount < 1 THEN
    RETURN;
    END IF;
    p_returnValue := 1;
    RETURN;
END;
$$;

