-- [OK] [AUTO] GM_UserChatAccusedDA_Srch

CREATE OR REPLACE FUNCTION gm_userchataccusedda_srch(
    p_top_count integer,
    p_page_num integer,
    p_user_id varchar(30),
    p_account_name varchar(30),
    p_account_id integer,
    p_char_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_query varchar(2000);
    v_where varchar(1000);
BEGIN
    IF (p_char_id != 0) THEN
    v_where := 'u.char_id = ' || CAST(p_char_id AS varchar);
    ELSE
    v_where := '0 < c.penalty_start_time';
    IF (COALESCE(p_user_id, '') != '') THEN
    v_where := v_where || ' and u.user_id = ''' || p_user_id || ''' ';
    END IF;
    IF (COALESCE(p_account_name, '') != '') THEN
    v_where := v_where || ' and u.account_name = ''' || p_account_name || ''' ';
    END IF;
    IF (p_account_id != 0) THEN
    v_where := v_where || ' and u.account_id = ' || CAST(p_account_id AS varchar);
    END IF;
    END IF;
    v_query := 'SELECT TOP (' || CAST(p_top_count AS varchar) || ') ' || ' u.char_id, u.user_id, u.account_id, u.account_name, u.org_server, ' || ' c.accused_count, c.penalty_start_time, c.accused_count_penalty, c.last_accused_time ' || ' FROM	user_chat_accused c  ' || ' JOIN	user_data u  ON u.char_id = c.char_id ' || ' WHERE ' || v_where || ' AND		u.char_id NOT IN (SELECT /*INLINE_LIMIT:' || CAST(p_top_count * (p_page_num-1*/ AS varchar) || ') u.char_id ' || '								FROM	user_chat_accused c  ' || '								JOIN	user_data u  ON u.char_id = c.char_id ' || ' 							WHERE ' || v_where || ' 							ORDER BY u.char_id ) ' || ' ORDER BY u.char_id ' || 'SELECT	COUNT(*) as total ' || ' FROM	user_chat_accused c  ' || ' JOIN	user_data u  ON u.char_id = c.char_id ' || ' WHERE ' || v_where;
    EXECUTE v_query;
END;
$$;

