-- [OK] [AUTO] aion_SetCharGlobalRank_SeasonRank

CREATE OR REPLACE FUNCTION aion_setcharglobalrank_seasonrank(
    p_rankId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE user_rank SET last_ranking = global_ranking, last_point = point WHERE rank_id = p_rankId;
    UPDATE user_rank SET best_ranking = last_ranking WHERE rank_id = p_rankId and last_ranking > 0  and (best_ranking > last_ranking or best_ranking = 0);
    UPDATE user_rank SET best_point = last_point WHERE rank_id = p_rankId and best_point < last_point;
END;
$$;

