-- [WARN] [REVIEW] aion_MoveToLegacyAllUserData
--   Warning: CURSOR logic detected - converted to PG cursor syntax
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION aion_movetolegacyalluserdata(
    p_ncount integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_table_name varchar(50);
    v_legacytbl varchar(70);
    v_column_name varchar(50);
    v_id_for_offset bigint;
    v_sql varchar(4000);
    check_item CURSOR FOR SELECT table_name, column_name_of_charid FROM legacy_user_tables;
    cur_item CURSOR FOR SELECT table_name, column_name_of_charid FROM legacy_user_tables;
BEGIN
    -- Transaction managed by PG function context
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name = 'temp_user_id_object$') THEN
    DROP TABLE temp_user_id_object$;
    END IF;
    v_sql := 'SELECT TOP ' || CAST(p_ncount AS varchar(50)) || ' char_id INTO temp_user_id_object$ FROM user_data WHERE delete_complete_date <> 0 AND delete_complete_date + 3600*24*90 < GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0)';
    RAISE NOTICE '%', v_sql;
    EXECUTE v_sql;
    INSERT INTO legacy_log(legacy_date, legacy_count) values(CURRENT_TIMESTAMP, p_ncount);
    v_id_for_offset := LASTVAL();
    OPEN check_item;
    FETCH check_item INTO v_table_name, v_column_name;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    v_legacytbl := 'legacy_' || CAST(v_id_for_offset AS varchar(20)) || '_' || v_table_name;
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name = v_legacytbl) THEN
    RAISE NOTICE '%', 'Error! Legacy table is exist. Try again!!';
    RETURN 1;
    END IF;
    FETCH check_item INTO v_table_name, v_column_name;
    v_fetch_found := FOUND;
    END LOOP;
    CLOSE check_item;
    OPEN cur_item;
    FETCH cur_item INTO v_table_name, v_column_name;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    v_legacytbl := 'legacy_' || CAST(v_id_for_offset AS varchar(20)) || '_' || v_table_name;
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name = v_table_name) THEN
    v_sql := 'SELECT * INTO ' || v_legacytbl || ' FROM ' || v_table_name || ' WHERE ' || v_column_name || ' IN (SELECT char_id FROM temp_user_id_object$)';
    IF v_table_name = 'user_item' THEN
    v_sql := 'SELECT * INTO ' || v_legacytbl || ' FROM ' || v_table_name || ' WHERE (warehouse <> 3 AND warehouse <> 6 AND warehouse <> 7) AND ' || v_column_name || ' IN (SELECT char_id FROM temp_user_id_object$)';
    END IF;
    RAISE NOTICE '%', v_sql;
    EXECUTE v_sql;
    v_sql := 'DELETE FROM ' || v_table_name || ' WHERE ' || v_column_name || ' IN (SELECT char_id FROM temp_user_id_object$)';
    IF v_table_name = 'user_item' THEN
    v_sql := 'DELETE FROM ' || v_table_name || ' WHERE (warehouse <> 3 AND warehouse <> 6 AND warehouse <> 7) AND ' || v_column_name || ' IN (SELECT char_id FROM temp_user_id_object$)';
    END IF;
    RAISE NOTICE '%', v_sql;
    EXECUTE v_sql;
    insert into legacy_table_list(log_id, table_name, result) values(v_id_for_offset, v_legacytbl, 1);
    ELSE
    insert into legacy_table_list(log_id, table_name, result) values(v_id_for_offset, v_legacytbl, 0);
    END IF;
    FETCH cur_item INTO v_table_name, v_column_name;
    v_fetch_found := FOUND;
    END IF;
    CLOSE cur_item;
    DROP TABLE temp_user_id_object$;
    -- COMMIT (implicit in PG function)
END;
$$;

