-- [OK] [AUTO] aion_ChangeEnhancedStigmaSlotCnt

CREATE OR REPLACE FUNCTION aion_changeenhancedstigmaslotcnt(
    p_nCharID integer,
    p_cnt smallint
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    IF NOT EXISTS (SELECT char_id FROM user_data WHERE char_id = p_nCharID::integer AND (delete_date = 0 OR (delete_date > GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0)))) THEN
    RETURN -1;
    END IF;
    UPDATE user_data SET 	enhanced_stigma_slot_cnt = p_cnt WHERE char_id = p_nCharID::integer;
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN 0;
    END IF;
    RETURN p_nCharID;
END;
$$;

