    RETURN -2;
    END IF;
    IF EXISTS (SELECT forbidden_id FROM forbidden_word WHERE FORBIDDEN_WORD = p_strNewGuildName and IS_LIKE = 0 and status=0 and forbidden_type=2 and forbidden_reason = 5 and ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (regdate)::timestamp) / 86400)::integer < 366)) THEN
    RETURN -2;
    END IF;
