    RETURN -2;
    END IF;
    v_ret := p_nGuildId;
    v_change_log_id := 0;
    insert into guild_name_change_log (guild_id, old_name, new_name, change_date, item_id, tid, master_id, master_user_id, master_account_id, master_account_name, race, class, gender, lev) select p_nGuildId, p_strOldGuildName, p_strNewGuildName, CURRENT_TIMESTAMP, p_nItemId, p_nItemTid, char_id, user_id, account_id, account_name, race, class, gender, lev from user_data where char_id = p_nCharID::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF 0 /* @v_ERROR */ <> 0 or v_rowcount = 0 THEN
    v_ret := -4;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN NULL;  -- Originally: GOTO error_process
    END IF;
    v_forbidden_id := 0;
    insert into forbidden_word ( FORBIDDEN_TYPE, FORBIDDEN_REASON, WORLD_ID, FORBIDDEN_WORD, STATUS, LOGIN_ID, LOGIN_NM, REGDATE, IS_LIKE) values(2, 5, p_nServerId, p_strOldGuildName, 0, 'UseItem', 'ChangeGuildName', CURRENT_TIMESTAMP, 0);
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF 0 /* @v_ERROR */ <> 0	or v_rowcount = 0 THEN
    v_ret := -5;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN NULL;  -- Originally: GOTO error_process
    END IF;
    UPDATE guild SET name = p_strNewGuildName, change_info_time = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) WHERE id = p_nGuildId;
    IF 0 /* @v_ERROR */ <> 0 THEN
    v_ret := -6;
    -- TODO: MANUAL REVIEW NEEDED - GOTO error_process
    RETURN NULL;  -- Originally: GOTO error_process
    END IF;
    RETURN p_nGuildId;
    -- Label: error_process
    IF v_change_log_id <> 0 THEN
    DELETE FROM guild_name_change_log where id = v_change_log_id;
    END IF;
    IF v_forbidden_id <> 0 THEN
    DELETE FROM forbidden_word where forbidden_id = v_forbidden_id;
    END IF;
    RETURN v_ret;
END;
$$;

