-- [WARN] [REVIEW] aion_MoveToLegacyItems
--   Warning: CURSOR logic detected - converted to PG cursor syntax
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION aion_movetolegacyitems(
    p_ncount integer,
    p_offset integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_legacytbl varchar(50);
    v_sql varchar(4000);
    v_ncolumn_org integer;
    v_ncolumn_leg integer;
    v_columns varchar(1000);
    v_name varchar(100);
    cur_item CURSOR FOR SELECT ui.name FROM (SELECT * FROM information_schema.columns WHERE object_id = OBJECT_ID('user_item')) AS ui INNER JOIN (SELECT * FROM information_schema.columns WHERE object_id = OBJECT_ID(v_legacytbl)) AS ul ON ui.name = ul.name;
    v__t_sql varchar(4000);
BEGIN
    v_legacytbl := 'user_item_legacy_' || CAST(p_offset AS varchar(20));
    -- Transaction managed by PG function context
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name = 'temp_item_id_object$') THEN
    DROP TABLE temp_item_id_object$;
    END IF;
    v_sql := 'SELECT id, char_id INTO temp_item_id_object$ FROM user_item WHERE (warehouse <> 3 AND warehouse <> 6 AND warehouse <> 7) AND char_id IN (SELECT TOP ' || CAST(p_ncount AS varchar(50)) || ' char_id FROM user_data WHERE delete_complete_date <> 0 AND delete_complete_date + 3600*24*90 < GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) AND item_legacy = 0)';
    RAISE NOTICE '%', v_sql;
    EXECUTE v_sql;
    IF NOT EXISTS (SELECT object_id FROM information_schema.tables WHERE name = v_legacytbl) THEN
    v_sql := 'SELECT * INTO ' || v_legacytbl || ' FROM user_item WHERE id IN (SELECT id FROM temp_item_id_object$)';
    RAISE NOTICE '%', v_sql;
    EXECUTE v_sql;
    UPDATE user_data SET item_legacy = p_offset WHERE char_id IN (SELECT char_id FROM temp_item_id_object$ GROUP BY char_id);
    DELETE FROM user_item WHERE id IN (SELECT id FROM temp_item_id_object$);
    ELSE
    PERFORM aion_SyncItemLegacyTbl(v_legacytbl);
    SELECT COUNT(*) INTO v_ncolumn_org FROM information_schema.columns WHERE object_id = OBJECT_ID('user_item');
    SELECT COUNT(*) INTO v_ncolumn_leg FROM information_schema.columns WHERE object_id = OBJECT_ID(v_legacytbl);
    IF v_ncolumn_org <> v_ncolumn_leg THEN
    RAISE NOTICE '%', 'Error! Maybe sync failed.';
    RETURN 1;
    END IF;
    v_columns := '';
    OPEN cur_item;
    FETCH cur_item INTO v_name;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    IF v_columns <> '' THEN
    v_columns := v_columns || ', ';
    END IF;
    v_columns := v_columns+v_name;
    FETCH cur_item INTO v_name;
    v_fetch_found := FOUND;
    END LOOP;
    CLOSE cur_item;
    v_sql := 'INSERT INTO ' || v_legacytbl || '(' || v_columns || ') SELECT ' || v_columns || ' FROM user_item WHERE id IN (SELECT id FROM temp_item_id_object$)';
    RAISE NOTICE '%', v_sql;
    v__t_sql := 'SET IDENTITY_INSERT ' || v_legacytbl || ' ON ' || v_sql || ' SET IDENTITY_INSERT ' || v_legacytbl || ' OFF';
    EXECUTE v__t_sql;
    IF 0 /* @v_ERROR */ = 0 THEN
    UPDATE user_data SET item_legacy = p_offset WHERE char_id IN (SELECT char_id FROM temp_item_id_object$ GROUP BY char_id);
    DELETE FROM user_item WHERE id IN (SELECT id FROM temp_item_id_object$);
    END IF;
    END IF;
    DROP TABLE temp_item_id_object$;
    -- COMMIT (implicit in PG function)
END;
$$;

