-- [OK] [AUTO] aion_OrderingAbyssRanking

CREATE OR REPLACE FUNCTION aion_orderingabyssranking(
    p_nServerId integer,
    p_nRace integer,
    p_nTime bigint,
    p_nNum integer,
    p_nDeductionForRank10 integer,
    p_nDeductionForRank11 integer,
    p_nDeductionForRank12 integer,
    p_nDeductionForRank13 integer,
    p_nDeductionForRank14 integer,
    p_nDeductionForRank15 integer,
    p_nDeductionForRank16 integer,
    p_nDeductionForRank17 integer,
    p_nDeductionForRank18 integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_update_time bigint;
BEGIN
    v_update_time := COALESCE((select max(update_time) from abyss_ranking where race = p_nRace::integer and server_id = p_nServerId::integer), 0);
    UPDATE user_gp_data SET glory_point = GetGloryPointAfterDeductionByRank(abyss_ranking.rank, glory_point, p_nDeductionForRank10, p_nDeductionForRank11, p_nDeductionForRank12, p_nDeductionForRank13, p_nDeductionForRank14, p_nDeductionForRank15, p_nDeductionForRank16, p_nDeductionForRank17, p_nDeductionForRank18) FROM user_gp_data INNER JOIN abyss_ranking ON user_gp_data.char_id=abyss_ranking.char_id WHERE user_gp_data.glory_point > 0 AND abyss_ranking.update_time=v_update_time AND abyss_ranking.server_id = p_nServerId::integer AND abyss_ranking.race = p_nRace::integer AND abyss_ranking.rank>0;
    delete WHERE glory_point<=0 and ownership_bonus_gp<=0;
    insert into abyss_ranking (abyss_ranking, server_id, update_time, char_id, abyss_point, race, class, lev, guild_id, rank, old_Ranking, gp, rank_updatedate) SELECT  RANK() over (order by (COALESCE(glory_point, 0) + COALESCE(ownership_bonus_gp, 0)) desc, abyss_point desc, lev desc, user_data.char_id asc) as rank, p_nServerId, p_nTime, user_data.char_id, abyss_point, race, class, lev, guild_id, 0, 0, (COALESCE(glory_point, 0) + COALESCE(ownership_bonus_gp, 0)) AS gp_sum, NULL from user_data LEFT OUTER JOIN user_gp_data ON user_data.char_id=user_gp_data.char_id where race = p_nRace::integer and org_server = p_nServerId and (delete_date = 0 or delete_date > p_nTime) and ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_logout_time)::timestamp) / 86400)::integer < 30) order by rank LIMIT p_nNum;
    UPDATE abyss_ranking AS b SET old_ranking = COALESCE((select b.abyss_ranking FROM abyss_ranking AS b where b.race = p_nRace::integer and b.server_id = p_nServerId::integer and b.update_time = v_update_time and b.char_id = abyss_ranking.char_id and b.rank != 0), 0) where update_time = p_nTime and race = p_nRace::integer and server_id = p_nServerId::integer;
    delete from abyss_ranking where update_time < (GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0) - 2419200);
    PERFORM aion_SetAbyssGuildRank(p_nRace);
END;
$$;

