-- [OK] [AUTO] aion_ChargeCharRace

CREATE OR REPLACE FUNCTION aion_chargecharrace(
    p_account varchar(20),
    p_race smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_n integer;
    v_rows integer;
    v_char_id integer;
    v_accountId integer;
    v_charName varchar(20);
    v_class smallint;
    v_dbid bigint;
    v_dbid1 bigint;
BEGIN
    IF object_id('tempdb..#tempcharid') is not null THEN
    DROP TABLE IF EXISTS tempcharid;
    END IF;
    CREATE TEMP TABLE tempcharid ( pid int identity(1,1), accountId int, charId int, charName nvarchar(20), classId tinyint );
    v_n := 1;
    INSERT INTO tempcharid (accountId, charId, charName, classId) SELECT account_id, char_id, user_id, class FROM user_data WHERE account_name = p_account;
    SELECT count(*) INTO v_rows FROM #tempcharid;
    WHILE v_n <= v_rows LOOP
    SELECT accountId, charId, charName, classId INTO v_accountId, v_char_id, v_charName, v_class FROM #tempcharid WHERE pid = v_n;
    IF v_char_id != 0 THEN
    IF(v_class = 1 OR v_class = 2) BEGIN;
    v_class := 0;
    END LOOP;
    IF(v_class = 4 OR v_class = 5) BEGIN;
    v_class := 3;
    IF(v_class = 7 OR v_class = 8) BEGIN;
    v_class := 6;
    IF(v_class = 10 OR v_class = 11) BEGIN;
    v_class := 9;
    IF(v_class = 13 OR v_class = 14) BEGIN;
    v_class := 12;
    IF(v_class = 16 OR v_class = 17) BEGIN;
    v_class := 15;
    UPDATE abyss_ranking SET race = p_race::integer WHERE char_id = v_char_id;
    IF (p_race = 0) THEN
    DELETE FROM user_quest WHERE char_id = v_char_id;
    DELETE FROM user_finished_quest WHERE char_id = v_char_id AND quest_id = 1006;
    DELETE FROM user_finished_quest WHERE char_id = v_char_id AND quest_id = 2945;
    DELETE FROM user_finished_quest WHERE char_id = v_char_id AND quest_id = 2008;
    DELETE FROM user_finished_quest WHERE char_id = v_char_id AND quest_id = 1920;
    UPDATE user_finished_quest SET quest_id = 1000 WHERE quest_id = 2000 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 21226 WHERE quest_id = 11205 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 21230 WHERE quest_id = 11220 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 21233 WHERE quest_id = 11064 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 21235 WHERE quest_id = 11067 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 25690 WHERE quest_id = 15690 AND char_id = v_char_id;
    UPDATE user_data SET race = p_race::integer, class = v_class, lev = 1, world = 210010000, xlocation = 871, ylocation = 1190, zlocation = 112, last_normal_world = 210010000, last_normal_xlocation = 871, last_normal_ylocation = 1190, last_normal_zlocation = 112, resurrect_world = 210010000, resurrect_xlocation = 871, resurrect_ylocation = 1190, resurrect_zlocation = 112, guild_id = 0 WHERE char_id = v_char_id;
    DELETE FROM user_item where char_id = v_char_id AND name_id = 186000005;
    DELETE FROM user_item where char_id = v_accountId AND name_id = 186000005;
    UPDATE user_item set warehouse = 6 where warehouse = 7 AND char_id = v_accountId;
    ELSE
    IF (p_race = 1) THEN
    DELETE FROM user_quest WHERE char_id = v_char_id;
    END IF;
    DELETE WHERE char_id = v_char_id AND quest_id = 1006;
    DELETE FROM user_finished_quest WHERE char_id = v_char_id AND quest_id = 2945;
    DELETE FROM user_finished_quest WHERE char_id = v_char_id AND quest_id = 2008;
    DELETE FROM user_finished_quest WHERE char_id = v_char_id AND quest_id = 1920;
    UPDATE user_finished_quest SET quest_id = 2000 WHERE quest_id = 1000 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 11205 WHERE quest_id = 21226 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 11220 WHERE quest_id = 21230 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 11064 WHERE quest_id = 21233 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 11067 WHERE quest_id = 21235 AND char_id = v_char_id;
    UPDATE user_finished_quest SET quest_id = 15690 WHERE quest_id = 25690 AND char_id = v_char_id;
    UPDATE user_data SET race = p_race::integer, class = v_class, lev = 1, world = 220010000, xlocation = 593, ylocation = 2464, zlocation = 280, last_normal_world = 220010000, last_normal_xlocation = 593, last_normal_ylocation = 2464, last_normal_zlocation = 280, resurrect_world = 220010000, resurrect_xlocation = 593, resurrect_ylocation = 2464, resurrect_zlocation = 280, guild_id = 0 WHERE char_id = v_char_id;
    DELETE FROM user_item where char_id = v_char_id AND name_id = 186000010;
    DELETE FROM user_item where char_id = v_accountId AND name_id = 186000010;
    UPDATE user_item set warehouse = 7 where warehouse = 6 AND char_id = v_accountId;
    END IF;
    INSERT INTO user_skill_backup1 SELECT * FROM user_skill WHERE char_id = v_char_id AND skill_id >= 30000;
    DELETE FROM user_skill WHERE char_id = v_char_id;
    INSERT INTO user_item (char_id,name_id,amount,slot,warehouse) VALUES (v_char_id,188900001, 30, '0', 5);
    v_dbid := LASTVAL();
    INSERT INTO user_item_option (id, char_id, enchant_count, authorize_count, skin_name_id) VALUES (v_dbid, v_char_id, 0, 0, 188900001);
    INSERT INTO user_mail (to_id,to_name,from_id,from_name,title,content,item_id,item_nameid,item_amount, express_mail) VALUES (v_char_id, v_charName, 0, '系统邮件','转换种族', '转种族补发升级药水', v_dbid, 188900001, 30, 0);
    INSERT INTO user_item (char_id,name_id,amount,slot,warehouse) VALUES (v_char_id,169650000, 1, '0', 5);
    v_dbid1 := LASTVAL();
    INSERT INTO user_item_option (id, char_id, enchant_count, authorize_count, skin_name_id) VALUES (v_dbid1, v_char_id, 0, 0, 169650000);
    INSERT INTO user_mail (to_id,to_name,from_id,from_name,title,content,item_id,item_nameid,item_amount, express_mail) VALUES (v_char_id, v_charName, 0, '系统邮件','转换种族', '转种族补发外貌变更', v_dbid, 169650000, 1, 0);
    END IF;
    v_n := v_n+1;
END;
$$;

