LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE user_data SET 	class = p_nClass::integer, guild_id = p_nGuildId::integer, guild_rank = p_nGuildRank, recreate_guild_time = p_nRecreateGuildTime, cur_server = p_nCurServer, world = p_nWorld, world_map_number = p_nWorldMapNumber, xlocation = p_nXlocation, ylocation = p_nYlocation, zlocation = p_nZlocation, dir = p_nDir, last_normal_world = p_nLastNormalWorld, last_normal_xlocation = p_nLastNormalXlocation, last_normal_ylocation = p_nLastNormalYlocation, last_normal_zlocation = p_nLastNormalZlocation, last_normal_dir = (p_nLastNormalDir % 120), death_count = p_nDeathCount, temporary_lost_exp = p_nTemporaryLostExp, resurrect_world = p_nResurrectWorld, resurrect_xlocation = p_nResurrectXlocation, resurrect_ylocation = p_nResurrectYlocation, resurrect_zlocation = p_nResurrectZlocation, now_hit = p_nHp, now_mana = p_nMp, now_flight = p_nFp, exp = p_nExp, abyss_point = p_nAbyssPoint, abyss_point_from_user = p_nAbyssPointFromUser, lev = p_nLevel::integer, stigmaPoint = p_nStigmaPoint, cur_title_id=p_nCurTitleId, cur_title_attr_id=p_nCurTitleAttrId, guild_intro = p_strGuildIntro,	 guild_nickname = p_strGuildNickName, today_compare_time = p_nTodayCompareTime, today_abyss_kill_cnt = p_nTodayAbyssKillCnt, today_abyss_point = p_nTodayAbyssPoint, this_week_compare_time = p_nThisWeekCompareTime, this_week_abyss_kill_cnt = p_nThisWeekAbyssKillCnt, this_week_abyss_point = p_nThisWeekAbyssPoint, last_week_abyss_kill_cnt = p_nLastWeekAbyssKillCnt, last_week_abyss_point = p_nLastWeekAbyssPoint, total_abyss_kill_cnt = p_nTotalAbyssKillCnt, best_abyss_rank = p_nBestAbyssRank, is_freefly = p_isFreefly, optionflags = p_optionflags, accused_count = p_accused_count, last_accuse_time = p_last_accuse_time, bot_point = p_bot_point, vital_point = p_vital_point, pvp_exp = p_pvp_exp, serial_kill_point = p_serial_kill_point, serial_kill_penalty_duration = p_serial_kill_duration, serial_kill_penalty_skill_rank = p_serial_kill_penalty_skill_rank, enhanced_stigma_slot_cnt = p_enhancedStigmaSlotCnt, change_info_time = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0), housing_id = p_housing_id, fatigue_resttime_online = p_fatigue_resttime_online, next_hotspot_use_time = p_next_hotspot_use_time, gotcha_fever_point = p_gotcha_fever_point, gotcha_fever_expire_time = p_gotcha_fever_point, last_explicit_beginner_force = p_last_explicit_beginner_force, absolute_exp = p_absolute_exp, serial_guard_point = p_serial_guard_point, serial_guard_last_scantime = p_serial_guard_last_scantime WHERE char_id = p_nCharID::integer;
END;
$$;

