-- [OK] [AUTO] aion_OrderingAbyssRanking_20160415

CREATE OR REPLACE FUNCTION aion_orderingabyssranking_20160415(
    p_isSpecialSvr integer,
    p_nServerId integer,
    p_nRace integer,
    p_nTime bigint,
    p_nNum integer,
    p_nThisWeekUpdateTime integer,
    p_nRecentGPMin integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_update_time bigint;
BEGIN
    v_update_time := COALESCE((select max(update_time) from abyss_ranking where race = p_nRace::integer and server_id = p_nServerId::integer), 0);
    IF (0 = p_isSpecialSvr) THEN
    delete from user_gp_data where glory_point<=0 and ownership_bonus_gp<=0;
    insert into abyss_ranking (abyss_ranking, server_id, update_time, char_id, abyss_point, race, class, lev, guild_id, rank, old_Ranking, gp, rank_updatedate) SELECT  RANK() over (order by (COALESCE(glory_point, 0) + COALESCE(ownership_bonus_gp, 0)) desc, abyss_point desc, lev desc, user_data.char_id asc) as rank, p_nServerId, p_nTime, user_data.char_id, abyss_point, race, class, lev, guild_id, 0, 0, (COALESCE(glory_point, 0) + COALESCE(ownership_bonus_gp, 0)) AS gp_sum, NULL from user_data LEFT OUTER JOIN user_gp_data ON user_data.char_id=user_gp_data.char_id where race = p_nRace::integer and org_server = p_nServerId and (delete_date = 0 or delete_date > p_nTime) and ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_logout_time)::timestamp) / 86400)::integer < 30) and (case when (this_week_compare_time = p_nThisWeekUpdateTime or (p_nThisWeekUpdateTime / 86400) = (this_week_compare_time / 86400)) then (CAST(this_week_glory_point AS bigint) + last_week_glory_point + two_weeks_ago_glory_point + three_weeks_ago_glory_point) when (this_week_compare_time >= (p_nThisWeekUpdateTime - 604800)  or ((p_nThisWeekUpdateTime / 86400)-7) = (this_week_compare_time / 86400)) then (CAST(this_week_glory_point AS bigint) + last_week_glory_point + two_weeks_ago_glory_point) when (this_week_compare_time >= (p_nThisWeekUpdateTime - 1209600) or ((p_nThisWeekUpdateTime / 86400)-14) = (this_week_compare_time / 86400)) then (CAST(this_week_glory_point AS bigint) + last_week_glory_point) when (this_week_compare_time >= (p_nThisWeekUpdateTime - 1814400) or ((p_nThisWeekUpdateTime / 86400)-21) = (this_week_compare_time / 86400)) then this_week_glory_point end) >= p_nRecentGPMin order by rank LIMIT p_nNum;
    ELSE
    insert into abyss_ranking (abyss_ranking, server_id, update_time, char_id, abyss_point, race, class, lev, guild_id, rank, old_Ranking, gp, rank_updatedate) SELECT  RANK() over (order by abyss_point desc, lev desc, user_data.char_id asc) as rank, p_nServerId, p_nTime, user_data.char_id, abyss_point, race, class, lev, guild_id, 0, 0, (COALESCE(glory_point, 0) + COALESCE(ownership_bonus_gp, 0)) AS gp_sum, NULL from user_data LEFT OUTER JOIN user_gp_data ON user_data.char_id=user_gp_data.char_id where race = p_nRace::integer and org_server = p_nServerId and (delete_date = 0 or delete_date > p_nTime) and ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (last_logout_time)::timestamp) / 86400)::integer < 30) order by rank LIMIT p_nNum;
    END IF;
    UPDATE abyss_ranking AS b SET old_ranking = COALESCE((select b.abyss_ranking FROM abyss_ranking AS b where b.race = p_nRace::integer and b.server_id = p_nServerId::integer and b.update_time = v_update_time and b.char_id = abyss_ranking.char_id and b.rank != 0), 0) where update_time = p_nTime and race = p_nRace::integer and server_id = p_nServerId::integer;
    delete from abyss_ranking where update_time < (GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0) - 2419200);
    PERFORM aion_SetAbyssGuildRank(p_nRace);
END;
$$;

