CREATE OR REPLACE FUNCTION aion_getmovesvrcharlist(
    p_serverId integer,
    p_lastCheckTime integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_utc_adjust bigint;
BEGIN
