-- [OK] [AUTO] aion_ProcessLegionDominionTakeOver

CREATE OR REPLACE FUNCTION aion_processlegiondominiontakeover(
    p_nTakeOverTime bigint,
    p_nServerId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_lastestTakeOverTime bigint;
BEGIN
    v_lastestTakeOverTime := COALESCE((select max(take_over_processed_time) from legion_dominion_rankings where server_id = p_nServerId::integer), 0);
    IF (0 < p_nTakeOverTime and v_lastestTakeOverTime < p_nTakeOverTime) THEN
    insert into legion_dominion_rankings values(0, 0, 0, 0, 0, p_nTakeOverTime, p_nServerId);
    UPDATE legion_dominion_rankings SET take_over_processed_time=p_nTakeOverTime where take_over_processed_time=0 and server_id = p_nServerId::integer;
    delete WHERE take_over_processed_time < (p_nTakeOverTime-30*24*60*60) and server_id = p_nServerId::integer;
    END IF;
END;
$$;

