-- [OK] [AUTO] GM_UserCustomAnimationDAO_InsertUpdateAnimation

CREATE OR REPLACE FUNCTION gm_usercustomanimationdao_insertupdateanimation(
    p_char_id integer,
    p_animation_id smallint,
    p_animation_type smallint,
    p_useState smallint,
    p_expire_time integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM user_customAnimation  WHERE char_id = p_char_id::integer AND animation_id = p_animation_id) THEN
    INSERT INTO user_customAnimation ( char_id, animation_id, animation_type, useState, expire_time ) VALUES ( p_char_id, p_animation_id, p_animation_type, p_useState, p_expire_time );
    ELSE
    UPDATE	user_customAnimation SET		animation_type = p_animation_type, useState = p_useState, expire_time = p_expire_time WHERE	char_id = p_char_id::integer AND		animation_id = p_animation_id;
    END IF;
END;
$$;

