-- [OK] [AUTO] aion_CheckMovableLegacyItems

CREATE OR REPLACE FUNCTION aion_checkmovablelegacyitems(
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_charcnt integer;
    v_itemcnt integer;
BEGIN
    SELECT COUNT(*) INTO v_charcnt FROM user_data WHERE delete_complete_date <> 0 AND delete_complete_date + 3600*24*90 < GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) AND item_legacy = 0;
    SELECT COUNT(*) INTO v_itemcnt FROM user_item WHERE (warehouse <> 3 AND warehouse <> 6 AND warehouse <> 7) AND char_id IN (SELECT char_id FROM user_data WHERE delete_complete_date <> 0 AND delete_complete_date + 3600*24*90 < GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0));
    RAISE NOTICE '%', 'movable char count : ' || CAST(v_charcnt AS varchar(20)) || ', item count : ' || CAST(v_itemcnt AS varchar(20));
END;
$$;

