-- [OK] [AUTO] aion_GetOfflineBuddyNoti

CREATE OR REPLACE FUNCTION aion_getofflinebuddynoti(
    p_charid integer,
    OUT p_requestCount integer,
    OUT p_lastmsg varchar(255)
) RETURNS record
LANGUAGE plpgsql
AS $$
DECLARE
    v_name varchar(50);
    v_msg varchar(255);
BEGIN
    SELECT COUNT(*) INTO p_requestCount FROM user_buddy_offline where USER_ID = p_charid::integer;
    SELECT inviter_name, inviter_msg INTO v_name, v_msg FROM user_buddy_offline where USER_ID = p_charid::integer and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (createdate)::timestamp) / 86400)::integer<= 7 order by id desc LIMIT 1;
    IF v_name is not null THEN
    p_lastmsg := v_name || ':' || v_msg;
    ELSE
    p_lastmsg := '';
    END IF;
END;
$$;

