-- [OK] [AUTO] aion_SetReformCount

CREATE OR REPLACE FUNCTION aion_setreformcount(
    p_char_id integer,
    p_next_reset_time integer,
    p_reform_count integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    UPDATE user_reform SET next_reset_time = p_next_reset_time, reform_count = p_reform_count WHERE char_id = p_char_id::integer;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    INSERT INTO user_reform(char_id, next_reset_time, reform_count) VALUES (p_char_id, p_next_reset_time, p_reform_count);
    END IF;
END;
$$;

