CREATE OR REPLACE FUNCTION aion_checkolduseroflowleveltodelete(
    p_check_days integer,
    p_low_level integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_charcnt integer;
BEGIN
    SELECT COUNT(*) INTO v_charcnt FROM user_data WHERE delete_date = 0 AND delete_complete_date = 0 AND GetUnixtimeWithUTCAdjust(last_logout_time, 0) + 3600*24*p_check_days < GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) AND lev < p_low_level::integer;
    RAISE NOTICE '%', 'applied char count : ' || CAST(v_charcnt AS varchar(20));
END;
$$;

