--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_userdatada_countcharbyworldoruseridoraccountnmorcnt(
    p_user_id varchar(10),
    p_account_name varchar(50),
    p_builder varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(1000);
    v_tmp integer;
BEGIN
    v_sql := ' select count(char_id) cnt ' || ' from user_data  ';
    v_tmp := 0;
    IF p_user_id != 'null' THEN
    v_sql := v_sql || ' WHERE user_id like ''' || p_user_id || '''';
    v_tmp := 1;
    END IF;
    IF p_account_name IS NOT NULL THEN
    IF v_tmp = 1 THEN
    v_sql := v_sql || ' AND account_name like ''' || p_account_name || '''';
    ELSE
    v_sql := v_sql || ' WHERE account_name like ''' || p_account_name || '''';
    v_tmp := 1;
    END IF;
    END IF;
    IF p_builder IS NOT NULL THEN
    IF p_builder = 95 THEN
    IF v_tmp = 1 THEN
    v_sql := v_sql || ' AND builder > ''0'' ';
    ELSE
    v_sql := v_sql || ' WHERE builder > ''0'' ';
    v_tmp := 1;
    ELSE
    IF v_tmp = 1 THEN
    v_sql := v_sql || ' AND builder = ''' || p_builder || '''';
    ELSE
    v_sql := v_sql || ' WHERE builder = ''' || p_builder || '''';
    v_tmp := 1;
    END IF;
    END IF;
    END IF;
    EXECUTE v_sql;
    RETURN;
END;
$$;

