-- [OK] [AUTO] aion_CheckPersonalInstantHousingUserRace

CREATE OR REPLACE FUNCTION aion_checkpersonalinstanthousinguserrace(
    p_user_id integer,
    p_requiredQuestLight integer,
    p_requiredQuestDark integer
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_questCount integer;
    v_id integer;
    v_race smallint;
    v_state smallint;
    v_permission smallint;
BEGIN
    SELECT quest_count INTO v_questCount FROM user_finished_quest WHERE char_id = p_user_id::integer AND (quest_id = p_requiredQuestLight::integer OR quest_id = p_requiredQuestDark::integer);
    IF (0 < (v_questCount)) THEN
    SELECT id INTO v_id FROM house_field WHERE owner_id = p_user_id::integer AND owner_type = 2;
    IF (0 < (v_id)) THEN
    PERFORM 65535, 2, 3;
    RETURN -2;
    ELSE
    IF EXISTS (SELECT id FROM house_instant WHERE id = p_user_id) THEN
    IF EXISTS (SELECT state FROM house_instant WHERE id = p_user_id and state = 5) THEN
    SELECT race INTO v_race FROM user_data WHERE char_id = p_user_id::integer;
    SELECT state, permission INTO v_state, v_permission FROM house_instant WHERE id = p_user_id;
    PERFORM v_race, v_state, v_permission;
    RETURN 0;
    ELSE
    PERFORM race, 6, 3 FROM user_data WHERE char_id = p_user_id::integer;
    RETURN -5;
    ELSE
    PERFORM race, 5, 1 FROM user_data WHERE char_id = p_user_id::integer;
    RETURN -1;
    ELSE
    PERFORM 65535, 2, 3;
    IF EXISTS (SELECT char_id FROM user_data WHERE char_id = p_user_id::integer) THEN
    RETURN -3;
    ELSE
    RETURN -4;
    END IF;
    END IF;
END;
$$;

