-- [OK] [AUTO] aion_CheckValidCharName

CREATE OR REPLACE FUNCTION aion_checkvalidcharname(
    p_strName varchar(20),
    p_strAccount varchar(14)
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_applyDate timestamp := CAST('2016-07-06 09:00:00' AS timestamp);
BEGIN
    IF EXISTS (SELECT char_id FROM user_data WHERE user_id = p_strName::integer AND (delete_date = 0 OR (delete_date > GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0)))) THEN
    RETURN -1;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE FORBIDDEN_WORD = p_strName and IS_LIKE = 0 and status=0 and (forbidden_type=0 or forbidden_type=1)) THEN
    RETURN -2;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE (p_strName LIKE '%' || FORBIDDEN_WORD || '%') and forbidden_word <> '' and IS_LIKE = 1 and status=0 and (forbidden_type=1 or forbidden_type=0)) THEN
    RETURN -2;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=p_strName and status=0 and (forbidden_reason in (3,4)) and ((REGDATE < v_applyDate and (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (regdate)::timestamp) / 86400)::integer < 366) or ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (regdate)::timestamp) / 86400)::integer < 61))) THEN
    RETURN -2;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=p_strName and status=0 and forbidden_reason = 2) THEN
    IF NOT EXISTS (SELECT FORBIDDEN_ID FROM forbidden_char WHERE FORBIDDEN_CHAR=p_strName and FORBIDDEN_ACCOUNT_NM=p_strAccount and status=0 and forbidden_reason = 2) THEN
    RETURN -3;
    END IF;
    END IF;
    RETURN 0;
END;
$$;

