-- [OK] [AUTO] aion_SetCharLocalRank_All

CREATE OR REPLACE FUNCTION aion_setcharlocalrank_all(
    p_rankId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE user_rank SET local_old_ranking = local_ranking, local_ranking = 0 WHERE rank_id = p_rankId;
    UPDATE user_rank SET local_ranking = num from ( select RANK() over (partition by user_data.race order by point desc) as num, rank_id, user_rank.char_id from user_rank join user_data on user_rank.char_id = user_data.char_id and user_data.delete_complete_date = 0 where rank_id = p_rankId and point > 0 ) x where x.num <= 1000 and user_rank.rank_id = x.rank_id and user_rank.char_id = x.char_id;
END;
$$;

