-- [OK] [AUTO] aion_SetCharLocalRank_All_byRating

CREATE OR REPLACE FUNCTION aion_setcharlocalrank_all_byrating(
    p_rateId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    UPDATE user_rank SET local_old_ranking = local_ranking, local_ranking = 0 WHERE rank_id = p_rateId;
    UPDATE user_rank SET local_ranking = num, CAST( AS pointx.mu AS integer) from ( select RANK() over (partition by user_data.race order by CAST(mu AS integer) desc) as num, rate_id, user_rate.char_id, user_rate.mu from user_rate join user_data on user_rate.char_id = user_data.char_id and user_data.delete_complete_date = 0 where rate_id = p_rateId::integer and update_cnt >= 5 ) x where x.num <= 1000 and user_rank.rank_id = x.rate_id and user_rank.char_id = x.char_id;
    INSERT INTO user_rank (char_id, rank_id, local_ranking, point) SELECT x.char_id, x.rate_id, x.num, CAST(x.mu AS integer) from ( select RANK() over (partition by user_data.race order by CAST(mu AS integer) desc) as num, rate_id, user_rate.char_id, user_rate.mu from user_rate join user_data on user_rate.char_id = user_data.char_id and user_data.delete_complete_date = 0 where rate_id = p_rateId::integer and update_cnt >= 5 ) x where x.num <= 1000 and x.char_id not in (select char_id WHERE rank_id = p_rateId);
END;
$$;

