    v_sql varchar(1300);
BEGIN
    v_sql := ' select top ' || p_view_count || ' t1.id, t1.to_id, t1.to_name, t1.from_id, t1.from_name, t1.title, t1.item_id, t1.item_nameid, t1.item_amount, t1.money, t1.state, t1.arrive_time, t1.express_mail, t1.abyss_point ' || ' from user_mail t1 ';
    IF p_mail_type = 1 THEN
    v_sql := v_sql || ' where (t1.from_id = ''' || p_char_id || ''') ';
    ELSIF p_mail_type = 2 THEN
    v_sql := v_sql || ' where (t1.to_id = ''' || p_char_id || ''') ';
    END IF;
    v_sql := v_sql || ' and t1.id not in (select top ' || p_top_count || ' id from user_mail ' IF p_mail_type = 1 set v_sql = v_sql || ' where (from_id = ''' || p_char_id || ''') ' ELSE IF p_mail_type = 2 set v_sql = v_sql || ' where (to_id = ''' || p_char_id || ''') ' set v_sql = v_sql || ' order by id desc ) ';
    v_sql := v_sql || ' order by t1.id desc ';
    EXECUTE v_sql;
END;
$$;

