-- [OK] [AUTO] aion_PutChallengeTask

CREATE OR REPLACE FUNCTION aion_putchallengetask(
    p_nUnionId integer,
    p_nType smallint,
    p_nTaskNameId integer,
    p_nStatus smallint,
    OUT p_nTaskDbId bigint,
    OUT p_return_code integer
) RETURNS record
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (Select id From challenge_task Where union_id=p_nUnionId and type = p_nType::integer and task_name_id=p_nTaskNameId) THEN
    p_return_code := 1;
    RETURN;
    ELSE
    Insert Into challenge_task(union_id, type, task_name_id, status, complete_count, last_complete_time) Values(p_nUnionId, p_nType, p_nTaskNameId, p_nStatus, 0, 0);
    IF 0 /* @v_ERROR */ <> 0 THEN
    p_return_code := 2;
    RETURN;
    END IF;
    p_nTaskDbId := LASTVAL();
    END IF;
    p_return_code := 0;
    RETURN;
END;
$$;

