-- [OK] [AUTO] aion_GetCharPlayBlockPunishInfo

CREATE OR REPLACE FUNCTION aion_getcharplayblockpunishinfo(
    p_nCharID integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_utc_adjust_hour bigint;
BEGIN
    v_utc_adjust_hour := DATEDIFF(HH, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), CURRENT_TIMESTAMP);
    PERFORM punish_code, DATEDIFF(SS, ('1970-01-01' || (v_utc_adjust_hour) * INTERVAL '1 hour'), start_date) as start_date, DATEDIFF(SS, ('1970-01-01' || (v_utc_adjust_hour) * INTERVAL '1 hour'), end_date) as end_date, punish_reason FROM user_punishment WHERE	char_id = p_nCharID::integer and play_block = 1 and status = 0 and end_date > CURRENT_TIMESTAMP;
END;
$$;

