    p_nCharId integer,
    p_nServerId integer,
    OUT p_loginTime varchar(30)
) RETURNS varchar(30)
LANGUAGE plpgsql
AS $$
DECLARE
    v_charName varchar(20);
    v_guild_id integer;
    v_account varchar(16);
    v_accountNo integer;
    v_hardware varchar(16);
    v_currTime timestamp;
BEGIN
    v_currTime := CURRENT_TIMESTAMP;
    p_loginTime := CAST(v_currTime AS varchar(30));
