-- [OK] [AUTO] aion_ClearPetitionMsg

CREATE OR REPLACE FUNCTION aion_clearpetitionmsg(
    p_nCharId integer,
    p_nPetSvId integer,
    p_nLocalSv integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_nPetSvId = p_nLocalSv THEN
    UPDATE user_data SET petition_msg = NULL WHERE char_id = p_nCharId::integer;
    ELSE
    DELETE FROM user_petition_msg WHERE char_id = p_nCharId::integer AND petition_sv_id = p_nPetSvId;
    END IF;
END;
$$;

