-- [OK] [AUTO] aion_SetCharLogoutTime_20120516

CREATE OR REPLACE FUNCTION aion_setcharlogouttime_20120516(
    p_nCharId integer,
    OUT p_logoutTime varchar(30)
) RETURNS varchar(30)
LANGUAGE plpgsql
AS $$
DECLARE
    v_currTime timestamp;
BEGIN
    v_currTime := CURRENT_TIMESTAMP;
    p_logoutTime := CAST(v_currTime AS varchar(30));
    UPDATE user_data SET last_logout_time = v_currTime , playtime = playtime + (EXTRACT(EPOCH FROM (v_currTime)::timestamp - (last_login_time)::timestamp) / 60)::integer, change_info_time = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) WHERE char_id = p_nCharId::integer;
END;
$$;

