-- [OK] [AUTO] aion_SetTownData

CREATE OR REPLACE FUNCTION aion_settowndata(
    p_town_id integer,
    p_point integer,
    p_lastLvChangedTime integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT town_id FROM town_data WHERE town_id = p_town_id) THEN
    UPDATE town_data SET point = p_point, lastLvChangedTime = p_lastLvChangedTime WHERE town_id = p_town_id;
    ELSE
    INSERT INTO town_data VALUES (p_town_id, p_point, p_lastLvChangedTime);
    END IF;
END;
$$;

