-- [OK] [AUTO] GM_UserMonsterAchievement_UpdateOrInsert

CREATE OR REPLACE FUNCTION gm_usermonsterachievement_updateorinsert(
    p_char_id integer,
    p_achieve_id integer,
    p_achieved_count integer,
    p_achieved_grade smallint,
    p_reward_received smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    UPDATE user_monster_achievement SET char_id = p_char_id::integer, achieve_id=p_achieve_id, achieved_count=p_achieved_count, achieved_grade=p_achieved_grade, reward_received=p_reward_received WHERE char_id = p_char_id::integer and achieve_id=p_achieve_id;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    INSERT into user_monster_achievement(char_id, achieve_id, achieved_count, achieved_grade, reward_received) VALUES(p_char_id, p_achieve_id, p_achieved_count, p_achieved_grade, p_reward_received);
    END IF;
END;
$$;

