-- [WARN] [REVIEW] GM_UserDataDA_SrchCharByWorldorUserIDorAccountNMorCnt
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_userdatada_srchcharbyworldoruseridoraccountnmorcnt(
    p_world_id varchar(5),
    p_user_id varchar(30),
    p_account_name varchar(50),
    p_builder varchar(5),
    p_deleted_char varchar(5),
    p_char_on varchar(5),
    p_deleted_move varchar(5),
    p_bx_char_id varchar(25),
    p_multi_user_ids varchar(1000),
    p_view_count varchar(6),
    p_top_count varchar(6)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
    v_tmp integer;
    v_sql_etc varchar(1000);
    v_tmp2 integer;
BEGIN
    v_sql_etc := ' and delete_type != ''10000'' ';
    v_tmp := 1;
    v_tmp2 := 0;
    IF p_char_on != 'null' THEN
    v_sql_etc := v_sql_etc || ' and last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' and last_logout_time > ''2007-12-12 00:00:00.000'' ';
    END IF;
    IF p_deleted_move != 'null' THEN
    v_sql_etc := v_sql_etc || ' and delete_type != ''0''  ';
    v_tmp2 := 1;
    END IF;
    IF p_deleted_char != 'null' THEN
    IF v_tmp2 = 0 THEN
    v_sql_etc := v_sql_etc || ' and delete_date = ''' || p_deleted_char || ''' ';
    END IF;
    END IF;
    IF p_bx_char_id != 'null' THEN
    v_sql_etc := v_sql_etc || ' and char_id = ''' || p_bx_char_id || '''';
    END IF;
    IF p_user_id != 'null' THEN
    v_sql_etc := v_sql_etc || ' and user_id = ''' || p_user_id || '''';
    END IF;
    IF p_multi_user_ids != 'null' THEN
    v_sql_etc := v_sql_etc || ' and (' || p_multi_user_ids || ') ';
    END IF;
    IF p_account_name != 'null' THEN
    IF v_tmp = 1 THEN
    v_sql_etc := v_sql_etc || ' AND account_name = ''' || p_account_name || '''';
    ELSE
    v_sql_etc := v_sql_etc || ' WHERE account_name = ''' || p_account_name || '''';
    v_tmp := 1;
    END IF;
    END IF;
    IF p_builder IS NOT NULL THEN
    IF p_builder = '95' THEN
    IF v_tmp = 1 THEN
    v_sql_etc := v_sql_etc || ' AND builder > ''0'' ';
    ELSE
    v_sql_etc := v_sql_etc || ' WHERE builder > ''0'' ';
    v_tmp := 1;
    ELSE
    IF v_tmp = 1 THEN
    v_sql_etc := v_sql_etc || ' AND builder = ''' || p_builder || '''';
    ELSE
    v_sql_etc := v_sql_etc || ' WHERE builder = ''' || p_builder || '''';
    v_tmp := 1;
    END IF;
    END IF;
    END IF;
    v_sql := 'select top ' || p_view_count || ' 	delete_type, delete_complete_date, inventory_growth, char_warehouse_growth, delete_date, char_id, user_id, account_id, account_name, org_server, cur_server,COALESCE(login_server, org_server) login_server,' || ' 	TO_CHAR(create_date, ''YYYY-MM-DD HH24:MI:SS'') create_date, CAST(gender AS char) gender, CAST(race AS char) race, CAST(class AS char) class, CAST(lev AS char) lev, CAST(builder AS char) builder, exp, world,	' || '   case ' || '     WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' and last_logout_time > ''2007-12-12 00:00:00.000'' THEN ''#339900'' ' || '     WHEN last_login_time != last_logout_time or last_login_time = ''1970-01-01 00:00:00.000''  THEN ''brown'' ' || '     WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' THEN ''black'' ' || '   end as logonoff ' || '	, gotcha_fever_point, gotcha_fever_expire_time ' || ' from user_data  ' || ' where char_id not in(select top ' || p_top_count || ' char_id from user_data  where org_server=''' || p_world_id || ''' ' || v_sql_etc || '  order by char_id desc) ';
    v_sql := v_sql || v_sql_etc;
    v_sql := v_sql || ' and org_server = ''' || p_world_id || '''';
    v_sql := v_sql || ' order by char_id desc ';
    EXECUTE v_sql;
END;
$$;

