-- [OK] [AUTO] aion_SetTrialAccountData

CREATE OR REPLACE FUNCTION aion_settrialaccountdata(
    p_accountId integer,
    p_resetTime integer,
    p_sellGold bigint,
    p_tradeGold bigint,
    p_decomposeSum integer,
    p_gatherSum integer,
    p_extractGatherSum integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT account_id FROM trial_account_data WHERE account_id = p_accountId::integer) THEN
    UPDATE trial_account_data SET reset_time = p_resetTime, sell_gold_sum = p_sellGold, trade_gold_sum = p_tradeGold, decompose_sum = p_decomposeSum, gather_sum = p_gatherSum, extract_gather_sum = p_extractGatherSum WHERE account_id = p_accountId::integer;
    ELSE
    INSERT INTO trial_account_data(account_id, reset_time, sell_gold_sum, trade_gold_sum, decompose_sum, gather_sum, extract_gather_sum) VALUES (p_accountId, p_resetTime, p_sellGold, p_tradeGold, p_decomposeSum, p_gatherSum, p_extractGatherSum);
    END IF;
END;
$$;

