    v_sql := ' select ' || ' t1.char_id, t1.user_id, t1.account_name, t1.account_id, t1.class, t1.lev, t1.race, t1.gender, ' || ' t1.history_date, t1.head_face_color, t1.head_hair_color, t1.head_eye_color, t1.head_lip_color, t1.head_face_type, t1.head_hair_type, t1.height_scale, t1.head_voice_type, t1.head_feat_type1, t1.head_feat_type2, ' || ' t2.delete_complete_date, t2.org_server, t2.delete_date ' || ' from user_customize_history t1, user_data t2 ' || ' where t1.char_id = t2.char_id ';
    IF p_user_id != 'null' THEN
    v_sql := v_sql || ' and t2.user_id = ''' || p_user_id || ''' ';
    END IF;
    IF p_char_id != 'null' THEN
    v_sql := v_sql || ' and t2.char_id = ''' || p_char_id || ''' ';
    END IF;
    IF p_account_name != 'null' THEN
    v_sql := v_sql || ' and t2.account_name = ''' || p_account_name || ''' ';
    END IF;
    v_sql := v_sql || ' order by t1.history_date asc ';
    EXECUTE v_sql;
    RETURN;
END;
$$;

