    p_csv_char_ids varchar(2000)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_query varchar(4000);
BEGIN
    v_query := ';
    PERFORM	char_id, CASE WHEN last_login_time = last_logout_time AND last_login_time != ''1970-01-01 00:00:00.000'' THEN ''on'' ELSE ''off'' END AS ''logonoff'' FROM	user_data  WHERE	char_id IN (' || p_csv_char_ids || ')';
    EXECUTE v_query;
END;
$$;

