CREATE OR REPLACE FUNCTION aion_setcharrankpoint_byrating_endseason(
    p_rank_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    INSERT INTO user_rank(char_id, rank_id, point) select char_id, p_rank_id, CAST(mu AS integer) from user_rate where rate_id = p_rank_id::integer and update_cnt >=5 and char_id not in (select char_id from user_rank where rank_id = p_rank_id);
    UPDATE user_rank SET point = -2147483648 WHERE rank_id = p_rank_id and char_id not in (select char_id from user_rate where rate_id = p_rank_id::integer);
END;
$$;

