-- [OK] [AUTO] aion_PutCharChangeLog

CREATE OR REPLACE FUNCTION aion_putcharchangelog(
    p_nCharId integer,
    p_nType integer,
    p_nOldValue integer,
    p_nNewValue integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_user_last_logintime timestamp;
    v_user_play_time integer;
    v_user_race smallint;
    v_user_class smallint;
    v_user_lev smallint;
    v_interval_time integer;
BEGIN
    SELECT race, class, lev, playtime, last_login_time INTO v_user_race, v_user_class, v_user_lev, v_user_play_time, v_user_last_logintime FROM user_data  WHERE char_id = p_nCharId::integer;
    v_interval_time := (SELECT  playtime from user_change_log where char_id = p_nCharId::integer and change_type = p_nType order by change_time desc LIMIT 1);
    IF (v_interval_time is null) THEN
    v_interval_time := 0;
    END IF;
    INSERT INTO user_change_log (char_id, change_type, race, class, lev, old_value, new_value, change_time, playtime, intervaltime) VALUES (p_nCharId, p_nType, v_user_race, v_user_class, v_user_lev, p_nOldValue, p_nNewValue, CURRENT_TIMESTAMP, v_user_play_time + (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (v_user_last_logintime)::timestamp) / 60)::integer, v_user_play_time + (EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (v_user_last_logintime)::timestamp) / 60)::integer - v_interval_time);
END;
$$;

