-- [WARN] [REVIEW] GM_UserMoveServiceLogDA_SrchGuildNameChange
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_usermoveservicelogda_srchguildnamechange(
    p_user_id varchar(30),
    p_char_id varchar(25),
    p_account_name varchar(50),
    p_guild_name varchar(40),
    p_guild_id varchar(25)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(1500);
BEGIN
    v_sql := ' select ' || ' t1.change_date, t1.old_name, t1.new_name, t1.item_id, t1.tid, t1.guild_id, ' || ' t1.master_id, t1.master_user_id, t1.master_account_name, t1.master_account_id, t1.class, t1.lev, t1.race, t1.gender, ' || ' t2.delete_complete_date, t2.org_server, t2.delete_date ' || ' from guild_name_change_log t1, user_data t2 ' || ' where t1.master_id = t2.char_id ';
    IF p_user_id != 'null' THEN
    v_sql := v_sql || ' and t2.user_id = ''' || p_user_id || ''' ';
    END IF;
    IF p_char_id != 'null' THEN
    v_sql := v_sql || ' and t2.char_id = ''' || p_char_id || ''' ';
    END IF;
    IF p_account_name != 'null' THEN
    v_sql := v_sql || ' and t2.account_name = ''' || p_account_name || ''' ';
    END IF;
    IF p_guild_name != 'null' THEN
    v_sql := v_sql || ' and t1.new_name = ''' || p_guild_name || ''' ';
    END IF;
    IF p_guild_id != 'null' THEN
    v_sql := v_sql || ' and t1.guild_id = ''' || p_guild_id || ''' ';
    END IF;
    v_sql := v_sql || ' order by t1.change_date asc ';
    EXECUTE v_sql;
    RETURN;
END;
$$;

