CREATE OR REPLACE FUNCTION aion_commentdelete(
    p_delete integer,
    p_comment_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_delete = 1 THEN
    update user_comment set deleted = 1 where comment_id = p_comment_id;
    ELSIF p_delete = 2 THEN
    update user_comment set deleted = 0 where comment_id = p_comment_id;
    END IF;
END;
$$;

