--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_usermoveservicelogda_srchmovedcharlist(
    p_user_id varchar(30),
    p_account_name varchar(50),
    p_char_id varchar(25)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(1000);
BEGIN
    v_sql := ' select ' || ' t1.move_date, t1.char_id_from, t1.user_id_from, t1.server_id_from, ' || ' t1.account_name, t1.account_id, t1.class, t1.lev, t1.race, t1.gender, t1.warehouse, t1.premium, ' || ' t2.user_id, t2.char_id, t2.delete_complete_date, t2.org_server, t2.delete_date ' || ' from user_move_service_log t1, user_data t2 ' || ' where t1.char_id = t2.char_id ';
    IF p_user_id != 'null' THEN
    v_sql := v_sql || ' and t2.user_id = ''' || p_user_id || ''' ';
    END IF;
    IF p_char_id != 'null' THEN
    v_sql := v_sql || ' and t2.char_id = ''' || p_char_id || ''' ';
    END IF;
    IF p_account_name != 'null' THEN
    v_sql := v_sql || ' and t2.account_name = ''' || p_account_name || ''' ';
    END IF;
    v_sql := v_sql || ' order by t1.move_date asc ';
    EXECUTE v_sql;
    RETURN;
END;
$$;

