CREATE OR REPLACE FUNCTION aion_commentlist(
    p_char_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_utc_adjust bigint;
BEGIN
    v_utc_adjust := GetUtcAdjustSecWithUTC_Local((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), CURRENT_TIMESTAMP);
    PERFORM comment_id, comment, writer, GetUnixtimeWithUTCAdjust(comment_date, v_utc_adjust) as comment_date from user_comment  where char_id = p_char_id::integer and deleted = 0 order by comment_id desc;
END;
$$;

