-- [WARN] [REVIEW] GM_UserDataDA_SrchMailList
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_userdatada_srchmaillist(
    p_world_id varchar(5),
    p_builder varchar(5),
    p_char_on varchar(5),
    p_from_char_id varchar(30),
    p_to_char_id varchar(30),
    p_from_lev varchar(30),
    p_to_lev varchar(30),
    p_from_create_date varchar(30),
    p_to_create_date varchar(30),
    p_race varchar(5),
    p_class_str varchar(200)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
    v_sql_etc varchar(1000);
BEGIN
    v_sql_etc := ' ';
    IF p_char_on = 'Y' THEN
    v_sql_etc := v_sql_etc || ' and last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' and last_logout_time > ''2007-12-12 00:00:00.000'' ';
    END IF;
    IF p_from_char_id != 'null' THEN
    v_sql_etc := v_sql_etc || ' and char_id between ''' || p_from_char_id || ''' and ''' || p_to_char_id || ''' ';
    END IF;
    IF p_from_lev != 'null' THEN
    v_sql_etc := v_sql_etc || ' and lev between ''' || p_from_lev || ''' and ''' || p_to_lev || ''' ';
    END IF;
    IF p_from_create_date != 'null' THEN
    v_sql_etc := v_sql_etc || ' and create_date between ''' || p_from_create_date || ''' and ''' || p_to_create_date || ''' ';
    END IF;
    IF p_race != 'null' THEN
    v_sql_etc := v_sql_etc || ' and race = ''' || p_race || '''';
    END IF;
    IF p_class_str != 'null' THEN
    v_sql_etc := v_sql_etc || ' and (' || p_class_str || ') ';
    END IF;
    v_sql := ' select lev, exp, account_id, char_id, user_id from user_data ' || ' where delete_date=0 and org_server=''' || p_world_id || ''' and builder=''' || p_builder || ''' ' || v_sql_etc;
    EXECUTE v_sql;
    RETURN;
END;
$$;

