BEGIN
    v_sql := ' select ' || ' t1.change_date, t1.old_name, t1.new_name, t1.tid, ' || ' t1.account_name, t1.account_id, t1.class, t1.lev, t1.race, t1.gender, ' || ' t2.delete_complete_date, t2.char_id, t2.org_server, t2.delete_date ' || ' from user_name_change_log t1, user_data t2 ' || ' where t1.char_id = t2.char_id ';
