-- [WARN] [REVIEW] GM_UserDataDA_SrchMoveCharByWorldorUserIDorAccountNMorCnt
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION gm_userdatada_srchmovecharbyworldoruseridoraccountnmorcnt(
    p_world_id varchar(5),
    p_user_id varchar(30),
    p_account_name varchar(50),
    p_builder varchar(5),
    p_deleted_char varchar(5),
    p_char_on varchar(5),
    p_deleted_move varchar(5),
    p_bx_char_id varchar(25),
    p_multi_user_ids varchar(1000),
    p_view_count varchar(5),
    p_top_count varchar(5)
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
    v_sql_etc varchar(1000);
BEGIN
    v_sql_etc := ' ';
    IF p_account_name != 'null' THEN
    v_sql_etc := v_sql_etc || ' and t1.account_name = ''' || p_account_name || '''';
    END IF;
    IF p_bx_char_id != 'null' THEN
    v_sql_etc := v_sql_etc || ' and char_id = ''' || p_bx_char_id || '''';
    END IF;
    IF p_user_id != 'null' THEN
    v_sql_etc := v_sql_etc || ' and user_id = ''' || p_user_id || '''';
    END IF;
    IF p_multi_user_ids != 'null' THEN
    v_sql_etc := v_sql_etc || ' and (' || p_multi_user_ids || ') ';
    END IF;
    IF p_builder IS NOT NULL THEN
    IF p_builder = 95 THEN
    v_sql_etc := v_sql_etc || ' and builder > ''0'' ';
    ELSE
    v_sql_etc := v_sql_etc || ' and builder = ''' || p_builder || '''';
    END IF;
    END IF;
    v_sql := ' select top ' || p_view_count || ' 	delete_type, delete_complete_date, inventory_growth, char_warehouse_growth, delete_date, b.char_id, user_id, account_id, account_name, org_server, cur_server,	' || ' 	TO_CHAR(create_date, ''YYYY-MM-DD HH24:MI:SS'') create_date, CAST(gender AS char) gender, CAST(race AS char) race, CAST(class AS char) class, CAST(lev AS char) lev, CAST(builder AS char) builder, exp, world,	' || '   case ' || '     WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' and last_logout_time > ''2007-12-12 00:00:00.000'' THEN ''#339900'' ' || '     WHEN last_login_time != last_logout_time or last_login_time = ''1970-01-01 00:00:00.000''  THEN ''brown'' ' || '     WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' THEN ''black'' ' || '   end as logonoff ' || 'from' || '(' || '	select t2.char_id from(' || '	select c.account_name' || '	from(' || '	select race, account_name from user_data ' || '	where delete_date=0 and org_server=''' || p_world_id || ''' ' || '	group by race, account_name) c' || '	group by c.account_name' || '	having count(*) > 1) t1, user_data t2' || '	where t1.account_name=t2.account_name and delete_date=0 and org_server=''' || p_world_id || ''' ' || v_sql_etc || ') b, user_data f' || 'where b.char_id=f.char_id and f.char_id not in ' || '(' || '	select top ' || p_top_count || ' t2.char_id from(' || '	select c.account_name' || '	from(' || '	select race, account_name from user_data ' || '	where delete_date=0 and org_server=''' || p_world_id || ''' ' || '	group by race, account_name) c' || '	group by c.account_name' || '	having count(*) > 1) t1, user_data t2' || '	where t1.account_name=t2.account_name and delete_date=0 and org_server=''' || p_world_id || ''' ' || v_sql_etc || ')';
    EXECUTE v_sql;
    RETURN;
END;
$$;

