-- [WARN] [REVIEW] aion_dbreindex_all
--   Warning: CURSOR logic detected - converted to PG cursor syntax

CREATE OR REPLACE FUNCTION aion_dbreindex_all(
    p_fillfactor smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_Table varchar(255);
    v_cmd varchar(500);
BEGIN
    v_cmd := 'DECLARE TableCursor CURSOR FOR select name from sys.all_objects where type_desc=''USER_TABLE'' and is_ms_shipped=0';
    EXECUTE v_cmd;
    OPEN TableCursor;
    FETCH TableCursor INTO v_Table;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    v_cmd := 'ALTER INDEX ALL ON ' || v_Table || ' REBUILD WITH (FILLFACTOR = ' || CAST(p_fillfactor AS varchar(3)) || ')';
    RAISE NOTICE '%', v_cmd || ' -- applied.';
    EXECUTE v_cmd;
    FETCH TableCursor INTO v_Table;
    v_fetch_found := FOUND;
    END LOOP;
    CLOSE TableCursor;
END;
$$;

