-- [OK] [AUTO] aion_SetChatAccusedInfo

CREATE OR REPLACE FUNCTION aion_setchataccusedinfo(
    p_char_id integer,
    p_accused_count integer,
    p_accused_count_penalty integer,
    p_penalty_start_time integer,
    p_last_accused_time integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    RETURN QUERY SELECT  char_id from user_chat_accused where char_id = p_char_id::integer LIMIT 1;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    insert into user_chat_accused (char_id, accused_count, accused_count_penalty, penalty_start_time, last_accused_time) values (p_char_id, p_accused_count, p_accused_count_penalty, p_penalty_start_time, p_last_accused_time);
    ELSE
    UPDATE user_chat_accused SET char_id = p_char_id::integer, accused_count = p_accused_count, accused_count_penalty = p_accused_count_penalty, penalty_start_time = p_penalty_start_time, last_accused_time=p_last_accused_time WHERE char_id = p_char_id::integer;
    END IF;
END;
$$;

