-- [OK] [AUTO] aion_PutCustomAnimation

CREATE OR REPLACE FUNCTION aion_putcustomanimation(
    p_charId integer,
    p_animationId smallint,
    p_animationType smallint,
    p_expireTime integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    Update user_customAnimation set useState = 0 where char_id = p_charId::integer and animation_type= p_animationType and useState != 0;
    Update user_customAnimation Set animation_type=p_animationType, expire_time=p_expireTime, useState=1	Where char_id = p_charId::integer and animation_id=p_animationId;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF v_rowcount = 0 THEN
    Insert into user_customAnimation (char_id, animation_id, animation_type, expire_time, useState) values(p_charId, p_animationId, p_animationType, p_expireTime, 1);
    END IF;
END;
$$;

