-- [OK] [AUTO] aion_SetCustomAnimation

CREATE OR REPLACE FUNCTION aion_setcustomanimation(
    p_charId integer,
    p_animationId smallint,
    p_animationType smallint,
    p_commandType smallint
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_commandType = 4 THEN
    Update user_customAnimation Set useState=0 Where char_id = p_charId::integer and animation_type=p_animationType;
    Update user_customAnimation Set useState=1 Where char_id = p_charId::integer and animation_id=p_animationId;
    END IF;
    IF p_commandType = 6 THEN
    Update user_customAnimation Set useState=0, expire_time=0 Where char_id = p_charId::integer and animation_id=p_animationId;
    END IF;
END;
$$;

