    p_nCharId integer,
    p_nEmotionType smallint,
    p_nExpireDate integer
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    -- Transaction managed by PG function context
    IF EXISTS (SELECT char_id FROM user_emotion WHERE char_id = p_nCharId::integer and emotion_type=p_nEmotionType) THEN
    UPDATE user_emotion SET expire_date = p_nExpireDate WHERE char_id = p_nCharId::integer and emotion_type=p_nEmotionType;
    ELSE
    INSERT INTO user_emotion(char_id, emotion_type, expire_date) VALUES (p_nCharId, p_nEmotionType, p_nExpireDate);
    END IF;
    -- COMMIT (implicit in PG function)
END;
$$;

