-- [OK] [AUTO] aion_SetDeletedCharComplete

CREATE OR REPLACE FUNCTION aion_setdeletedcharcomplete(
    p_nCharId integer,
    p_nDeleteCompleteTime integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_nAccId integer;
    v_userId varchar(40);
    v_nLevel smallint;
    v_nMaxCharId integer;
    v_nMaxLevel smallint;
BEGIN
    UPDATE user_data SET delete_complete_date = p_nDeleteCompleteTime ,guild_id = 0, change_info_time = GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0) WHERE char_id = p_nCharId::integer and delete_complete_date = 0 and delete_date != 0 and delete_date <= p_nDeleteCompleteTime;
    IF v_rowcount = 1 THEN
    SELECT account_id, user_id, lev INTO v_nAccId, v_userId, v_nLevel WHERE char_id = p_nCharId::integer;
    SELECT char_id, lev INTO v_nMaxCharId, v_nMaxLevel FROM user_data Where account_id=v_nAccId and delete_complete_date=0 Order by lev desc LIMIT 1;
    PERFORM v_userId, v_nAccId, v_nLevel,COALESCE(v_nMaxCharId, 0), COALESCE(v_nMaxLevel, 0);
    END IF;
END;
$$;

