-- [OK] [AUTO] aion_GetDbProfile_BlockQuery

CREATE OR REPLACE FUNCTION aion_getdbprofile_blockquery(
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT   a.session_id AS BlockedSessionID, b.blocking_session_id ,        b.wait_duration_ms / 1000 as 'WaitDuration(Sec)', b.wait_type ,        c.resource_type, db_name(c.resource_database_id) AS ResourceDBName, c.request_mode, c.request_type, c.request_status, b.resource_description ,        db_name(e.dbid) AS BlockedDBName, object_name(e.objectid) AS BlockedObjectName, e.text AS BlockedQuery ,        substring(e.text, (d.statement_start_offset / 2) + 1, ((case d.statement_end_offset when -1; datalength(e.text) else d.statement_end_offset end - d.statement_start_offset)/2) + 1) AS BlockedStmt ,        db_name(g.dbid) AS BlockingDBName, object_name(g.objectid) AS BlockingObjectName, g.text AS BlockingQuery ,        a.task_address, a.worker_address, b.waiting_task_address, b.blocking_task_address from            sys.dm_os_tasks a inner join  sys.dm_os_waiting_tasks b  on a.task_address = b.waiting_task_address or a.task_address = b.blocking_task_address inner join  sys.dm_tran_locks c        on b.resource_address = c.lock_owner_address inner join  sys.dm_exec_requests d     on a.session_id = d.session_id and a.request_id = d.request_id cross apply sys.dm_exec_sql_text(d.sql_handle) e inner join  sys.dm_exec_connections f               on b.blocking_session_id = f.session_id cross apply sys.dm_exec_sql_text(f.most_recent_sql_handle) g where b.blocking_session_id is not null;
END;
$$;

