-- [WARN] [REVIEW] GM_UserPetDAO_ChangePetName
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION
--   Warning: ROLLBACK TRANSACTION converted to RAISE EXCEPTION

CREATE OR REPLACE FUNCTION gm_userpetdao_changepetname(
    p_dbid bigint,
    p_char_id integer,
    p_name varchar(20)
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    tran;
    IF EXISTS (select forbidden_id from forbidden_word where (FORBIDDEN_TYPE=0 and FORBIDDEN_REASON=1 and is_like=0 and forbidden_word=p_name) or (FORBIDDEN_TYPE=0 and FORBIDDEN_REASON=1 and is_like=1 and forbidden_word like '%' || p_name || '%')) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 2;
    END IF;
    IF EXISTS (select id from user_pet where name = p_name) THEN
    RAISE EXCEPTION 'Rollback requested';
    RETURN 1;
    ELSE
    update user_pet set name=p_name where id=p_dbid and char_id = p_char_id::integer;
    END IF;
    -- COMMIT (implicit in PG function)
    RETURN 0;
END;
$$;

