-- [OK] [AUTO] GM_UserDataDA_SrchUseBotChannelList

CREATE OR REPLACE FUNCTION gm_userdatada_srchusebotchannellist(
    p_world_id integer,
    p_char_id integer,
    p_user_id varchar(20),
    p_account_id integer,
    p_account_name varchar(20),
    p_use_bot_channel varchar(1),
    p_page_num integer DEFAULT 1,
    p_view_count integer DEFAULT 10000
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_query varchar(3000);
    v_where varchar(1000);
    v_order_col varchar(100);
BEGIN
    v_order_col := 'char_id desc';
    v_where := ' where	delete_date = 0 and		org_server = ' || CAST(p_world_id AS varchar);
    IF (p_char_id != 0) THEN
    v_where := v_where || ' and		u.char_id = ' || CAST(p_char_id AS varchar);
    END IF;
    IF (p_user_id != '') THEN
    v_where := v_where || ' and		user_id = ''' || p_user_id || '''';
    END IF;
    IF (p_account_id != 0) THEN
    v_where := v_where || ' and		u.account_id = ' || CAST(p_account_id AS varchar);
    END IF;
    IF (p_account_name != '') THEN
    v_where := v_where || ' and		account_name = ''' || p_account_name || '''';
    END IF;
    IF (p_use_bot_channel != '') THEN
    v_where := v_where || ' and		COALESCE(use_bot_channel, 0) = ' || p_use_bot_channel;
    END IF;
    v_query := ';
    PERFORM  || ' LIMIT ' || CAST(p_view_count AS varchar) * from	(SELECT /*INLINE_LIMIT:' || CAST(p_page_num*p_view_count AS varchar*/ || ') ROW_NUMBER() over (order by u.' || v_order_col || ') as num , u.char_id, user_id, u.account_id, account_name, class, gender, race, lev, builder, create_date, org_server, delete_date, delete_complete_date, delete_type , COALESCE(e.use_bot_channel, 0) as use_bot_channel, world, e.use_bot_channel_update_date as bot_update_date, case WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' and last_logout_time > ''2007-12-12 00:00:00.000'' THEN ''339900'' WHEN last_login_time != last_logout_time or last_login_time = ''1970-01-01 00:00:00.000''  THEN ''brown'' WHEN last_login_time = last_logout_time and last_login_time != ''1970-01-01 00:00:00.000'' THEN ''black'' end as logonoff from	user_data u left join user_extra_info e on e.char_id = u.char_id ' || v_where || ' order by ' || v_order_col || ' ) x where	num > ' || CAST((p_page_num-1)*p_view_count AS varchar) || ' order by ' || v_order_col;
    EXECUTE v_query;
END;
$$;

