-- [OK] [AUTO] aion_GetDbProfile_QueryFrom

CREATE OR REPLACE FUNCTION aion_getdbprofile_queryfrom(
    p_before_sec integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_from_check_time timestamp;
BEGIN
    v_from_check_time := (CURRENT_TIMESTAMP + (-p_before_sec) * INTERVAL '1 second');
    RETURN QUERY SELECT  p.name AS SP Name,qs.execution_count,qs.last_execution_time,qs.last_elapsed_time, qs.total_elapsed_time/qs.execution_count AS avg_elapsed_time FROM sys.procedures AS p INNER JOIN sys.dm_exec_procedure_stats AS qs ON p.object_id = qs.object_id WHERE qs.database_id = DB_ID() and DATEADD(S, (last_elapsed_time/1000000), Last_EXECUTION_TIME) > v_from_check_time ORDER BY last_elapsed_time  DESC LIMIT 50;
END;
$$;

