-- [OK] [AUTO] aion_GetDbProfile_StatisticsCpuAve

CREATE OR REPLACE FUNCTION aion_getdbprofile_statisticscpuave(
) RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
    PERFORM  Average CPU used = total_worker_time / qs.execution_count ,Total CPU used = total_worker_time ,Last CPU used = last_worker_time ,MAX CPU used = max_worker_time ,Execution count = qs.execution_count ,Individual Query = SUBSTRING(qt.text FROM qs.statement_start_offset/2 FOR (CASE WHEN qs.statement_end_offset = -1 THEN LENGTH(CAST(qt.text AS text)) * 2 ELSE qs.statement_end_offset END - qs.statement_start_offset)/2) , COALESCE(object_name(objectid, dbid), 'unknown') AS OBJName ,qs.creation_time ,qs.last_execution_time ,qs.min_worker_time ,qs.max_worker_time FROM sys.dm_exec_query_stats qs CROSS APPLY sys.dm_exec_sql_text(qs.sql_handle) as qt ORDER BY Average CPU used DESC LIMIT 10;
END;
$$;

