-- [OK] [AUTO] aion_GetDbProfile_StatisticsIoTotal

CREATE OR REPLACE FUNCTION aion_getdbprofile_statisticsiototal(
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY SELECT  (total_logical_reads/execution_count) as avg_logical_reads , (total_logical_writes/execution_count) as avg_logical_writes , (total_physical_reads/execution_count) as avg_physical_reads , Execution_count , statement_start_offset , COALESCE(q.text, 'UNKNOWN') , COALESCE(object_name(q.objectid, q.dbid),'UNKNOWN')  AS OBJName from sys.dm_exec_query_stats cross apply sys.dm_exec_query_plan(plan_handle) p cross apply sys.dm_exec_sql_text(plan_handle) as q order by (total_logical_reads + total_logical_writes)/execution_count Desc LIMIT 10;
END;
$$;

