-- [OK] [AUTO] aion_PutGuild_20100916

CREATE OR REPLACE FUNCTION aion_putguild_20100916(
    p_strGuildName varchar(32),
    p_nMasterId integer,
    p_nRace smallint,
    p_nSubMasterRight smallint,
    p_nOfficerRight smallint,
    p_nMemberRight smallint,
    p_nNewbieRight smallint
) RETURNS integer
LANGUAGE plpgsql
AS $$
BEGIN
    IF EXISTS (SELECT id FROM guild WHERE name = p_strGuildName) THEN
    RETURN -1;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE FORBIDDEN_WORD = p_strGuildName and IS_LIKE = 0 and status=0 and forbidden_type=0) THEN
    RETURN -2;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE FORBIDDEN_WORD = p_strGuildName and IS_LIKE = 0 and status=0 and forbidden_type=2 and forbidden_reason <> 5) THEN
    RETURN -2;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE FORBIDDEN_WORD = p_strGuildName and IS_LIKE = 0 and status=0 and forbidden_type=2 and forbidden_reason = 5 and ((EXTRACT(EPOCH FROM (CURRENT_TIMESTAMP)::timestamp - (regdate)::timestamp) / 86400)::integer < 366)) THEN
    RETURN -2;
    END IF;
    IF EXISTS (SELECT FORBIDDEN_ID FROM forbidden_word WHERE (p_strGuildName LIKE '%' || FORBIDDEN_WORD || '%')  and forbidden_word <> '' and IS_LIKE = 1 and status=0 and (forbidden_type=2 or forbidden_type=0)) THEN
    RETURN -2;
    END IF;
    INSERT INTO guild (name, race, master_id, level, rank, submaster_right, officer_right, member_right, newbie_right, point, fund, delete_requested, delete_time, notice1, notice2, notice3, notice4, notice5, notice6, notice7, change_info_time) VALUES (p_strGuildName, p_nRace, p_nMasterId, 1, 0, p_nSubMasterRight, p_nOfficerRight, p_nMemberRight, p_nNewbieRight, 0, 0, 0, 0, '', '', '', '', '', '', '', GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),0));
    IF 0 /* @v_ERROR */ <> 0 THEN
    RETURN 0;
    END IF;
    RETURN LASTVAL();
END;
$$;

