-- [OK] [AUTO] GM_UserPunishmentDAO_AddModPunishForBot

CREATE OR REPLACE FUNCTION gm_userpunishmentdao_addmodpunishforbot(
    p_account_id integer,
    p_char_id integer,
    p_play_block smallint,
    p_status smallint,
    p_punish_code integer,
    p_punish_min integer,
    p_punish_reason varchar(200),
    p_login_id varchar(30),
    p_login_nm varchar(30)
) RETURNS bigint
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
BEGIN
    IF NOT EXISTS (SELECT 1 FROM user_punishment WHERE account_id = p_account_id::integer AND char_id = p_char_id::integer) THEN
    INSERT INTO user_punishment ( account_id, char_id, play_block, status, punish_code, start_date, end_date, remain_minute, punish_reason, login_id, login_nm ) VALUES ( p_account_id, p_char_id, p_play_block, p_status, p_punish_code, CURRENT_TIMESTAMP, (CURRENT_TIMESTAMP + (p_punish_min) * INTERVAL '1 minute'), p_punish_min, p_punish_reason, p_login_id, p_login_nm );
    ELSE
    UPDATE	user_punishment SET		punish_code = p_punish_code WHERE	account_id = p_account_id::integer AND char_id = p_char_id::integer;
    END IF;
    RETURN v_rowcount;
END;
$$;

