-- [OK] [AUTO] GM_UserQuestDA_SrchMyQuestByCharID

CREATE OR REPLACE FUNCTION gm_userquestda_srchmyquestbycharid(
    p_char_id varchar(20),
    p_quest_type varchar(10),
    p_view_count integer,
    p_top_count integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_quest_type = 'ing' THEN
    RETURN QUERY SELECT	quest_branch, char_id, quest_id, quest_status, quest_progress, '0' quest_count , 0 as repeat_quest_count, 0 as repeat_quest_resetnum FROM	user_quest WHERE (char_id = p_char_id::integer) order by quest_id asc;
    ELSIF p_quest_type = 'end' THEN
    RETURN QUERY SELECT  quest_branch, char_id, quest_id, '9999' quest_status, '0' quest_progress, quest_count , repeat_quest_count, repeat_quest_resetnum FROM	user_finished_quest WHERE	(char_id = p_char_id::integer) and quest_id not in (SELECT  quest_id from user_finished_quest where char_id = p_char_id::integer order by quest_id asc LIMIT p_top_count) ORDER BY quest_id asc LIMIT p_view_count;
    END IF;
END;
$$;

