-- [OK] [AUTO] aion_SetWorldExtCondition

CREATE OR REPLACE FUNCTION aion_setworldextcondition(
    p_world_num integer,
    p_variable varchar(256),
    p_variable_hash integer,
    p_value integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_rowcount integer := 0;
    v_id integer;
BEGIN
    v_id := 0;
    SELECT id INTO v_id FROM world_extcondition WHERE world_type = 0 AND world_num = p_world_num AND variable_hash = p_variable_hash;
    GET DIAGNOSTICS v_rowcount = ROW_COUNT;
    IF (v_rowcount > 1) THEN
    SELECT id INTO v_id FROM world_extcondition WHERE world_type = 0 AND world_num = p_world_num AND variable = p_variable;
    END IF;
    IF (v_id <> 0) THEN
    UPDATE world_extcondition SET value = p_value WHERE id = v_id;
    ELSE
    INSERT INTO world_extcondition (world_type, world_num, variable, variable_hash, value) VALUES (0, p_world_num, p_variable, p_variable_hash, p_value);
    END IF;
END;
$$;

