-- [OK] [AUTO] aion_StartServer

CREATE OR REPLACE FUNCTION aion_startserver(
    p_nServerId integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_serverStartTime integer;
    v_serverStartDateTime timestamp;
    v_serverEndDateTime timestamp;
BEGIN
    IF EXISTS (select server_id from server_info where server_id = p_nServerId::integer and info_name = 'SERVER_START_TIME') THEN
    v_serverStartDateTime := (select dateadd(second, int_value - GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0), CURRENT_TIMESTAMP) from server_info where server_id = p_nServerId::integer and info_name = 'SERVER_START_TIME');
    v_serverEndDateTime := (select dateadd(second, int_value - GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0), CURRENT_TIMESTAMP) from server_info where server_id = p_nServerId::integer and info_name = 'SERVER_LAST_HEARTBIT_TIME');
    UPDATE user_data SET  last_logout_time = v_serverEndDateTime, playtime = playtime + (EXTRACT(EPOCH FROM (v_serverEndDateTime)::timestamp - (last_login_time)::timestamp) / 60)::integer WHERE cur_server = p_nServerId and last_login_time >= v_serverStartDateTime and last_login_time = last_logout_time;
    update server_info Set int_value= GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0) where server_id = p_nServerId::integer and info_name = 'SERVER_START_TIME';
    update server_info Set int_value= GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0) where server_id = p_nServerId::integer and info_name = 'SERVER_LAST_HEARTBIT_TIME';
    ELSE
    INSERT INTO server_info (server_id, info_name, int_value, int64_value, str_value) Values(p_nServerId, 'SERVER_START_TIME', GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0), 0, '');
    INSERT INTO server_info (server_id, info_name, int_value, int64_value, str_value) Values(p_nServerId, 'SERVER_LAST_HEARTBIT_TIME', GetUnixtimeWithUTCAdjust((CURRENT_TIMESTAMP AT TIME ZONE 'UTC'), 0), 0, '');
    END IF;
END;
$$;

