-- [WARN] [REVIEW] aion_SyncItemLegacyTbl
--   Warning: CURSOR logic detected - converted to PG cursor syntax
--   Warning: sp_executesql converted to EXECUTE - may need manual USING clause

CREATE OR REPLACE FUNCTION aion_syncitemlegacytbl(
    p_legacytbl varchar(50)
) RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_ret integer;
    v_sql varchar(2000);
    v_type varchar(100);
    v_constraint varchar(200);
    v_type_id integer;
    v_item_id integer;
    v_legacy_id integer;
    v_name varchar(100);
    v_typename varchar(20);
    v_typesize integer;
    v_is_nullable integer;
    v_is_identity integer;
    v_default_object integer;
    v_default_string varchar(100);
    cur_item CURSOR FOR SELECT type_id, item_id, legacy_id, name, typename, typesize, is_nullable, is_identity, default_object, default_string FROM temp_object$;
BEGIN
    IF EXISTS (SELECT object_id FROM information_schema.tables WHERE name = 'temp_object$') THEN
    DROP TABLE temp_object$;
    END IF;
    v_ret := 0;
    CREATE TABLE temp_object$ ( type_id				int, item_id				int, legacy_id			int, name				nvarchar(100), typename			nvarchar(20), typesize			int, is_nullable			int, is_identity			int, default_object		int, default_string		nvarchar(100) );
    INSERT INTO temp_object$(type_id, item_id, legacy_id, name, typename, typesize, is_nullable, is_identity, default_object, default_string) SELECT 0, ui.column_id, 0, ui.name, t.name, ui.max_length, ui.is_nullable, ui.is_identity, ui.default_object_id, GetDefaultConstraintValue(ui.default_object_id) FROM (SELECT * FROM information_schema.columns WHERE object_id = OBJECT_ID('user_item')) AS ui INNER JOIN sys.types AS t ON ui.user_type_id = t.user_type_id WHERE ui.name NOT IN (SELECT name FROM information_schema.columns WHERE object_id = OBJECT_ID(p_legacytbl));
    INSERT INTO temp_object$(type_id, item_id, legacy_id, name, typename, typesize, is_nullable, is_identity, default_object, default_string) SELECT 1, ui.column_id, ul.column_id, ui.name, t.name, ui.max_length, ui.is_nullable, ui.is_identity, ui.default_object_id, GetDefaultConstraintValue(ui.default_object_id) FROM (SELECT * FROM information_schema.columns WHERE object_id = OBJECT_ID('user_item')) AS ui INNER JOIN (SELECT * FROM information_schema.columns WHERE object_id = OBJECT_ID(p_legacytbl)) AS ul ON ui.name = ul.name INNER JOIN sys.types AS t ON ui.user_type_id = t.user_type_id WHERE	ui.user_type_id <> ul.user_type_id	OR ui.max_length <> ul.max_length;
    INSERT INTO temp_object$(type_id, item_id, legacy_id, name, typename, typesize, is_nullable, is_identity, default_object, default_string) SELECT 2, 0, ui.column_id, ui.name, t.name, ui.max_length, ui.is_nullable, ui.is_identity, ui.default_object_id, GetDefaultConstraintValue(ui.default_object_id) FROM (SELECT * FROM information_schema.columns WHERE object_id = OBJECT_ID(p_legacytbl)) AS ui INNER JOIN sys.types AS t ON ui.user_type_id = t.user_type_id WHERE ui.name NOT IN (SELECT name FROM information_schema.columns WHERE object_id = OBJECT_ID('user_item'));
    OPEN cur_item;
    FETCH cur_item INTO v_type_id, v_item_id, v_legacy_id, v_name, v_typename, v_typesize, v_is_nullable, v_is_identity, v_default_object, v_default_string;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    v_type := CASE v_typename WHEN 'nvarchar'			THEN 'nvarchar(' || CAST(v_typesize/2 AS varchar(10)) || ')' WHEN 'varchar'			THEN 'varchar(' || CAST(v_typesize AS varchar(10)) || ')';
    ELSE					v_typename;
    END LOOP;
    IF v_is_nullable = 0 THEN
    v_constraint := 'NOT NULL ';
    ELSE
    v_constraint := 'NULL ';
    END IF;
    IF v_default_object <> 0 THEN
    v_constraint := v_constraint || 'DEFAULT' || v_default_string;
    END IF;
    IF v_type_id = 0 THEN
    v_sql := 'ALTER TABLE ' || p_legacytbl || ' ADD ' || v_name || ' ' || v_type || ' ' || v_constraint;
    ELSIF v_type_id = 1 THEN
    v_sql := 'ALTER TABLE ' || p_legacytbl || ' ALTER COLUMN ' || v_name || ' ' || v_type;
    END IF;
    RAISE NOTICE '%', v_sql;
    IF v_type_id < 2 THEN
    EXECUTE v_sql;
    v_ret := 0 /* @v_ERROR */;
    END IF;
    FETCH cur_item INTO v_type_id, v_item_id, v_legacy_id, v_name, v_typename, v_typesize, v_is_nullable, v_is_identity, v_default_object, v_default_string;
    v_fetch_found := FOUND;
    END IF;
    CLOSE cur_item;
    DROP TABLE temp_object$;
    IF v_ret = 0 THEN
    RAISE NOTICE '%', 'The legacy tbl has been synchronized.';
    ELSE
    RAISE NOTICE '%', 'Error occurred(' || CAST(v_ret AS varchar(30)) || '). Do sync manually.';
    END IF;
    RETURN v_ret;
END;
$$;

