-- [OK] [AUTO] GM_UserRankDA_SrchUserListByRankId

CREATE OR REPLACE FUNCTION gm_userrankda_srchuserlistbyrankid(
    p_rank_id integer,
    p_cvs_race varchar(100),
    p_cvs_class varchar(100),
    p_rank_from integer,
    p_rank_to integer
) RETURNS SETOF record
LANGUAGE plpgsql
AS $$
DECLARE
    v_sql varchar(4000);
BEGIN
    v_sql := ';
    RETURN QUERY SELECT r.*, u.user_id, u.char_id, u.race, u.class, u.gender, u.lev, u.account_name, u.account_id, g.name as ''guild_nm'' FROM user_rank r  JOIN user_data u  ON u.char_id = r.char_id LEFT JOIN guild g  ON g.id = u.guild_id WHERE r.rank_id = ' || CAST(p_rank_id AS varchar);
    IF (COALESCE(p_cvs_race, 'null') <> 'null') THEN
    v_sql := v_sql || ' AND u.race IN (' || p_cvs_race || ') ';
    END IF;
    IF (COALESCE(p_cvs_class, 'null') <> 'null') THEN
    v_sql := v_sql || ' AND u.class IN (' || p_cvs_class || ') ';
    END IF;
    v_sql := v_sql || ' AND ' || CAST(p_rank_from AS varchar) || '<= local_ranking AND local_ranking <=' || CAST(p_rank_to AS varchar);
    SET v_sql = v_sql || ' ORDER BY r.local_ranking ASC';
    EXECUTE v_sql;
END;
$$;

