-- [WARN] [REVIEW] aion_PutHouseScriptFieldToInstant
--   Warning: CURSOR logic detected - converted to PG cursor syntax

CREATE OR REPLACE FUNCTION aion_puthousescriptfieldtoinstant(
    p_addr_id integer,
    p_char_id integer
) RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    v_fetch_found boolean := true;
    v_slot_id integer;
    v_script_size smallint;
    v_script_data bytea;
    script_cursor CURSOR FOR (SELECT slot_id, script_size, script_data FROM house_field_script WHERE addr_id = p_addr_id);
BEGIN
    OPEN script_cursor;
    FETCH script_cursor INTO v_slot_id, v_script_size, v_script_data;
    v_fetch_found := FOUND;
    WHILE v_fetch_found LOOP
    PERFORM aion_SetHouseInstantScript(p_char_id, v_slot_id, v_script_size, v_script_data);
    FETCH script_cursor INTO v_slot_id, v_script_size, v_script_data;
    v_fetch_found := FOUND;
    END LOOP;
    CLOSE script_cursor;
    DELETE FROM house_field_script WHERE addr_id = p_addr_id;
END;
$$;

